INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710779', 'Indradhanu: PCCOE International Grand Challenge 2026', 'Eligibility: Open exclusively to students currently enrolled in undergraduate (UG), postgraduate (PG), or other STEM programs. Each team must consist of 2&ndash;5 members, including the team leader. Required Documents: Submit a single consolidated PDF containing the identity cards of all team members. Submit a signed No Objection Certificate (NOC) to participate in subsequent rounds. Mentor Guidelines: Each team must have a designated mentor. The mentor may be a faculty member from the participating institution or an industry professional. The mentor will not be counted as part of the team size. Certificates: An e-certificate will be awarded to every team member who successfully qualifies for the first round. Physical certificates will be awarded only to finalist and winning teams.', '2026-07-01T00:00:00+05:30', '2027-02-15T00:00:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/indradhanu-pccoe-international-grand-challenge-2026-pimpri-chinchwad-college-of-engineering-pccoe-pune-1710779', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001712464', 'EduSync: Connect the Web', 'Overview: The Connected Educational Experience Core Objective To solve the communication disconnect between schools and homes by building a unified platform that enhances student learning, ensures physical safety, and supports mental well-being. Key Features & Requirements: Academic Analytics: Tools to visualize and track student growth and performance over time. Safety Systems: Secure gate-pass management and integrated transport tracking. Mental Wellness Support: Features like anonymous check-ins, AI-driven sentiment analysis, and real-time chat/notifications (requiring clean state management). The Target User Experience (Dual-Portal) For Parents: A rich, interactive mobile application designed to track milestones, view academic progress, and monitor safety (like real-time bus tracking with proximity alerts). For Teachers: A comprehensive web dashboard enabling them to monitor the holistic health and progress of their entire classroom at a glance. Innovation Opportunities ("Think Outside the Box") Integrating gamified learning paths to reward students for consistent homework submissions. Seamlessly embedding real-time bus tracking directly into the parent portal. Problem Statement: Background: Disconnected communication between parents, teachers, and students leads to blind spots in academic progress and hinders early intervention for student well-being. The Challenge Create technology solutions that improve students'' learning experiences, safety, mental well-being, and foster seamless collaboration between parents and schools. Core Technical Requirements: Performance Analytics: Visualizing student growth over time. Student Safety Systems: Secure gate-pass management and transport tracking. Mental Wellness Support: Anonymous check-ins and AI-driven sentiment analysis. Ensure clean state management to handle real-time chat and notifications efficiently. The User Experience: A dual-facing portal: A rich, interactive mobile view for parents to track milestones, and a comprehensive web dashboard for teachers to monitor their entire classroom''s holistic health. Think Outside the Box: Gamified Learning Paths: Rewarding consistent homework submissions. Real-Time Bus Tracking: Integrated directly into the parent portal with proximity alerts. Tech Stack Guidelines: Complete Freedom: There are no restrictions on the programming languages, frameworks, or databases you can use. Teams are entirely free to choose any tech stack they prefer to architect, build, and deploy their solution. Eligibility: Open to students across India. Individual and Team Participation (1&ndash;4 Members). Students from any branch or academic year are eligible. Beginners as well as experienced developers are welcome. Rules & Guidelines: Projects must be original and developed by the participating team. AI tools may be used as development assistants; however, participants must be able to explain their implementation during evaluation. Teams must own the submitted source code and project assets. The decision of the judging panel will be final and binding.', '2026-07-07T19:30:00+05:30', '2026-07-24T21:05:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/edusync-connect-the-web-paper-buddy-1712464', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001712083', 'Shepreneurs 2026', 'Shepreneurs 2026 A 10-Day Women''s Startup Challenge Presented by TechVerse Solutions &times; She Builds What is Shepreneurs 2026? Shepreneurs 2026 is a 10-day online challenge for women who want to build a business. It doesn''t matter if you are just starting out or already running something small this challenge is for you. Your idea can be anything: a tech business, a work-from-home business, a small shop, a food business from your home, a service you offer people anything you''re good at. If it''s your idea, you can join. This is not a boring class where you just sit and listen. In this challenge, you will actually work on your idea, get help from real mentors, and show your progress step by step. In 10 days, you won''t just "learn" something you will actually build something real. Who Can Join Shepreneurs 2026? Anyone. You do not need to be an expert. You do not need to already have a business. This challenge is open to: Students (School & College): if you have an idea and want to start early with proper guidance. Working Women: if you have a job but always wanted to build something of your own. Homemakers & Mothers: if you manage your home and have an idea you never got the time to start &mdash; this challenge is made to fit into your daily routine. Women with just an Idea: if you''ve been thinking about something for a long time but never took the first step. Women already Building Something Small: if you need guidance and support to keep going. Women who already run a Business: if you want to grow it or fix something in it. Student, working woman, homemaker, mother, new founder, or business owner everyone is welcome. No matter your age or background, there is a place for you here. Special Mother & Daughter Recognition We believe women inspire women. Daughters who encourage their mothers to join Shepreneurs 2026 will be celebrated alongside them. Selected Mother & Daughter pairs will receive special recognition, exclusive appreciation gifts, and a special feature during the event. Kickoff Meet &ndash; 20th Before the challenge starts, there will be a live meet on the 20th where everything will be explained clearly: what to do, how to do it, how to send your videos, and how the WhatsApp group will work. This meet is for every participant, so nobody feels confused about what is happening. Come with your questions &mdash; they will be answered live. How Does It Work? The challenge runs for 10 days. It is fully online, so you can join from your home, your college, or your workplace  anywhere. Days What You Do Day 1 &ndash; 2 Think about your idea clearly. Record a simple 3&ndash;5 minute video introducing your idea. (Round 1 &ndash; Ideation Round submission, see below.) Day 3 &ndash; 6 Start working on your idea and make real progress. Prepare and submit your Demo Video link. (Round 2 &ndash; Demo Video Round.) Day 7 Mentorship day with industry experts. Day 8 &ndash; 9 Use the mentor''s advice to improve your idea. Day 10 Final video showcasing your complete journey and pitch your business/product to the panel. (Round 3 &ndash; Business Pitching Round.)   All your videos, from Day 1 to Day 10, will be uploaded on our YouTube channel. This way, more people get to see your journey and your business. Challenge Rounds Shepreneurs 2026 is judged across three rounds: Rounds Structure Round 1 &ndash; Ideation Round: Participants must submit their business idea, including the problem they aim to solve, their proposed solution, and what makes their idea unique. Round 2 &ndash; Demo Video Round: Participants must submit a demo video showcasing their idea, prototype, product, or the progress they have made during the challenge. Round 3 &ndash; Business Pitching Round: Participants must present and pitch their business or startup, highlighting their solution, progress, business model, and future vision. Prize Pool Worth ₹25,000+ Winner: ₹2,000 Cash Prize + Premium Swag Kit + Vouchers + Winner Certificate + Exclusive Recognition Runner-up: ₹1,800 Cash Prize + Premium Swag Kit + Vouchers + Winner Certificate + Exclusive Recognition Second Runner-up: ₹1,500 Cash Prize + Premium Swag Kit + Vouchers + Winner Certificate + Exclusive Recognition Consolation Prize I: ₹1,500 Cash Prize + Premium Swag Kit + Vouchers + Winner Certificate Consolation Prize II: ₹1,000 Cash Prize + Premium Swag Kit + Vouchers + Winner Certificate Special Theme Winners Best Business Idea Award: Awarded to the participant with the most innovative, practical, and impactful business idea. Mother & Daughter Recognition Award: Celebrating inspiring Mother & Daughter teams building dreams together. Hiring & Career Opportunities Outstanding participants may receive internship, freelance, or hiring opportunities from our hiring partners and startup ecosystem, based on their performance and available openings. Winner Selection Criteria Winners will be selected primarily based on the quality of their business idea, innovation, problem-solving approach, execution, and overall progress made during the challenge &mdash; not on professional video editing, expensive resources, or production quality. We encourage every participant to focus on building a meaningful solution rather than a perfect presentation. Why Should You Join? You will actually finish something. You get help from real mentors. You get seen by more people. You meet other women like you. Win exciting rewards! Opportunities for internships, freelance projects, and hiring through our partner network (subject to availability). You get recognised. What Will You Get at the End? Real progress on your business, not just a plan in your head. Honest feedback from a mentor about your specific idea. Videos of your journey for Instagram, your resume, or to show your work. A chance to win Cash Prizes, Vouchers, Goodies, Swags, and other exciting rewards. Opportunities for internships, freelance projects, and hiring through our partner network (subject to availability). New friends and connections with mentors and other women entrepreneurs. The confidence of turning your idea into action and taking the first step towards entrepreneurship. How to Register? Click the "Register" button on this Unstop page. Fill in your basic details and write a small note about your idea or your business. Join the Official WhatsApp Community (Mandatory) &mdash; link below. Mark your calendar for the Kickoff Meet on the 20th. Join the Official WhatsApp Community (Mandatory) All updates, submission forms, deadlines, and announcements will only be shared here. Joining is compulsory for every participant. https://chat.whatsapp.com/G4iZY4aV3tf6MgWctiZsW9 A Few Important Things This challenge is fully online. You only need a phone or laptop with internet. Joining the WhatsApp group is compulsory. Attend the Kickoff Meet on the 20th. Spots are limited. Joining is free unless told otherwise. Empowering Women to Build, One Startup at a Time', '2026-07-07T22:00:00+05:30', '2026-07-31T00:00:00+05:30', 'Online', 'online', '₹ 2,000', 'https://unstop.com/hackathons/shepreneurs-2026-techverse-solutions-1712083', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001712263', 'ELUCode', 'ELUCode is a fast-paced 2-hour competitive coding contest by EduLinkUp designed to challenge your problem-solving ability, algorithmic thinking, and coding speed. The contest brings together students and developers from across the community to compete on a set of carefully curated problems ranging from logical puzzles to algorithmic challenges. Participants will face multiple problems of varying difficulty levels, testing their understanding of data structures, algorithms, logic building, and efficient coding practices. Whether you are a beginner exploring competitive programming or an experienced coder looking to sharpen your skills, ELUCode provides a platform to learn, compete, and showcase your abilities. Top performers will be recognised through special achievement badges and certificates within the EduLinkUp ecosystem.', '2026-07-15T00:00:00+05:30', '2026-08-15T21:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/elucode-edulinkup-1712263', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001711474', 'Brainwave', 'Association of Computing, Technology & Science (ACTS-EDC), University School of Automation & Robotics (USAR), Guru Gobind Singh Indraprastha University (GGSIPU), East Delhi Campus is organizing BRAINWAVE 2026 ! Join the Official BRAINWAVE 2026 WhatsApp Community for Updates and Query Resolution:https://chat.whatsapp.com/KO79BBDUoqH7RqcepXjB1J About the Opportunity:BRAINWAVE 2026 is the flagship National Innovation Challenge organized by the Association of Computing, Technology & Science (ACTS-EDC), University School of Automation & Robotics (USAR), Guru Gobind Singh Indraprastha University (GGSIPU), East Delhi Campus. The competition brings together innovators, developers, designers, entrepreneurs, and problem-solvers from across the country to build impactful solutions for real-world challenges. Participants will have the opportunity to showcase their creativity, technical expertise, and entrepreneurial mindset while receiving mentorship from industry professionals. Through multiple evaluation rounds, expert mentoring, and an in-person Grand Finale, BRAINWAVE 2026 aims to foster innovation that creates meaningful social and technological impact. Tracks: Participants may choose a problem statement from the Official Problem Statement Tracks or compete under the Open Innovation Track. The official problem statements will be released in two phases: Track Set 1 (4 Tracks): 20 July 2026 Track Set 2 (4 Tracks): 30 July 2026 A total of 8 innovation tracks, each comprising multiple real-world problem statements, will be released across both track sets. Eligibility: Open to undergraduate, postgraduate, diploma students, and recent graduates from any recognized institution. Team size: 2&ndash;4 members. Inter-college teams are allowed. Inter-specialization and interdisciplinary teams are allowed. Why Participate? Solve real-world industry and societal challenges. Learn directly from experienced mentors and industry leaders. Network with innovators, entrepreneurs, researchers, and recruiters. Showcase innovative ideas before an eminent jury. Compete for cash prizes, internships, certificates, and exciting rewards. Gain national recognition for your innovation. Important Guidelines: The official PPT template and submission guidelines will be released before the submission round. Teams must submit only original work. Any form of plagiarism or misconduct will result in immediate disqualification. The decisions of the organizing committee and jury will be final and binding. Travel and accommodation will not be provided for the Grand Finale. Participating teams must make their own arrangements. Meals, refreshments, and participant kits will be provided during the Grand Finale. Code of Conduct: All participants, mentors, judges, sponsors, and volunteers are expected to follow the official BRAINWAVE 2026 Code of Conduct throughout the event. By registering, participants agree to comply with all event policies and guidelines. Official Code of Conduct (PDF):https://shorturl.at/5fyBj', '2026-07-07T17:00:00+05:30', '2026-08-21T09:01:00+05:30', 'Online', 'online', '₹ 20,000', 'https://unstop.com/hackathons/brainwave-2026-guru-gobind-singh-indraprastha-university-ggsipu-delhi-1711474', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001712204', 'HackVerse 2026 | National Level Innovation Hackathon', 'HackVerse 2026 | National Level Innovation Hackathon HackVerse 2026 is the flagship national-level innovation hackathon organized by the IEEE Computational Intelligence Society (IEEE CIS) Student Chapter, Bharati Vidyapeeth (Deemed to be University) College of Engineering, Pune. The hackathon aims to bring together passionate innovators, developers, designers, and problem-solvers from across India to build impactful technology-driven solutions for real-world challenges. Whether you''re passionate about Artificial Intelligence, Cybersecurity, Sustainability, Social Innovation, or Open Innovation, HackVerse 2026 provides a platform to transform your ideas into reality while learning from mentors, networking with industry experts, and competing for exciting prizes. Competition Tracks Participants can choose ONE of the following tracks: AI for Social Impact EmpowerHER Cybersecurity Made Simple For The Memes Open Innovation Eligibility &bull; Open to undergraduate and postgraduate students from any recognized college or university in India. &bull; Students from all engineering and technology disciplines are eligible. &bull; Cross-college teams are allowed. &bull; Team Size: 1&ndash;4 Members Competition Format Round 1 &mdash; Idea Submission Teams must submit: &bull; Problem Statement &bull; Proposed Solution &bull; PPT Presentation The submissions will be evaluated based on: &bull; Innovation &bull; Feasibility &bull; Technical Approach &bull; Impact The Top 100 Teams will advance to Round 2. Round 2 &mdash; Online 24-Hour Hackathon Qualified teams will participate in a 24-hour online hackathon, where they will develop a working prototype of their solution. Teams will receive mentorship from industry experts and experienced mentors throughout the hackathon. Round 3 &mdash; Offline Grand Finale The Top 25 Teams will be invited to Pune for the Offline Grand Finale. Finalists will: &bull; Demonstrate their prototype &bull; Present before an expert jury &bull; Compete for prizes, recognition, and networking opportunities Tentative Timeline Registration & Round 1 Submission Deadline 5 August 2026 Registration Deadline & Round 1 Submission Deadline (PPT / Idea Submission) 10 August 2026 Announcement of Top 100 Teams Selected for Round 2 13&ndash;14 August 2026 24-Hour Online Hackathon Round for Top 100 Teams 15&ndash;17 August 2026 Evaluation of Online Hackathon Submissions / Demo Review / Jury Screening 18 August 2026 Announcement of Top 25 Finalist Teams for Offline Grand Finale 21 August 2026 12-Hour Offline Grand Finale at, PuneFinal Presentations, Jury Evaluation, Prize Distribution & Closing Ceremony Note: The organizing committee reserves the right to revise the timeline if required. Any changes will be communicated through official channels. Evaluation Criteria Teams will be evaluated on: &bull; Innovation & Creativity &bull; Technical Feasibility &bull; Prototype Quality &bull; Problem-Solution Fit &bull; Scalability &bull; User Experience &bull; Social & Business Impact &bull; Presentation & Demonstration Rules &bull; Each team must contain 1&ndash;4 members. &bull; One participant can be part of only one team. &bull; Plagiarism or copied solutions will lead to immediate disqualification. &bull; Teams must submit only original work. &bull; Decisions of the organizing committee and jury shall be final. &bull; Participants must adhere to the IEEE Code of Ethics and maintain professional conduct throughout the event. What You''ll Get Cash Prizes Certificates Mentorship Sessions Networking Opportunities Internship & Career Opportunities National-Level Recognition Organized By IEEE Computational Intelligence Society (IEEE CIS) Student ChapterBharati Vidyapeeth (Deemed to be University) College of Engineering, Pune', '2026-07-15T00:00:00+05:30', '2026-08-21T22:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hackverse-2026-national-level-innovation-hackathon-bharati-vidyapeeth-deemed-university-1712204', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001712065', 'Trinity Idea Pitch Arena 2026 | Win ₹1,500 | MSME 6.0 Incubation Opportunity', 'The Research & Development (R&D) Cell in association with the Institution''s Innovation Council (IIC), Trinity College of Engineering & Technology (Autonomous), Peddapalli, proudly presents Trinity Idea Pitch Arena 2026. This event is designed to encourage students to think beyond conventional ideas and present innovative, practical, and scalable solutions to real-world challenges. It provides a platform for aspiring innovators, entrepreneurs, and problem-solvers to showcase their creativity before an expert panel. Outstanding ideas will be identified and guided for further development through the college''s Innovation & Incubation ecosystem and may be considered for submission to national innovation programs such as MSME Idea Hackathon 6.0, startup incubation initiatives, and other innovation opportunities. Themes: Participants may submit ideas in, but are not limited to, the following domains: Renewable Energy Robotics & Automation Industry 4.0 & Industry 5.0 Automotive Technology Energy Efficiency Frontier & Emerging Technologies Smart Agriculture Healthcare Education Technology Artificial Intelligence & Machine Learning IoT & Embedded Systems Social Innovation Sustainable Development Open Innovation (Any Original Idea) Eligibility: Open to Diploma, Undergraduate (UG), and Postgraduate (PG) students. Students from all branches and specializations are eligible. Individual and team participation are allowed. Maximum team size: 4 members. Interdisciplinary teams are encouraged.', '2026-07-07T00:00:00+05:30', '2026-07-12T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/trinity-idea-pitch-arena-hackathon-2026-trinity-college-of-engineering-and-technology-peddapalli-1712065', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708797', 'ExploitX: Into the Void 2.0 CTF', 'About the Competition: ExploitX: Into The Void &ndash; Season 2 is a national-level cybersecurity Capture The Flag (CTF) competition organized by ExploitX, Chennai Institute of Technology. The competition is designed to test participants'' technical knowledge, problem-solving abilities, and practical cybersecurity skills through real-world-inspired challenges. The event consists of two competitive rounds: Round 1 &ndash; Preliminary Round (Online): Date: 18 July 2026 Duration: 12 Hours Mode: Online Teams compete to solve cybersecurity challenges. The highest-scoring teams will qualify for the Grand Finale. Round 2 &ndash; Grand Finale (Offline): Dates: 30&ndash;31 July 2026 Duration: 24 Hours Venue: Chennai Institute of Technology, Chennai Qualified teams will compete in an intensive onsite Capture The Flag (CTF) competition. Winners will be decided based on the final scoreboard. Eligibility: Open to undergraduate, postgraduate, and diploma students from recognized institutions. Participants from any branch or specialization are eligible. Basic knowledge of cybersecurity is recommended but not mandatory. Team Formation: Team Size: 2 members. Inter-college teams are allowed. Inter-specialization teams are allowed. Competition Format: Solve challenges across multiple cybersecurity domains: Web Security Cryptography Forensics Reverse Engineering Binary Exploitation OSINT Miscellaneous Challenges carry different point values. Dynamic scoring may be used depending on participation. Teams must submit valid flags to earn points. Rankings are based on total score and submission time. Rules: Only registered team members are allowed to participate. Sharing flags, solutions, or hints with other teams is strictly prohibited. Any form of plagiarism, collusion, or unfair practices will result in immediate disqualification. Denial-of-Service (DoS/DDoS), attacks against the competition infrastructure, or attempts to disrupt the platform are strictly prohibited. Exploiting unintended vulnerabilities in the competition platform is not allowed unless explicitly permitted. Participants must use only their own accounts during the competition. The organizers'' decision regarding scoring, disputes, and disqualifications will be final. Organizers reserve the right to modify the rules if necessary to ensure fair competition. Registration: Registration Fee: ₹200 per team. Registration is confirmed only after successful payment (where applicable). Important Notes: Stable internet connectivity is required for the online round. Qualified finalists must arrange their travel to the offline venue unless otherwise notified. Participants are expected to maintain professional and ethical conduct throughout the competition. Detailed instructions and platform access will be shared with registered teams before the event.', '2026-06-30T00:00:00+05:30', '2026-07-31T11:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/exploitx-into-the-void-20-ctf-chennai-institute-of-technology-1708797', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001711745', 'Innovate 4 Impact', 'Note: If you have already registered on the website, there is no need to register again here.About the Challenge: Innovate 4 Impact is a national-level social impact innovation challenge organized by the IEEE WIE Affinity Group, Bharati Vidyapeeth (Deemed to be University) College of Engineering, Pune. The objective of Innovate 4 Impact is to promote innovation, problem-solving, and technical development among students while encouraging the participation of women in engineering and technology. The event encourages students to develop innovative, scalable, and technology-driven solutions that address real-world societal challenges across Healthcare, Wellbeing & Accessibility, Women''s Safety & Empowerment, and Smart Technology & Innovation. The competition provides participants with an opportunity to showcase their creativity, technical skills, and impactful ideas through a structured multi-round evaluation process. Team Formation Rules: Team Size: 2&ndash;4 members. At least one female member is mandatory. Cross-college teams are not allowed; all team members must belong to the same institution. Each participant can be a member of only one team. Team changes are not permitted after Round 1 without organizer approval. Eligibility Criteria: Open to undergraduate students across India. Students from all engineering and interdisciplinary domains are eligible. Cross-domain collaboration is encouraged. Participants must possess a valid college/institute ID card. Participation is restricted to students currently enrolled in recognized institutions in India. Event Themes: Healthcare, Wellbeing & Accessibility Women''s Safety & Empowerment Smart Technology & Innovation', '2026-07-06T00:00:00+05:30', '2026-08-07T23:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innovate-4-impact-ieee-wie-affinity-group-bharati-vidyapeeth-deemed-to-be-university-college-of-engineering-p-1711745', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001711964', 'National Level Technical Hackathon', 'About the Opportunity: Welcome to the National Level Technical Hackathon by Dhanalakshmi Srinivasan Engineering College, Perambalur. Embark on a thrilling journey at the National Level Technical Hackathon, an exciting hackathon challenge hosted by Dhanalakshmi Srinivasan Engineering College, Perambalur. This event is designed to bring together bright minds from across the nation to tackle technical challenges and showcase their innovative solutions. This hackathon is a prime opportunity to demonstrate your technical prowess, collaborate with peers through team participation, and contribute to the advancement of technology. Get ready to code, create, and compete! Eligibility and Registration: Registration on unstop is mandatory. Rewards and Prizes: Rewards and prize details (as provided). Note: Join the National Level Technical Hackathon and make your mark!', '2026-07-06T00:00:00+05:30', '2026-08-11T19:44:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/national-level-technical-hackathon-dhanalakshmi-srinivasan-engineering-college-perambalur-1711964', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001711619', 'The ₹100 Founder Challenge', 'Bootstrap 100: Build a Startup with Just ₹100 About the Competition: What if you had only ₹100 to build a startup? No investors. No venture capital. No expensive marketing campaigns. Just ₹100, your ideas, and your entrepreneurial mindset. Bootstrap 100 is a national-level entrepreneurship challenge organized by TechVerse Solutions, where participants are challenged to transform a simple idea into a scalable business using an initial budget of just ₹100. This competition is designed to evaluate innovation, business strategy, execution planning, and problem-solving rather than financial resources. Whether you''re an aspiring entrepreneur, student, innovator, or startup enthusiast, this is your opportunity to prove that great businesses are built with creativity, determination, and smart execution not just funding. If you believe your next big idea doesn''t require a huge investment, this challenge is for you.Theme: Build a startup with an initial investment of only ₹100. Challenge Statement: Imagine you have exactly ₹100 to start your entrepreneurial journey. Your objective is to design a startup that: Solves a real-world problem. Targets a clearly defined customer segment. Has a practical and sustainable business model. Can acquire its first customers. Generates revenue. Demonstrates the potential to scale from ₹100 into a successful business. The focus is not on creating unrealistic billion-dollar valuations but on presenting a practical roadmap that reflects strong entrepreneurial thinking. Who Can Participate? Open to students from all colleges and universities. Open to recent graduates and aspiring entrepreneurs. Participants from all academic backgrounds are welcome. Individual and team participation are allowed. Why Participate? Apply entrepreneurial thinking to a real-world challenge. Build a portfolio-worthy startup business plan. Showcase your business strategy and innovation skills. Present your idea before an expert judging panel (for shortlisted teams). Network with like-minded innovators. Earn an official certificate from TechVerse Solutions. AI Usage Policy: This is an AI-Friendly Competition. Participants are allowed to use AI tools such as ChatGPT, Gemini, Claude, Microsoft Copilot, or similar platforms for research, brainstorming, ideation, and content refinement. However: The final submission must reflect your own strategic thinking and decision-making. Participants remain fully responsible for the originality and authenticity of their work. Any external resources or AI-generated content should be appropriately acknowledged wherever applicable. Plagiarism, copyright infringement, or direct copying of existing business plans may result in disqualification. Judges may evaluate submissions based on originality, feasibility, reasoning, practicality, and execution. Submission Guidelines: All submissions must be uploaded through the Unstop Submission Portal only. Email or WhatsApp submissions will not be accepted. Participants are responsible for submitting their entries before the deadline. Incomplete or late submissions may not be evaluated. Rewards & Recognition: Bootstrap Grant: In the spirit of this competition, the top-performing teams will receive a symbolic ₹100 Bootstrap Grant, celebrating the idea that every successful startup begins with a small step. Rewards: Winner: ₹100 Bootstrap Grant Winner Certificate Runner-up: ₹100 Bootstrap Grant Runner-up Certificate All eligible participants will receive an Official Certificate of Participation. The Top 10 Teams will be shortlisted for the Live Startup Pitch Finale, where they will present their ideas before the judging panel. Code of Conduct: Participants are expected to maintain professionalism and academic integrity throughout the competition. The following may result in immediate disqualification: Plagiarism or copied content. Copyright or intellectual property violations. Submission of another participant''s work. Misleading or false information. Any attempt to manipulate the evaluation process. The decision of the organizing team and judging panel shall be final and binding. About TechVerse Solutions Community: TechVerse Solutions Community is a student-driven innovation community dedicated to empowering learners through competitions, hackathons, workshops, industry-oriented challenges, and skill-development initiatives. Our mission is to bridge the gap between academic learning and real-world application by creating opportunities that inspire innovation, entrepreneurship, and continuous learning.Stay Connected with the Community Stay updated with important announcements, upcoming competitions, workshops, hackathons, learning resources, and community activities by joining our official platforms. Instagram: Follow us for event updates, behind-the-scenes content, and winner announcements. LinkedIn: Connect with us for professional updates, opportunities, and industry-focused content. YouTube: Subscribe for tutorials, workshops, expert sessions, and event highlights. WhatsApp Community: Join our official community to receive timely notifications about competitions, internships, hackathons, and exclusive opportunities. Official Links: Instagram: https://www.instagram.com/techverse.098/ LinkedIn: https://www.linkedin.com/company/tvsolutions YouTube: https://www.youtube.com/@techverse.098-m8y WhatsApp Community: https://chat.whatsapp.com/Ie4FzRGHelb5c697mefvH7 Following or joining these platforms is recommended to stay informed about the competition and future opportunities. Ready to Build Your Startup? Every unicorn once started with almost nothing. Now it''s your turn to prove that ₹100 is enough to start something extraordinary. Think Smart. Build Lean. Bootstrap Your Future.', '2026-07-06T10:00:00+05:30', '2026-07-13T16:00:00+05:30', 'Online', 'online', '₹ 100', 'https://unstop.com/hackathons/the-rs100-founder-challenge-techverse-solutions-1711619', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001711499', 'Varithon 2026', 'Every year, Maharashtra witnesses one of its largest and most significant traditions &mdash; the Wari, where millions of devotees from across the state come together and embark on a remarkable journey to Pandharpur. This journey is much more than a pilgrimage; it is a path of tyag (sacrifice), devotion, and unwavering faith in Lord Vitthal.However, every year, several challenges arise during the Wari, including traffic congestion, crowd management, temple queue management, accommodation for Warkaris, healthcare accessibility, emergency response, and many others. Recognizing these challenges, our Head of Department, Dr. Anjali Bhatlawande, envisioned a platform where technology and innovation could contribute meaningful solutions. Thus, Varithon 2026 was born.Under the leadership and guidance of Dr. Sachin Sakhare, Ms. Swati N. Deshmukh, and Dr. Anjali Bhatlawande, Varithon 2026 aims to create a meaningful impact and engage millions of people in its mission and journey.Building upon the successful organization of Toycathon 2026, Varithon 2026 aspires to reach even greater heights and inspire innovative solutions for one of Maharashtra''s most cherished traditions. Tracks/Themes: This year, Varithon 2026 invites participants to submit projects under the following four tracks: 1. Health, Safety & Emergency Response Track Focused on healthcare, emergency management, public safety, and risk mitigation during the pilgrimage. 2. Crowd, Mobility & Resource Management Track Focused on crowd movement, transportation, logistics, infrastructure, and operational efficiency throughout the Wari. 3. Pilgrim Experience & Temple Management Track Focused on improving the overall experience of Warkaris before, during, and after reaching Pandharpur and visiting the temple. 4. Open Innovation Track This track encourages participants to identify and solve any challenge related to the Wari that is not explicitly covered under the above themes. Our Suggestion to Participants: We strongly encourage participants to experience the Wari firsthand, interact with stakeholders, understand the on-ground challenges, and develop practical, scalable, and impactful solutions for Varithon 2026. Why Participate? Prize pool worth ₹1,00,000. Opportunity to showcase your solutions directly to industry leaders, academicians, and government stakeholders. Chance to transform your idea into a startup or social venture. Networking opportunities with students from across India. Opportunity to work on real-world problems impacting millions of people. Certificates for participation and progression through competition stages. Recognition at a national-level innovation platform. Timeline at a Glance: Team Registration Opens: 15 June 2026 Team Registration Closes: 30 July 2026 Stage 1 Report Submission: 18 July 2026 &ndash; 31 July 2026 Stage 1 Results: 5 August 2026 Stage 2 Video Submission (3&ndash;5 Minutes): 6 August 2026 &ndash; 16 August 2026 Stage 2 Results: 22 August 2026 Stage 3 Grand Finale Hackathon: 28&ndash;29 August 2026 at MMCOE Campus, Pune Team Formation Guidelines: Team size must be between 2 and 5 members. Participants must be undergraduate students aged 17&ndash;25 years. Every team must appoint a Team Leader, who will serve as the primary point of contact (POC) for all communications from the Varithon team. Once registration is completed, changes to the team composition will not be permitted. Inter-college, inter-department, and inter-year teams are allowed. Registration Details: Registration is completely free of cost. Participation certificates and stage-wise achievement certificates will be provided. Only the shortlisted 50&ndash;100 teams qualifying for Stage 3 will be required to pay a nominal convenience fee to support arrangements for the 24-hour Hackathon at the MMCOE Campus. Details regarding the fee will be communicated to shortlisted teams. No report, presentation, or project submission is required while filling out this registration form. This form is solely intended for collecting team formation details. Upon successful registration, each team will receive a unique Team ID (will take a few days), which will serve as the official identity of the team throughout the Varithon 2026 journey. Important Links: Brochure: https://canva.link/o6vdzq9l1hsl22r  Rulebook: https://canva.link/rhdadt4c0r2vu78 Linktree: https://linktr.ee/mmcoe_varithon2026  Report Template: https://drive.google.com/file/d/1mv0UOx1WaZQ4-4GSwNn8OWdrjiYSNAHN/view  For Queries: Atharva Chaudhari: +91 97678 11342 Kalyani Bhandari: +91 98221 45349 Urja Doshi: +91 91686 99716', '2026-07-05T00:00:00+05:30', '2026-08-29T10:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/varithon-2026-marathwada-mitra-mandals-college-of-engineering-mmcoe-pune-1711499', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710309', 'ThunderCipher Case Files #001: The Crypto Heist', 'ThunderCipher Case Files is a monthly investigation-based Capture The Flag (CTF) series where participants analyze realistic enterprise environments inspired by publicly documented cybersecurity incidents. Unlike traditional CTFs, you''ll investigate digital evidence, identify cryptographic weaknesses, reconstruct incidents, and solve challenges that mirror real-world security failures. Date: 18 July 2026 Mode: Online Individual Based Duration: 8 Hours Challenges: 6 Investigation-Based Cases', '2026-07-03T00:00:00+05:30', '2026-07-19T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/thundercipher-case-files-001-the-crypto-heist-thundercipher-1710309', 'external', ARRAY['Web3']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709796', 'HI Labs AI & Tech Hackathon 2026 | ₹10,000 Prize Pool', 'Hack the Future Hack the Future is a one-day hackathon for builders, thinkers, and problem solvers, organized by HiLabs. Date: 12th July 2026Location: HiLabs, Lucknow (location on map) Bring your laptop. No laptop, no entry. What is This? HiLabs is opening its doors for a full-day hackathon where students come in, pick a problem, build a solution, and pitch it &mdash; all in one day. No slides. No theory. Just execution. This isn''t a quiz. This isn''t a seminar. It''s the closest thing to a real engineering day you''ll experience as a student. Rewards Winner: ₹5,000 cash 1st Runner Up: ₹2,000 cash 2nd Runner Up: ₹2,000 cash All participants get goodies & certificates Total Prize Pool: ₹10,000 Guidelines Register before the deadline &mdash; seats are limited. Bring your own laptop &mdash; mandatory. Problem statements will be revealed on the day. Submission includes a working prototype + 3-minute pitch. Judging will be based on idea, execution, and presentation. No plagiarism &mdash; builds must be original. HiLabs team''s decision is final. Why Show Up? Win real cash. Get seen by the HiLabs founding team. Network with students who actually build things. Receive a certificate of participation. Top performers may get a direct interview call for the Fellowship Program. That last one matters more than the prize money.', '2026-07-02T00:00:00+05:30', '2026-07-11T00:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/hi-labs-ai-tech-hackathon-2026-rs10000-prize-pool-human-intelligence-labs-private-limited-1709796', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710806', 'Safe Click Hackathon', 'Symbiosis University of Applied Sciences is going to conduct a Safe Click Hackathon 2.0 in collaboration with the MP Police. Students from universities and schools can participate in a 4-hour sprint hackathon. Students can form a team of 2- 4 members. Only 20 Teams are allowed on First Come First Serve Basis No shortlisting; direct to the offline round. Date - 7 July 2026 Time - 10:00 AM- 4:00PM  Venue - Seminar Hall 2, Symbiosis University Of Applied Sciences All Participants will receive a participation certificate from the Commissioner of Police', '2026-07-04T00:00:00+05:30', '2026-07-06T14:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/safe-click-hackathon-symbiosis-university-of-applied-sciences-suas-indore-madhya-pradesh-1710806', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710516', 'Agents of Change – National Agentic AI Bootcamp & Buildathon 2026', 'AGENTS OF CHANGE &ndash; National Agentic AI Bootcamp & Buildathon 2026 is a two-day national-level event organized by the OIST ACM and ACM-W Student Chapter to introduce participants to the rapidly evolving field of Agentic AI. The event combines an expert-led hands-on bootcamp with an exciting buildathon where participants will work in teams to design and develop intelligent AI agents capable of solving real-world campus problems. Event Dates 10 &ndash; 11 July 2026 Eligibility Open to all college students Team Size: 1 - 4 members Event Format Day 1 Introduction to Agentic AI Hands-on Workshop Buildathon Kick-off Team Formation Mentor Guidance Project Development Project Submission (GitHub Repository + Demo Video) Day 2 Project Evaluation Shortlisting Live Demonstrations Final Presentations Winner Announcement Certificates & Awards Submission Requirements GitHub Repository Demo Video Working Project Evaluation Criteria Innovation & Creativity Technical Implementation Agentic AI Concepts User Experience Practical Impact Presentation & Demo Rules Teams must consist of 1 - 4 members. Registration Fee: ₹399 per team (₹299 per team for ACM Members) & ₹199 for solo participants. Accommodation (Optional): ₹450 per person (Includes 2 days'' stay and 3 meals per day). Only original work is permitted. AI tools and open-source libraries may be used. Plagiarism will result in disqualification. Projects must be submitted before the submission deadline. A registration fee is applicable for participation. Paid accommodation is available for outstation participants (subject to availability). Join the official WhatsApp group after registration for fee payment, accommodation, and event updates. Participants must carry a valid College ID and laptop. Judges'' decisions will be final. Perks Participation Certificates for all participants. Top 3 Teams will receive Winner, First Runner-up, and Second Runner-up Awards. Top 3 Teams will receive Goodies & AICTE-Approved Internship. &zwj;Mentorship from Industry Experts. Hands-on Experience with Agentic AI. Networking Opportunities with AI Enthusiasts and Professionals. OIST Participants will receive an AICTE Virtual Internship (as per AICTE guidelines). After registering, join our official WhatsApp Community for updates: https://chat.whatsapp.com/D7KDYUxAhOr1meDpJjFePL', '2026-07-03T20:30:00+05:30', '2026-07-11T15:30:00+05:30', 'Online', 'online', 'AWARDS AND PAID INTERNSHIP', 'https://unstop.com/hackathons/agents-of-change-national-agentic-ai-bootcamp-buildathon-2026-agents-of-change-2026-oriental-group-of-institu-1710516', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699177', 'Tech-A-Thon 5.0 - By ECE Society', 'ECE Society, BIT Mesra proudly presents its flagship innovation event: Tech-A-Thon 5.0. This month-long hybrid inter-college innovation sprint, scheduled from 18th July to 23rd August 2026, brings together students from across India to develop impactful solutions. Theme: GreenGrid: Agro-Tech and Rural Development Areas of Focus: Smart Agriculture & Precision Farming Food Processing & Supply Chain Innovation Rural Development & Accessibility Sustainable Energy & Automation AI/ML for Agricultural Applications IoT & Embedded Systems for Rural Solutions Open Innovation Participants will leverage emerging technologies, including Artificial Intelligence, Machine Learning, IoT, Embedded Systems, Automation, Electronics, and Web Technologies, to create sustainable solutions for real-world problems. Exciting rewards await the top performers. Let your ideas cultivate the future. Eligibility Open to students pursuing full-time B.Tech/B.E., M.Tech/M.E.  or Dual Degree programs from engineering colleges across India. Participants must register in teams of 1&ndash;3 members. Cross-college teams are allowed. Cross-year teams are allowed. Cross-specialization teams are allowed. Rules and Guidelines All members of the team must register using their WhatsApp numbers. All members must register using their official university email IDs. If unavailable, a Gmail ID may be used. A participant must be a member of only one team. Rounds and Stages Round 1 :  Quiz-A-Bit A 60-question multiple-choice assessment covering aptitude, technology, electronics, and general awareness. Any one team member may attempt the quiz, and the score obtained will represent the team''s total for Round 1. You can attempt the assessment once the round is live- Friday, July 24, 2026, at 12:00 PM till Sunday, July 26, 2026, at 11:59 AM. Each team is allowed only one attempt. The assessment must be completed in a single sitting i.e., you must finish the task before the timer runs out. There is no negative marking. In case of a tie, completion time will be considered first, followed by accuracy. Round 2 : Tech-A-Bit (Hackathon Round) All shortlisted teams will gain access to the detailed problem statement once the round goes live on 29th July 2026. The document will clearly outline the challenge, steps to follow, and the evaluation process. Once completed, team leaders will be required to submit their solution as per the instructions provided in the problem statement. This may include a private GitHub repository link and any other assets or documentation needed for evaluation. Further submission instructions and access credentials will be shared closer to the round launch. The Submission window is from Wednesday, July 29, 2026, to Wednesday, August 12, 2026, 11:59 PM. Teams can change their submissions until 11:50 PM on Wednesday, August 12, 2026. Only the team leader can make the submission. Participants can choose a topic from the provided list or propose their own ideas based on the theme. If we select your topic, you and others can work on projects related to it. Round 3 : Presentation of Solutions Top teams will present their solutions before the panel of Team ECESoc. Presentations may be conducted in online or offline mode based on the feasibility of the participants and event requirements. Final schedules and presentation guidelines will be communicated to shortlisted teams. Round 4: Grand Finale Top Teams from the Presentation Round will finally present the solutions on the final Day where the winners will be decided. This presentation may be conducted in online or offline mode based on the feasibility of the participants and the event requirements. Rewards and Prizes Winning teams will receive exclusive prizes, goodies, and recognition. Winning teams will receive exclusive goodies worth ₹20k. All teams qualified for Round 2 to get appreciation certificates. 10% additional discount on Unstop Pro for all participants. Join us in building technology-driven solutions that empower farmers, strengthen food systems, and accelerate rural transformation.', '2026-07-04T00:00:00+05:30', '2026-08-23T20:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/tech-a-thon-50-bit-mesra-ranchi-1699177', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710621', 'AlgoSprint 2026 – Online Coding Challenge', 'About the Challenge AlgoSprint 2026 is an exciting online coding competition designed to test participants'' programming, logical reasoning, and problem-solving skills. The challenge consists of carefully curated algorithmic problems ranging from Easy to Hard difficulty levels. Whether you''re a beginner looking to gain experience or an experienced programmer aiming to compete with the best, AlgoSprint 2026 provides the perfect platform to showcase your coding abilities. Eligibility Open to all college students across India. Individual participation only. Students from any branch and any year can participate. Challenge Format Mode: Online Duration: 2 Hours Total Questions: 5 Difficulty Level: Easy &rarr; Hard Languages Supported C++ Java Python C Evaluation Criteria Automatic judging system. Solutions will be evaluated on hidden test cases. Ranking will be based on: Number of problems solved. Total time taken. Penalty in case of ties. Rules Individual participation only. Participants must use only one account. Any form of plagiarism or unfair practices may lead to immediate disqualification. The organizer''s decision will be final and binding. What You''ll Receive Winner Recognition Digital Certificate of Participation Winner & Top Performer Certificates National Leaderboard Ranking Real Competitive Programming Experience Skills Assessed Problem Solving Data Structures Algorithms Competitive Programming Logical Reasoning Time Complexity Analysis Why Participate? Practice coding under real contest conditions. Improve problem-solving and analytical thinking. Compare your performance with participants across India. Strengthen your programming skills for placements and coding interviews.', '2026-07-03T00:00:00+05:30', '2026-09-30T23:09:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/algosprint-2026-online-coding-challenge-gyan-ganga-college-of-technology-ggct-1710621', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710631', 'Hack Synthesis 3.0 - 2026', 'HackSynthesis A high-octane 30-hour hackathon where creativity meets code and ideas in order to transform into impactful solutions. The hackathon invites the brightest student innovators, designers and developers from across the nation to collaborate, complete and go beyond the boundaries of technology. Rules & Guidelines Plagiarism will lead to immediate disqualification. Respect mentors, volunteers, and other participants. Bring your own laptop, chargers, and essentials. Meals, workspace, lodging will be provided by the organizers. At any point of time do not resort to unfair means which may hamper the general flow of the hackathon. The decision of the judges, will be considered as final. The selected teams participating in the grand finale will be making their projects on the days of the hackathon itself. Participation Details Team Size: 1 to 3 members Eligibility: Open to college students across India Registration Fee: Free Platform: On-site, University of Engineering and Management, Kolkata Presentation Submission Details Theme: Open Innovation &ndash; no specific problem statements. What to submit? Your idea in the form of a presentation. Template? No template will be provided &ndash; you''re free to design your own. Your presentation must include: Team info and project title Clear problem statement Brief solution explanation Tech stack to be used Architecture/workflow diagram Unique features Future scope Submission Upload via the official portal using your registered email. Note Plagiarism will result in disqualification.', '2026-07-04T00:00:00+05:30', '2026-09-20T18:00:00+05:30', 'Online', 'online', '₹ 30,000', 'https://unstop.com/hackathons/hack-synthesis-30-2026-university-of-engineering-and-management-kolkata-1710631', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001707618', 'HackOcean - A National  Level Frontend Hackathon', 'HackOcean - National-Level Frontend Hackathon HackOcean is a National-Level Online Frontend Hackathon organized by the Digital Learning Group (DLG) in collaboration with Madhav Institute of Technology & Science (MITS), Gwalior. HackOcean is designed to challenge participants through multiple evaluation stages that assess problem-solving ability, product thinking, UI/UX design, presentation skills, and frontend development expertise. Participants are encouraged to leverage AI-powered development tools responsibly to build innovative, high-quality solutions.Competition Format Round 1 - Ignition (PPT Submission Round) The first round is designed to evaluate your problem understanding, solution approach, creativity, UI planning, and presentation skills. Participants are required to submit only a presentation (PPT). Instructions Download the Official PPT Template provided below. Prepare your solution only using the provided template. Submit the completed PPT before the deadline. Mention your Team Name clearly on the first slide. AI tools are allowed for research and design assistance. Official PPT Template Download the Official HackOcean Document ( PPT, RULEBOOK, BROCHURE ):https://drive.google.com/drive/folders/1F_U3dJ66GNIP3z7AILoMwg-DeWnyFaBP  Join Our Official WhatsApp Community Stay updated with important announcements, event reminders, Mission Packs, FAQs, shortlisted teams, and all HackOcean updates. Join Here:https://chat.whatsapp.com/EnMtdVGmw6JIBbaWccxfPX All important announcements regarding HackOcean will be shared only through the official WhatsApp Community. Evaluation Criteria (Round 1) &ndash; 50 Marks Criteria Marks Problem Understanding 12 Solution Approach & Innovation 12 UI/UX Wireframe & Planning 10 Presentation Quality 10 Creativity & Feasibility 6  IMPORTANT Only the TOP 50 Teams will be shortlisted for Round 2 (Grand Finale). The shortlisted teams will be announced after the evaluation of all PPT submissions. Round 2 &ndash; Deep Ocean (Grand Finale) Shortlisted teams will receive three frontend problem statements. Each team must choose ANY ONE problem statement and build a complete frontend solution within 12 Hours. Dummy data and AI-assisted development are permitted. Choose ANY ONE Problem Statement PS 01 &ndash; ABYSS | Deep Sea Exploration Co. ABYSS is a fictional deep-sea exploration company that offers premium submarine adventures to discover the hidden wonders of the ocean. Your challenge is to design and develop a modern, responsive landing page that highlights the company''s services, attracts visitors, and delivers a smooth user experience using modern frontend development practices. PS 02 &ndash; REEF | Ocean Conservation Platform REEF is a fictional environmental organization working to protect coral reefs and marine ecosystems. Build a clean and engaging landing page that encourages users to learn about the mission, participate as volunteers, and support ocean conservation through an intuitive frontend experience. PS03 &ndash; DeepSea Guardian | AI-powered Deep Ocean Pollution & Biodiversity Monitoring Develop an intelligent platform that continuously monitors deep-sea ecosystems using underwater drones, sonar, satellite imagery, and IoT sensors to detect illegal dumping, plastic accumulation, ghost fishing nets, coral bleaching, and endangered marine species while generating predictive environmental risk maps. General Requirements Responsive Multi-Page Frontend SEO Optimized Mobile Friendly Fast Performance Clean UI/UX Deploy on Vercel / Netlify / GitHub Pages Submit: GitHub Repository Live Deployed URL Evaluation Criteria (Round 2) &ndash; 50 Marks Criteria Marks Problem Solving 12 Performance & Core Web Vitals 10 UI/UX & Responsiveness 10 SEO & Accessibility 6 Visual Design & Creativity 8 Innovation 4 Rules Team Size: 1&ndash;4 Members AI Tools are Fully Allowed Code must be written during hackathon hours. Existing website copying will result in immediate disqualification. Team changes are not allowed after registration. Live deployed website submission is mandatory. Judges'' decision will be final. Registration To ensure committed participation and a competitive experience, registration is open with a nominal fee. Solo &ndash; ₹49 Duo (2 Members) &ndash; ₹89 Trio (3 Members) &ndash; ₹139 Squad (4 Members) &ndash; ₹179 After successful registration, teams will participate in Round 1 (Ignition). Prizes & Rewards Prize Pool Worth ₹1.5 Lakhs+ Premium Memberships CodeCrafters VIP Membership  AI Interview Credits Free .XYZ Domains for Top Teams Digital Certificates for All Participants 🇮🇳 National-Level Recognition Why Participate? Solve real-world frontend challenges. Build an impressive portfolio project. Compete with developers from across India. Win exciting prizes and sponsored rewards. Learn modern frontend technologies and AI-assisted development workflows. Showcase your creativity, presentation, and development skills on a national platform.', '2026-06-29T00:00:00+05:30', '2026-07-24T23:59:00+05:30', 'Online', 'online', '₹ 3,000', 'https://unstop.com/hackathons/hackocean-a-national-level-frontend-hackathon-madhav-institute-of-technology-and-science-mits-gwalior-1707618', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702624', 'International Innovation Challenge 3.0', 'Eligibility: Open to all students across various disciplines. Each team must consist of a minimum of 1 member and a maximum of 4 members. Team members can be from the same or different institutions, but cross-institutional teams must ensure clear communication. Registration Fee: MUJ Students (Indian): ₹699 per team (not per person) Non-MUJ Students (Indian): ₹799 per team (not per person) International Students: $50 per team Important Payment Guidelines: Ensure the correct registration fee is paid based on your team''s eligibility. International students paying the fee intended for Indian students will lead to team disqualification. While making the payment, please provide: Team Leader&rsquo;s details (Name, Contact Information) Correct Transaction ID Failure to provide the correct transaction ID or attach the correct payment proof will result in team disqualification. Project Requirements: Projects must be original and demonstrate innovation, reflecting a deep understanding of the problem being addressed. Participants should clearly outline the feasibility and practical applications of their solutions. PPT Submission for Shortlisting Round: Teams must submit their project in the form of a PPT of up to 9 slides, adhering to the template provided and including the prototype (if any). Round 1 Theme: Participants may choose any one of the 10 themes mentioned in the official guidelines. PPT submission deadline: 11th August, 2026. For International participants: The shortlisting round will be online, and the final round can be either online or offline. Shortlisting Process: After PPT submission, each project will be thoroughly evaluated by an expert panel of judges based on originality, innovation, feasibility, and impact. The results of the shortlisting round will be announced by 13th August, 2026. Shortlisted teams will receive an invitation to participate in the offline round at Manipal University Jaipur. International teams will have the option to join online or offline. General Rules: Teams must adhere to all deadlines and guidelines; any violation may result in disqualification. Decisions made by the judges and organizers are final and binding. Teams are encouraged to maintain ethical conduct and refrain from plagiarism. Originality will be strictly enforced. Note: A common Rest Room will be provided to the participants, one for boys and one for girls (no additional charges). Meals will be provided to the teams.', '2026-07-03T00:00:00+05:30', '2026-08-25T18:00:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/international-innovation-challenge-30-manipal-university-mu-jaipur-1702624', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709488', 'Devengers Promptwars 2026', 'About the Challenge DEVENGERS PromptWars 2026, hosted by DEVENGERS in collaboration with Google for Developers, is a 4-hour AI hackathon where participants solve a surprise real-world challenge using Generative AI, Google Gemini, prompt engineering, automation tools, and no-code/low-code platforms. Whether you''re a student, developer, or AI enthusiast, this is your chance to build, compete, and win. Important (Mandatory) ️ Joining the official DEVENGERS WhatsApp group is compulsory for all participants. The following will be shared only in the WhatsApp group: Problem Statement Submission Portal Link Google Meet Link Event Updates & Announcements Rules & Guidelines Top 10 Shortlisting & Results If you do not join the group, you may miss important updates and the submission process. Official WhatsApp Group:https://chat.whatsapp.com/I4qKhLJBX8N8l5IHUfzJvp Event Timeline (7 July 2026) 10:00 AM &ndash; 10:30 AMOpening & Live Briefing (Google Meet) 10:30 AMProblem Statement Release 10:30 AM &ndash; 2:30 PMBuild & Submit your solution. Required Submission: GitHub Repository Link Deployed Project Link Project Description Prompt Workflow / Strategy 4:00 PM &ndash; 5:00 PMTop 10 Final Pitching Round (Google Meet) After 5:00 PMResult Announcement Build. Learn. Lead. Impact.', '2026-07-01T00:00:00+05:30', '2026-07-07T18:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/devengers-promptwars-2026-devengers-promptwars-2026-devengers-1709488', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710440', 'Vibeathon 6.0 (Vibecoding Hackathon)', 'VibeAthon 6.0 | VibeCoding Hackathon Build Fast. Solve Real Problems. Get Recognized. VibeAthon 6.0 is the sixth edition of NxtGenSec''s flagship monthly VibeCoding Hackathon, bringing together students, developers, professionals, startup builders, and AI enthusiasts from across India to build impactful, production-ready web applications in just 72 hours. Unlike traditional coding competitions, VibeAthon focuses on solving real-world challenges by developing complete, publicly deployable solutions using modern technologies and AI-assisted development workflows. The official problem statement will be revealed during the Kickoff Session on 25 July 2026 at 10:00 AM IST. Why Participate? Build a real-world project for your portfolio. Showcase your technical and problem-solving skills. Collaborate with talented builders from across India. Compete for exciting prizes and national recognition. Explore internship, collaboration, and networking opportunities. Learn and build using AI-powered development workflows. Eligibility The hackathon is open to: College Students School Students Fresh Graduates Working Professionals Independent Developers Startup Builders Participants from all institutions and organizations across India are welcome. Team Size Individual Participation Teams of up to 4 members Hackathon Duration 25 July &ndash; 27 July 2026 (72 Hours) Registration Process Register individually or as a team. Complete the participant verification process. Join the official communication channel after approval. Attend the Kickoff Session to receive the official problem statement. Build, deploy, and submit your solution before the deadline. Technologies Allowed Participants are free to use: Any Programming Language Any Framework Cloud Platforms Databases APIs & SDKs AI Models Low-Code / No-Code Platforms Open-Source Technologies AI Coding Assistants Submission Requirements Each submission must include: Public GitHub Repository Live Deployed Application Proof of Development (PoD) Project Documentation (README) Evaluation Criteria Projects will be evaluated based on: Problem Understanding Innovation & Creativity Technical Implementation User Experience Product Completeness Deployment Quality Demo & Presentation Rewards & Recognition Winners Winner 1st Runner-Up 2nd Runner-Up Excellence Awards Every Participant Receives Digital Participation Certificate Internship Opportunities Project Showcase Community Recognition AI Workflow Recognition Builder Network Access Mentorship & Learning Resources Important Dates Event Date Registration Opens 1 June 2026 Builder Preparation 8&ndash;24 July 2026 Kickoff & Problem Statement 25 July 2026 Hackathon Begins 25 July 2026 Final Submission 27 July 2026 (11:49 PM IST) Evaluation 28&ndash;29 July 2026 Results Announcement 31 July 2026 Rules The official problem statement will be announced only during the Kickoff Session. Projects must be developed during the hackathon period. Teams may consist of 1&ndash;4 participants. Plagiarism or previously developed projects will lead to immediate disqualification. The submitted application must be functional and publicly accessible. The decision of the organizing team shall be final. Ready to Build? Turn your ideas into real-world products, collaborate with innovators across India, and showcase your skills on a national stage. Join VibeAthon 6.0 and build something impactful in just 72 hours!', '2026-07-03T00:00:00+05:30', '2026-07-24T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/vibeathon-60-vibecoding-hackathon-nxtgensec-1710440', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001710316', 'Codability''26', 'About the Opportunity: Get ready to showcase your software development prowess at Codability''26, an exciting online coding challenge hosted by the Madan Mohan Malaviya University of Technology (MMMUT), Gorakhpur. This event is designed for individuals eager to test their coding skills and problem-solving abilities in a dynamic virtual environment. As an individual participant, you''ll dive deep into the world of software development, tackling challenges that require strong technical acumen, agile methodologies, and effective problem-solving. This is your chance to shine and demonstrate your capabilities in a competitive yet collaborative setting. Themes/Problem Statements: While exact problems will be revealed to participants, this event focuses on areas related to Simple Programming,  This event focuses on areas related to Simple Programming, Data Structures and Algorithms Eligibility and Registration: This opportunity is open to individual participants. Competition Structure: The structure for this online coding challenge is as follows: There are no competition structure details provided at this time. Rewards and Prizes: Rewards & prize details (as provided): Prize pool for this competition is Rs 10 K First :- Rs 5000 Second:- Rs 3000 Third: Rs 1000 Don''t miss this chance to participate in the Codability''26 online coding challenge and elevate your software development skills!', '2026-07-03T00:00:00+05:30', '2026-08-09T20:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/codability26-mmmut-gorakhpur-1710316', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708229', 'NeuraMorphix HackForge 2026', 'About: NeuraMorphix HackForge 2026 is a 48-hour online hackathon organized by Team NeuraMorphix &mdash; a student-led AI initiative building next-generation solutions for real-world problems.Registration Period: June 29 &ndash; September 11, 2026 Build Sprint: September 12&ndash;13, 2026 (48 Hours) Results: September 13, 2026 (Tentative) Mode: 100% Online Theme: "Forge the Future &mdash; AI for Every Real Problem" Got an idea that can change the world? This is your stage. Build. Break. Forge. Problem Statements: Problem Statements Will Be Released at The Start of The Build Sprint on September 12, 2026, at 12:00 Am Ist. Each Team Must Choose One Problem Statement and Build Their Solution Around It. Solutions Should Demonstrate Originality, Feasibility, and Real-World Relevance. Eligibility: Open Exclusively to 1st and 2nd Year Undergraduate Students Students from Any College or University are Eligible Solo Participants or Teams of Up to 4 Members Inter-College Teams Are Allowed Inter-Specialization Teams Are Allowed Any Programming Language, Tech Stack, or Framework May Be Used Team Formation: Team Size: 1&ndash;4 Members Inter-College Teams Are Allowed Each Participant Can Be Part of Only One Team Hackathon Format: Mode: 100% Online Registration Period: June 29 &ndash; September 11, 2026 Build Sprint: September 12&ndash;13, 2026 (48 Hours) Problem Statement Release: September 12, 2026 | 12:00 Am Ist Submission Deadline: September 13, 2026 | 11:59 Pm Ist Submission Requirements: Each Team Must Submit: Project Overview Solution Explanation Git Hub Repository Link Demo Video (loom / You Tube) Supporting Ppt or Documentation ️ Late Submissions Will Not Be Accepted. Judging Criteria: Criteria Weightage Real-World Impact & Relevance 25% Technical Implementation 30% Innovation & Creativity 20% Demo & Presentation Quality 15% Scalability & Future Potential 10% Rules: All Work Must Be Original and Built During the 48-Hour Sprint (september 12&ndash;13, 2026). Plagiarism or Pre-Built Solutions Are Strictly Prohibited and Will Result in Immediate Disqualification. Open-Source Tools and Libraries Are Allowed with Proper Attribution. Each Participant May Be Part of Only One Team. The Decisions of The Judges and Organizers Are Final. Neura Morphix Reserves the Right to Update the Rules, Timelines, or Event Schedule if Necessary. Contact: Email: Neuramorphix@gmail.Com Powered by Unstop | Organized by Team NeuraMorphix | SRM Institute of Science and Technology (SRMIST), Kattankulathur, Chennai', '2026-06-29T00:00:00+05:30', '2026-09-13T21:00:00+05:30', 'Online', 'online', 'Prize Pool & Opportunity of Mentorship and Networking with Industry Leaders', 'https://unstop.com/hackathons/neuramorphix-hackforge-2026-srm-institute-of-science-and-technology-kattankulathur-chennai-1708229', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703351', 'SquidHack 2026', 'About the Hackathon: Squid Hack 2026 is a 24-hour innovation challenge designed to bring together creative minds, problem-solvers, and tech enthusiasts from across the country. Eligibility Criteria: Open to all UG, PG, and Dual Degree students from recognized universities and institutions. Students from all branches and specializations are eligible. Participants must possess a valid college ID. Cross-college teams are allowed. Team Size: Minimum Team Size: 1 Members Maximum Team Size: 4 Members At least one female member is mandatory in every team. Hackathon Format: Round 1: Registration & Idea Submission Register your team on Unstop by paying a registration fee of ₹100 per team. Submit your Problem Statement PPT outlining your proposed solution. The PPT should cover: Problem Statement, Proposed Solution, and Expected Impact. Participants are free to choose their own problem statement and PPT format. Round 2: Grand Finale (Offline) Only Shortlisted Teams from the PPT Round will advance to the Grand Finale. All finalist teams must complete the Final Round Registration (₹1500 per team) before the deadline to be eligible for participation. This is a fully offline round &mdash; all teams must be physically present at the venue: SAGE University, Indore. Teams will be required to build their complete project from scratch during the hackathon duration &mdash; no pre-built projects allowed. Problem statements will be published on the SquidHack website 2 days before the hackathon. Shortlisted teams must choose one of the available problem statements, with each statement having a limited team capacity. Mentors will be available on-site to guide and assist teams throughout the development phase. Round 3: Final Presentation & Demo Teams will present their working prototype before the judging panel. Judges will evaluate projects based on innovation, impact, feasibility, and execution. Themes: Participants can build solutions in any of the following domains: Artificial Intelligence & Machine Learning Web Development Mobile Applications Cybersecurity FinTech HealthTech EdTech Sustainability & Smart Cities Open Innovation Judging Criteria: Innovation & Creativity &ndash; 30% Technical Implementation &ndash; 25% Problem Relevance &ndash; 20% User Experience & Design &ndash; 10% Scalability & Impact &ndash; 15% Rules & Regulations: The project must be developed during the hackathon period. The idea should be original and not previously submitted in any competition. Open-source libraries and AI tools are permitted. Plagiarism or copied projects will result in immediate disqualification. One participant can register with only one team. Organizers reserve the right to verify project authenticity. All decisions made by the judging panel will be final and binding.', '2026-06-24T00:00:00+05:30', '2026-08-02T15:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/squidhack-sage-university-sageu-indore-madhya-pradesh-1703351', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708928', 'CMR Thinkfest 3.0', 'We are excited to announce that CMR College of Engineering & Technology (UGC Autonomous Institution), Hyderabad, Telangana is organizing the third edition&mdash;CMR THINKFEST 3.0 (National Level Project Competition), which is set to take place on 01st August, 2026. Education, Research and Innovation go hand-in-hand and with the intersection of disciplines, new ideas emerge and impulse innovation. CMRCET is known as the top-notch Institution for its internationally renowned quality in Multidisciplinary Innovation.CMR THINKFEST 3.0 is an exhilarating and innovative project competition that aims to bring together bright minds and creative thinkers from various institutions to collaborate, ideate and innovate in the realm of technology and beyond. It is an excellent opportunity for students to showcase their skills, network with peers and gain valuable experience in problem-solving. Themes: Students can submit a project of their own on any one of the themes of Sustainable Development Goals (SDGs) Any Project under open Innovation The best projects will receive a Prize pool money upto Rs. 40,000/- and also few Surprise Gifts. Apart from awards, innovative projects have the opportunity to get incubation support, mentorship, industry networking, resources and training. Details of the Cash Prize is as given below The Winner- ₹20,000/- I Runner- ₹10,000/- II Runner- ₹5,000/- Two Consolation Prizes-Each ₹2500/- (One Consolation Prize Exclusively for Girls Team) Team Size: 3-5 Members Important Deadlines: Event Date 01st August, 2026 Deadline for Registration 15th July, 2026 Acceptance Notification (On or Before) 17th July, 2026 Deadline for Payment (On or Before) 19th July, 2026     Shortlisted teams need to pay registration fee: 299/- per student (Includes Lunch). We believe that participation from your college would greatly enrich the collaborative spirit of this Project Competition. Your students'' innovative ideas and passion for technology would be an invaluable contribution to this event.Thank you for considering our invitation, and we eagerly anticipate your institution''s involvement in making CMR THINKFEST 3.0 a resounding success.', '2026-06-30T16:00:00+05:30', '2026-07-14T23:59:00+05:30', 'Online', 'online', '₹ 20,000', 'https://unstop.com/hackathons/cmr-thinkfest-30-cmr-college-of-engineering-and-technology-cmrcet-hyderabad-1708928', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709589', 'Code Cup 2026', 'About the Event : The World Cup fever is at its peak. ACM brings you Code Cup 2026! A 48-hour online, FIFA-themed build sprint where your code does the talking. Registration Process: Fill this google form : https://docs.google.com/forms/d/e/1FAIpQLSfsiCo7eDnFDhSwAWWttKZjvuMxbwBjaUKYxXszp3AMYBZEiQ/viewform After submitting the form and completing payment, proceed to register your team on Unstop to finalize your entry. Registration is considered complete only after both steps are done &mdash; form submission + payment and Unstop registration. After registration, teams will be added to WhatsApp groups for further discussions and announcements. Tracks (choose one): Computer Vision Cybersecurity Data & AI Analytics Eligibility: Open to all UG students BE/Btech Only Inter-college teams: Allowed Inter-specialization teams: Allowed Team size: 2 to 4 members Registration Fee: ₹200 per team Prize Pool ₹6,000 total &mdash; ₹2,000 for the winning team in each track (3 tracks) Competition Format &mdash; 2 Rounds Round 1: Idea Submission (PPT) Teams submit a PPT presenting their idea/approach for their chosen track No fixed template provided : teams may design their own PPT, but it must clearly include: Problem statement / idea explanation Proposed approach/methodology, Team member details (name, USN/ID, college, branch) Shortlisting for Round 2 is based on this PPT evaluation Round 2: Project Build + Live Demo Shortlisted teams build their project and submit: A GitHub repository with detailed documentation (README, setup instructions, approach) A demo video of the working project From these, finalist teams are shortlisted for the judging panel Judges evaluate the demo and submissions to select track winners Timeline: Registration Closes: Friday, 3rd July, 11:59 PM PPT (Round 1) Submission Closes: Saturday, 4th July, 11:59 PM Shortlist Notification: Sunday, 5th July (Morning/Afternoon) Project Work Period Begins: After the shortlist notification Project Submission (GitHub Repository + Documentation + Demo Video): Tuesday, 7th July, 11:59 PM Results Announcement: Saturday, 11th July Rules: All code and project work must be original and built during the event timeline &mdash; submission of pre-built/ready-made projects (built before the competition) is strictly prohibited and will lead to disqualification. Teams must not share code, ideas, or resources with other participating teams during the competition. Each team may compete in only one track. Team composition (members) cannot be changed after registration closes. All team members must be present and available for the live demonstration round; absence may lead to disqualification from that round. The organizing committee''s/judges'' decisions are final and binding. Teams must adhere to all submission deadlines, late submissions will not be accepted or evaluated. Any misconduct, misbehavior, or violation of these rules during the event may lead to disqualification at any stage.', '2026-07-01T00:00:00+05:30', '2026-07-07T23:59:00+05:30', 'Online', 'online', '₹ 2,000', 'https://unstop.com/hackathons/code-cup-2026-rv-college-of-engineering-rvce-bangalore-1709589', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699949', 'Hacklabify V1.0', 'Building the Next Generation of Innovators: HackLabify V1.0 is a technology-driven innovation platform designed to bring together students, developers, designers, entrepreneurs, researchers, and problem-solvers from across India. The initiative provides participants with an opportunity to collaborate, learn, and create impactful solutions to real-world challenges. Through challenges, mentorship, networking opportunities, and project development, HackLabify aims to foster creativity, technical excellence, and entrepreneurial thinking. Participants will have the opportunity to showcase their ideas, develop practical skills, and engage with a growing community of innovators. Key Focus Areas: Artificial Intelligence (AI) Cybersecurity FinTech Education Technology Healthcare Innovation Sustainability Productivity Solutions Emerging Technologies Why Participate? Solve real-world challenges Learn from mentors and industry experts Build innovative projects Network with like-minded individuals Gain practical experience Showcase your skills and ideas Our Vision: To create an accessible innovation ecosystem where talented individuals can transform ideas into meaningful solutions, connect with opportunities, and contribute to the future of technology and society. Event Venue: Master''s Union, Gurugram DLF CyberPark, Sector 20, Gurugram, Haryana, India Join HackLabify V1.0 and become part of a community dedicated to innovation, collaboration and technological advancement. Join us for an exciting journey of innovation! We look forward to seeing your brilliant ideas.You can also Register Here (Best)www.hacklabify.org/register', '2026-07-01T00:00:00+05:30', '2026-09-02T13:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hacklabify-v10-hacklabify-1699949', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709357', 'Frontend Wars 2026: Build the Future', 'About the Competition; Frontend Wars 2026Design. Build. Dominate. Frontend Arena proudly presents Frontend Wars 2026, a frontend-focused coding competition designed for developers who love building exceptional digital experiences. This competition is created to test participants across multiple dimensions including product thinking, frontend engineering, user experience, creativity, and data visualization. Participants will compete in multiple elimination rounds where they will solve real-world challenges under strict time constraints and demonstrate their ability to transform ideas into polished frontend applications. Eligibility; Open to all students and developers. Individual participation only. Cross-college participation allowed. Participants must have a GitHub account. Participants must submit all deliverables before the deadline.   Competition Format; Round 1; A time-bound frontend development challenge focused on product thinking, creativity, user experience, and implementation skills. Round 2; A frontend data visualization and storytelling challenge where shortlisted participants will transform complex datasets into meaningful digital experiences. Only shortlisted participants from Round 1 will advance to Round 2. Requirements; Technology Requirements; React 19. TypeScript. Vite. Tailwind CSS. Allowed Libraries; Framer Motion. Chart.js. Recharts. React Icons. Lucide React. Additional frontend libraries may be used provided they do not offer complete pre-built application templates. Not Allowed; Next.js. Vue.js. Angular. Svelte. Backend Development. Firebase. Supabase. Databases. External APIs. Pre-built Templates. AI-generated complete project submissions. Submission Requirements; GitHub Repository Link. Live Deployment Link. Short Project Description. Judging Parameters; Product Thinking. User Experience. Visual Design. Functionality. Code Quality. Creativity. Performance. Data Visualization.   Hall of Fame; The Champion, Runner-Up, Second Runner-Up, and Top 10 Finalists will be featured on the Frontend Arena Hall of Fame.', '2026-07-01T00:00:00+05:30', '2026-08-01T22:00:00+05:30', 'Online', 'online', 'Exclusive goodies and rewards will be awarded to the Champion of Frontend Wars 2026, sponsored by UptoSkills. also receive access to internship opportunities through UptoSkills', 'https://unstop.com/hackathons/frontend-wars-2026-build-the-future-frontend-arena-1709357', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709519', 'Aerothon 2026 - HAL x IITI', 'Aerothon 2026 is a national-level aerospace hackathon organized by Hindustan Aeronautics Limited (HAL) in collaboration with IIT Indore, bringing together innovators, engineers, programmers, and researchers to tackle real-world challenges in aerospace engineering using data-driven approaches. From machine learning for aerodynamic prediction to surrogate modelling for propulsion systems and intelligent optimization of aerospace designs, participants will work on cutting-edge problem statements inspired by modern aerospace engineering challenges. There is no entry/registration fee for this event! Competition Format: Round 1: Online Screening Round Teams will select and solve one of the provided problem statements and submit their proposed solution, methodology, and implementation. The best teams from across the country will be shortlisted for the Grand Finale. Only the Team Leader needs to register and add their remaining team members. The Problem Statements are available attachments section Round 2: Offline Grand Finale Grand Finale: 24-Hour Hackathon at IIT Indore Shortlisted teams will be invited to IIT Indore for an intense 24-hour hackathon on 7th&ndash;8th August 2026, where they will build, refine, and present their solutions before an expert panel. The finale offers participants an opportunity to: Work on industry-inspired aerospace challenges. Interact with faculty and researchers from IIT Indore. Engage with experts and officials from HAL. Network with students and innovators from across the country. Present solutions to a distinguished jury from academia and industry. Compete for prizes worth up to ₹2,10,000. Who Should Participate? Students interested in: Aerospace Engineering Artificial Intelligence and Machine Learning Data Science and Analytics Optimization and Scientific Computing Whether you''re an aerospace enthusiast, an AI developer, a simulation expert, or a problem solver looking to apply technology to the next generation of aviation and space systems, Aerothon 2026 is your platform to innovate and compete. Please note that the data is open source and/or generated and is not original data from HAL or IIT Indore Team Details: Team Size: 2&ndash;4 members Eligibility: Undergraduate and postgraduate students from recognized institutions across India Think. Build. Fly.  Do follow us for more information and for more hackathons like these! Instagram:snt.iiti: https://www.instagram.com/snt.iiti?igsh=MXV0NnI0YjMzemdieg==tl_iiti: https://www.instagram.com/tl_iiti?igsh=MWhqYXFvdXk3OXJr LinkedIn:SnT: https://www.linkedin.com/company/science-and-technology-council-iit-indore/TL: https://www.linkedin.com/company/tinkerers-lab-iit-indore/', '2026-07-01T00:00:00+05:30', '2026-08-08T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/aerothon-2026-hal-x-iiti-iit-indore-1709519', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709515', 'AI Career Hackathon', 'AI Career Challenge Ready to showcase your engineering skills beyond your resume? The AI Career Challenge is an AI-native hiring challenge for developers with 1+ year of experience. We''re looking for talented engineers for two roles: Frontend Engineer and Backend Engineer. On the day of the challenge, participants will receive a real-world AI product problem statement and will have 2.5 hours to build an MVP using AI tools and modern development workflows. Throughout the challenge, you''ll interact with mentors, discuss your technical approach, and present your solution in a startup-style technical interview. We evaluate more than just the final product. Our focus is on: Problem-solving approach Engineering fundamentals Technical decision-making Product thinking Communication and technical reasoning Top-performing participants will be referred to our startup hiring partners based on their skills and role fit. If you''re excited to solve challenging AI problems and demonstrate how you think, we''d love to see you there.', '2026-07-01T00:00:00+05:30', '2026-07-04T16:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/shebuilds-ai-career-hackathon-shebuilds-1709515', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709331', 'Smart School FinTech Innovation Challenge 2026', 'Smart School FinTech Innovation Challenge 2026 Build the Future of Education Through Technology Technology has transformed industries worldwide, yet many educational institutions continue to face challenges such as fragmented software systems, manual administrative processes, disconnected communication, outdated financial workflows, and inefficient operations. At PaperBuddy, we believe that the next generation of Software Engineers has the potential to solve these challenges by building innovative and impactful technology solutions. The Smart School FinTech Innovation Challenge 2026 is a national-level software engineering hackathon where students, developers, designers, and innovators come together to create production-ready software that solves real-world problems. This is more than just a hackathon&mdash;it''s an opportunity to demonstrate your engineering skills, solve meaningful challenges, collaborate with talented minds across India, and compete for exciting rewards, including a Software Engineer Pre-Placement Offer (PPO). Whether you''re passionate about Full Stack Development, Mobile Applications, Artificial Intelligence, Cloud Computing, Backend Systems, or Product Engineering, this challenge is built for you. Challenge Statement Educational institutions generate enormous amounts of data every day, yet many schools still rely on disconnected software, paperwork, inefficient fee management systems, and outdated administrative workflows. Your challenge is to design and develop a production-ready software solution capable of solving real-world problems within Smart Schools, Education Technology, Financial Technology, or Digital Productivity. Your solution should focus on creating measurable value by improving efficiency, enhancing user experience, automating repetitive processes, or introducing innovative digital solutions that can positively impact students, teachers, parents, and educational institutions. We encourage participants to think beyond traditional solutions and build products that are scalable, practical, and capable of solving real business problems. Submission Format Every participating team must submit the following before the final submission deadline: Project Presentation (PPT) The presentation should include: Problem Statement Proposed Solution Key Features System Architecture Technology Stack Future Scope Working Prototype Working Prototype A fully functional web, mobile, or desktop application demonstrating your solution. Source Code A complete GitHub repository with clean, well-documented, and properly structured code. Demo Video A 3&ndash;5-minute demonstration explaining the project, its features, workflow, and real-world impact. Project Documentation Include: Installation & Setup Guide Project Architecture APIs & Integrations (if applicable) Technical Overview Live Demo (Optional but Recommended) If your application is deployed, share the live URL for easier evaluation. Note: All submissions must be original. Any form of plagiarism will result in immediate disqualification. Eligibility Open to students across India. Individual and Team Participation (1&ndash;4 Members). Students from any branch or academic year are eligible. Beginners as well as experienced developers are welcome. Rewards & Recognition Winner Software Engineer Pre-Placement Offer (PPO) at PaperBuddy (subject to final technical evaluation and interview). Runner-Up ₹30,000 Cash Prize Second Runner-Up ₹20,000 Cash Prize All eligible participants will receive a Digital Certificate of Participation. Evaluation Criteria Projects will be evaluated based on: Innovation & Creativity Problem Solving Approach Technical Excellence Software Architecture Code Quality UI/UX Design Scalability & Performance Business Impact Product Demonstration & Presentation Rules & Guidelines Projects must be original and developed by the participating team. Plagiarism or copied work will lead to immediate disqualification. AI tools may be used as development assistants; however, participants must be able to explain their implementation during evaluation. Teams must own the submitted source code and project assets. The decision of the judging panel will be final and binding. Why Participate? Solve real-world challenges. Build a production-ready software product. Strengthen your resume and portfolio. Compete with talented innovators across India. Win exciting cash prizes. Earn an opportunity for a Software Engineer PPO at PaperBuddy. Showcase your skills before industry professionals.', '2026-07-01T00:00:00+05:30', '2026-07-16T19:15:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/smart-school-fintech-innovation-challenge-2026-paper-buddy-1709331', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001709437', 'AI for Bharat Hackathon 2026 – Build AI Solutions for India''s Real Problems', 'AI for Bharat Hackathon 2026 India faces problems that global, off-the-shelf AI solutions often fail to solve - language diversity, rural access gaps, agricultural unpredictability, and healthcare reach. This hackathon challenges participants to build AI-powered solutions tailored to real Indian contexts. Theme Tracks Regional Language AI (voice, translation, low-resource NLP) AgriTech (crop advisory, pest detection, yield prediction) Rural Healthcare Access (diagnostics, telemedicine tools) Smart Public Transport & Civic Infrastructure Financial Inclusion (rural banking, fraud detection, micro-credit) EligibilityOpen to students (undergraduate & postgraduate) and early-career professionals. Only Individual participation allowed for final submission. Format Stage 1: Idea/PPT submission (shortlisting round) Stage 2: 48 hour build sprint (online) Rules Use of open-source datasets, public APIs, and pre-trained models is allowed and encouraged Code must be original and built during the hackathon window (prior ideation is fine) Plagiarism or use of pre-built products will lead to disqualification All submissions must include a working prototype/demo + GitHub repo + 2-min explainer video Judging Criteria Innovation & relevance to Indian context (25%) Technical implementation (25%) Feasibility/scalability (20%) UI/UX & presentation (15%) Social impact potential (15%) Prizes Winner: ₹1000 Runner-up: ₹700 Best Use of AI for Social Good: ₹500 Winning Certificate', '2026-07-01T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-for-bharat-hackathon-2026-build-ai-solutions-for-indias-real-problems-indraprastha-institute-of-informatio-1709437', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708678', 'MSOC 2026 — MSTC Summer of Code Data Science', 'MSOC 2026 &mdash; MSTC Summer of Code (Data Science & Analytics Track) About the Program: MSOC (MSTC Summer of Code) is a guided learning-to-build program organized by the Microsoft Student Technical Club (MSTC), DA-IICT. Participants spend the initial weeks developing practical skills in Data Science and Applied AI before applying their knowledge in a structured, two-round hackathon. This track is designed for students who want to move beyond tutorials and build a complete data-driven project&mdash;from identifying a real-world problem to developing, documenting, and presenting a working solution. Track Details: Track: Data Science & Analytics. Team Size: 1&ndash;2 members. Mode: Online. What You''ll Do: Receive a real-world problem statement. Build, document, and demonstrate a working data-driven solution. Receive evaluation and feedback from MSTC mentors and faculty. Who Should Participate? This track is open to anyone interested in Data Science or Generative AI, whether beginner or intermediate, who wants a structured opportunity to build their first real-world project instead of learning only through tutorials. Eligibility: Open to all current undergraduate and postgraduate students of DA-IICT. Open to students from all academic years and disciplines. No prior experience in Data Science, AI, or Machine Learning is required. Each participant may be part of only one team. Both team members (for teams of two) must register individually on Unstop before the registration deadline. Community Support: Join the official MSOC WhatsApp community for updates, announcements, and mentor support: Rules & Regulations: All work must be original and created specifically for MSOC 2026. Reused or previously submitted projects are not permitted. The use of open-source libraries, frameworks, pre-trained models, and AI coding tools is allowed, provided they are properly credited in the project README. Teams may seek guidance from MSTC mentors; however, all core development must be completed by the team members. All updates regarding submissions, deadlines, and clarifications will be communicated through the official MSOC WhatsApp community and Unstop. Participants are responsible for staying informed. The organizing committee reserves the right to modify timelines, problem statements, or evaluation criteria if required, with prior notice. Participants are expected to maintain professionalism in all interactions with mentors, judges, organizers, and fellow participants. The decisions of the judging panel and organizing committee shall be final and binding. Disqualification Criteria: A team will be disqualified if: The submitted project is plagiarized, copied, or substantially reused from an existing public project without proper disclosure. The GitHub repository is private, inaccessible, or unavailable during evaluation. The team misrepresents dataset sources or fabricates results. Any form of misconduct, including impersonation or submission tampering, is identified. The submission is made after the deadline without prior approved extension.', '2026-06-29T00:00:00+05:30', '2026-07-08T20:00:00+05:30', 'Online', 'online', '₹ 600', 'https://unstop.com/hackathons/msoc-2026-mstc-summer-of-code-data-science-dhirubhai-ambani-institute-of-information-and-communication-techno-1708678', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001671501', 'Roboauto-2026', 'RoboAuto Hackathon 2026 &ndash; AGV & Automation Challenge: Date: 9th & 10th July 2026Venue: VJIT, Hyderabad⏰ Duration: 24 Hours (Day + Night)Team Size: 3&ndash;5 Members RoboAuto Hackathon 2026 is an intensive 24-hour hands-on robotics and automation challenge designed to push the boundaries of innovation in autonomous systems. Organized by the Robotics and Innovation Club of Vidya Jyothi Institute of Technology (VJIT), Hyderabad, this event invites engineering students to design and build Automated Guided Vehicle (AGV)-like robots and smart automation solutions that solve real-world industrial problems. Participants will work in teams to develop functional prototypes capable of tasks such as line-following, path planning, obstacle avoidance, and material transport&mdash;core concepts used in modern factories and warehouses. Throughout the hackathon, teams will receive guidance from experienced mentors and faculty, helping them refine their ideas and improve execution under real-time constraints. What You''ll Build: AGV-like robots for material handling. Line-following or path-guided systems. Obstacle detection and avoidance solutions. Mini automation systems simulating industrial workflows. Event Format: Duration: 24 hours (continuous build and overnight hacking). Structure: Idea pitching. Development and mentorship rounds. Final demo and evaluation. Why Participate?: Gain hands-on experience in robotics, embedded systems, and automation. Work on real-world industrial problem statements. Collaborate in teams within a competitive environment. Win exciting prizes from a ₹10,000 prize pool. Earn certificates and recognition.', '2026-04-25T07:30:00+05:30', '2026-07-08T18:29:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/roboauto-2026-vidya-jyothi-institute-of-technology-1671501', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001708852', 'Breaking Bot IPEC', 'About Breaking Bot IPEC: Breaking Bot IPEC is the flagship national-level hackathon jointly organized by IEEE Student Branch, Indraprastha Engineering College (IPEC), Ghaziabad, and Coders Den. Inspired by the iconic Breaking Bad universe, the hackathon challenges participants to "break" conventional thinking, experiment with bold ideas, and build innovative technology that solves real-world problems. More than just a coding competition, Breaking Bot IPEC is where creativity meets technology. Participants will collaborate in teams to transform ambitious ideas into impactful solutions while experiencing an energetic atmosphere filled with mentorship, networking, and innovation. Mandatory Steps: Fill the Mandatory Registration Form: https://forms.gle/MgGrg1WNp2zy8ESJA Submit the Idea Presentation (PPT) before the submission deadline. Failure to complete either of the above mandatory steps may result in disqualification. Join the official WhatsApp Community for important announcements, updates, and event-related communication: https://chat.whatsapp.com/FKgLSZ4OZ3cI0XfN8gjvIr Hackathon Tracks: Artificial Intelligence & Machine Learning Web Development Mobile App Development Cloud Computing Cybersecurity Blockchain & Web3 Internet of Things (IoT) Healthcare & MedTech Sustainability & Climate Technology Education Technology FinTech Open Innovation Participants are encouraged to solve real-world challenges by developing innovative, scalable, and impactful technology-driven solutions. Eligibility: Undergraduate students Postgraduate students Developers, designers, and technology enthusiasts from recognized institutions across India Team Size: 2&ndash;3 Members Cross-college teams are allowed. Cross-disciplinary teams are encouraged. Each participant can be a member of only one team. Competition Format: Round 1 &ndash; Online Idea Submission (Screening Round): The first round is an online elimination stage. Teams must submit a PowerPoint Presentation (PPT) explaining their proposed solution. The PPT should clearly cover the problem statement, existing challenges, proposed solution, key features, workflow or system architecture, technology stack, implementation roadmap, innovation, scalability, expected impact, and future scope of the project. The presentation should effectively communicate the originality, feasibility, and potential real-world impact of the proposed solution. Every submission will be evaluated on: Innovation Technical feasibility Problem relevance Practical implementation Clarity of presentation Scalability Real-world impact Only the highest-ranked teams will advance to the Offline Grand Finale. Round 2 &ndash; Offline Grand Finale: Shortlisted teams will be invited to Indraprastha Engineering College, Ghaziabad, where they will compete in an intensive offline hackathon. During the event, participants will: Build a fully functional prototype. Receive mentorship from industry experts. Validate and refine their solution. Present and demonstrate their project before an expert judging panel. Network with fellow innovators, mentors, recruiters, and professionals. The highest-scoring teams will be declared winners and receive exciting prizes, certificates, goodies, and recognition. Judging Criteria: Projects will be evaluated based on: Projects will be evaluated based on innovation and creativity, technical implementation, problem relevance, user experience (UI/UX), scalability, business potential, practical feasibility, presentation and demonstration, and the overall impact of the solution. Rules & Guidelines: All project ideas must be original. Teams are expected to build their prototype during the hackathon. Previously developed or commercially available projects are not permitted. Participants may use open-source tools, APIs, and frameworks while complying with their respective licenses. Any plagiarism, unethical conduct, or violation of the event rules will result in immediate disqualification. Shortlisted teams must remain present throughout the Offline Grand Finale. The decision of the organizing committee and judging panel shall be final. Why Participate? Build innovative solutions to real-world problems. Collaborate with talented developers and designers. Learn directly from experienced mentors and industry professionals. Present projects before experts and recruiters. Expand their professional network. Win exciting prizes, goodies, and certificates. Strengthen their portfolio with a real-world project. Gain exposure to internship, hiring, and collaboration opportunities. Enhance technical, communication, and teamwork skills. Why "Breaking Bot"? Inspired by the legendary Breaking Bad universe, Breaking Bot IPEC symbolizes breaking traditional boundaries of innovation and engineering. Just as the series challenged conventions, this hackathon encourages participants to think differently, solve complex problems, and build technology that creates meaningful impact. Bring your ideas, experiment fearlessly, and "cook" your next big innovation. Stay Connected: LinkedIn: https://www.linkedin.com/company/ieee-ipec/?viewAsMember=true Instagram: https://www.instagram.com/ieeeipec/ WhatsApp Community: https://chat.whatsapp.com/FKgLSZ4OZ3cI0XfN8gjvIr About the Organizers: IEEE Student Branch, IPEC: The IEEE IPEC Student Branch at Indraprastha Engineering College is committed to fostering innovation, technical excellence, and professional growth through hackathons, workshops, seminars, technical competitions, and industry collaborations. As a part of the world''s largest technical professional organization, IEEE IPEC empowers students to build impactful technologies for the future. Coders Den: Coders Den is a thriving student developer community focused on building technical skills through coding contests, hackathons, collaborative projects, workshops, and peer learning. Together with IEEE IPEC, Coders Den aims to create an engaging ecosystem where innovation, collaboration, and creativity thrive. Break Limits. Build Solutions. Become the One Who Breaks the Bot. Assemble your team, unleash your creativity, and get ready for an unforgettable innovation journey at Breaking Bot IPEC!', '2026-07-01T13:00:00+05:30', '2026-08-08T12:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/breaking-bot-ipec-inderprastha-engineering-college-ipec-ghaziabad-1708852', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001706104', 'COSC Hackweek', 'COSC Hackweek is a week long online event, presented by the CBIT Open Source Community. Hackweek is designed to help you learn, build, and explore the world of technology and open-source through daily challenges throughout the week. Whether you are taking your first step into tech or you''re an experienced developer looking to sharpen your skills, Hackweek offers something for everyone. Explore new technologies, solve hands-on challenges, and get exposure to various tools while being part of a vibrant learning community. Details: Participation: Individual participation Registration Fee: FREE Date: 06th July 2026 - 12th July 2026 Mode: Online Platform: Official COSC HackWeek Website + Discord  Eligibility Criteria: Open to all students, professionals, and coding enthusiasts regardless of their field or background Participants with varying levels of expertise from beginners to advanced programmers are welcome to join Basic programming knowledge in any language is recommended Guidelines & Rules: Daily challenges will be released on the official COSC HackWeek website Participants can attempt any number of challenges during the event period Solutions can be submitted as GitHub links, screenshots or other required formats. All submissions must be made before the final deadline (July 11, 2026 - 11:59 PM IST) Maintain respectful conduct and fair competition throughout the event Any form of misconduct or plagiarism may lead to disqualification Note: Stay tuned to the announcements channel for daily challenge releases and important updates Use the help channel for challenge-related queries and community support Points will be awarded based on challenge completions, and top performers will be featured and rewarded Participation certificates will be provided to all registered participants who submit atleast one solution during the course of the week. Embrace this fantastic opportunity to enhance your skills and connect with the programming community! Register now for FREE and let your coding brilliance shine at COSC HackWeek 2026!', '2026-06-27T00:00:00+05:30', '2026-07-05T23:59:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/cosc-hackweek-chaitanya-bharathi-institute-of-technology-cbit-hyderabad-1706104', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703344', 'Vibe2Vision', 'All participants are requested to read the complete rule book before the event. Vibe2Vision 2026 is a 36-hour innovation hackathon organized by the IEEE Women in Engineering (WIE) Chapter, IEEE VSSUT Student Branch. Participants will design and build impactful technology solutions under the theme "Catalyst for Equity &ndash; Engineering Resilient Ecosystems for Women." The hackathon emphasizes creativity, problem-solving, rapid development, and effective use of modern AI-assisted development tools to create functional, user-centric applications. Rules & Architecture Teams are free to choose any programming language, framework, AI tool, IDE, database, cloud platform, or deployment technology. Teams are expected to maintain active development throughout the event. The hackathon will run continuously for 36 hours. Participation is allowed in teams of 2 to 4 members. Every team must work on one of the three official challenge tracks. A GitHub push/check-in is mandatory every 6 hours to demonstrate continuous progress. (Night hours from 10:00 PM to 6:00 AM are exempt from mandatory check-ins.) Organizers reserve the right to monitor repositories and verify development progress at any stage of the hackathon. All submitted work must be original and created during the hackathon.', '2026-06-28T17:00:00+05:30', '2026-07-07T10:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/vibe2vision-ieee-sheaspire-30-veer-surendra-sai-university-of-technology-vssut-odisha-1703344', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704689', 'Cascade - A Cryptic Hunt', 'General: The competition will be conducted entirely through the official Cryptic Hunt Portal. Each registered team will receive unique login credentials before the event. Participants are responsible for keeping their login credentials secure throughout the competition. Competition Format: Teams must begin by reading the mission briefing available on the portal. The event consists of multiple case files that can be solved in any order unless specified otherwise. Answers must be submitted through the portal only. Successfully completing all case files unlocks the Final Stage. Completing the Final Stage marks the official completion of the event. Time & Ranking: The event timer starts when a participant first logs into the portal. Logging out does not pause the timer. Every submission is automatically timestamped. Final rankings will primarily be based on: Successful completion of all case files. Completion of the Final Stage. Official completion timestamp (earlier completion ranks higher). In case no team completes the Final Stage, rankings will be determined by overall progress. Any ties will be resolved using the timestamp of the last successfully completed case. Technical Guidelines: Participants are advised to use a stable internet connection. Technical issues arising from a participant&rsquo;s device or internet connection will not qualify for additional time. In case of portal-related issues, participants should immediately contact the organizing team. Fair Play Policy: Sharing answers or collaborating with other teams is strictly prohibited. Attempting to exploit bugs, gain unauthorized access, or interfere with the event portal is prohibited. Any form of plagiarism, cheating, or unfair practices will lead to immediate disqualification. The organizing committee reserves the right to review submissions in case of suspicious activity. Important: Decisions made by the judges and the organizing committee shall be final and binding. The organizing committee reserves the right to modify the rules if necessary. By participating, teams agree to abide by all event rules and the decisions of the organizing committee.', '2026-06-27T00:00:00+05:30', '2026-07-05T00:00:00+05:30', 'Online', 'online', '3k worth goodies from Upto Skills , Coding Ninjas & Unstop + Internship Opportunity', 'https://unstop.com/hackathons/cascade-a-cryptic-hunt-manipal-university-mu-jaipur-1704689', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001705001', 'Hack to Survive', 'Think you have what it takes to survive the ultimate challenge? Whatsapp group link - https://chat.whatsapp.com/Dhqhr4lbkY23HinrAD5wLe Hack to Survive is a thrilling Squid Game-inspired hackathon where every round is a test of skill, creativity, strategy, and innovation. Participants must survive multiple elimination rounds, solve real-world problems, and build impactful solutions under pressure to advance to the next stage. Whether you''re a developer, designer, entrepreneur, or problem solver, this is your chance to showcase your talent, compete against the best minds, and fight for the top spot on the leaderboard. Event Details: Date: 8 August 2026 Venue: TBA  Mode: To Be Announced What to Expect? Multiple survival-themed challenge rounds Exciting problem statements Networking with talented participants Certificates and recognition Prizes for top-performing teams A unique Squid Game-inspired competitive experience Only the strongest ideas survive. Will yours make it to the end?', '2026-06-27T00:00:00+05:30', '2026-08-08T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hack-to-survive-kiras-logic-1705001', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704716', 'VentureX', 'About the Competition: VentureX is an 18-hour hackathon where participants solve real-world problem statements provided by the judging panel at the start of the competition. Teams analyze the problem, develop an innovative and practical solution, and prepare a comprehensive presentation within the allotted time. The competition evaluates creativity, critical thinking, teamwork, and problem-solving under time constraints. Teams present their solutions before a panel of judges at the end of the hackathon. Solutions are evaluated based on innovation, feasibility, scalability, impact, presentation skills, and overall effectiveness. Participants gain hands-on experience, receive feedback from mentors and industry experts, and develop entrepreneurial and collaborative skills. Competition Format: Round 1: Online Quiz (Screening Round) Online aptitude and business quiz. Assesses analytical thinking, problem-solving abilities, and entrepreneurial knowledge. Top-performing teams qualify for the next round. Round 2: Business & Innovation Hackathon Real-world problem statement provided at the beginning of the hackathon. Teams get 18 hours to analyze the problem, develop innovative solutions, create a business or implementation strategy, and prepare the final presentation. Round 3: Final Presentation Teams present their solutions before the judging panel. Followed by a question-and-answer session. Evaluation is based on innovation, feasibility, scalability, business viability, presentation skills, problem-solving approach, and overall impact. Rules: Eligibility: Team size: 2-5 members. Open to students enrolled in any recognized university in India. Registration through Unstop before the deadline is mandatory. General Rules: Shortlisted teams must report to the venue at least 30 minutes before the event. Valid college ID cards are mandatory for verification. Professional conduct must be maintained throughout the event. Problem statement will be revealed only at the beginning of the hackathon. Teams must work only on the assigned problem statement. Internet and publicly available resources may be used unless stated otherwise. Plagiarism, malpractice, or unfair practices will result in immediate disqualification. Judges'' and organizers'' decisions will be final and binding. Organizers reserve the right to modify the schedule, rules, or format if required. Any dispute will be resolved by the Organizing Team, whose decision will be final. Submission Guidelines: Only teams shortlisted through the screening quiz can participate in the hackathon. Final presentation must be submitted in PPT or PDF format before the announced deadline. Only one final submission per team is allowed. The submitted solution must be the team''s original work. Teams must carry offline copies of the presentation in both PPT and PDF formats. Each team will receive a fixed presentation time followed by a Q&A session. All presentations and interactions must be conducted in English.', '2026-06-27T10:00:00+05:30', '2026-08-09T16:00:00+05:30', 'Online', 'online', '₹ 12,000', 'https://unstop.com/hackathons/bizzathon-hackathon-e-summit-2026-iit-ism-dhanbad-indian-institute-of-technology-indian-school-of-mines-iit-i-1704716', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704834', 'AlgoQuest 2026 – National Level Coding Competition', 'Tagline Code. Compete. Conquer. Rise Beyond Limits. About the Event Ascent Quest 2026 is the flagship national-level online coding competition organized by The Ascent Circle to bring together aspiring programmers, competitive coders, and problem solvers from across India. Designed to test logical reasoning, programming expertise, algorithmic thinking, and problem-solving abilities, the competition offers participants an opportunity to compete against the best while enhancing their coding skills. Whether you''re taking your first step into competitive programming or you''re an experienced developer looking to challenge yourself, Ascent Quest 2026 provides the perfect platform to learn, compete, and grow. The coding contest will be conducted on the official HackerRank Coding Arena, while registrations will be managed through Unstop. Event Details Event Name: Ascent Quest 2026 Organized By: The Ascent Circle Registration Platform: Unstop Coding Platform: HackerRank Coding Arena Contest Date: 5 July 2026 Unstop Registration Deadline: 5 July 2026 | 10:30 AM IST HackerRank Registration Deadline: 5 July 2026 | 10:45 AM IST (Mandatory) Contest Window: 11:00 AM &ndash; 8:00 PM IST Contest Duration: 90 Minutes Mode: Online Registration Fee: Free Participation: Individual Eligibility: Open to School Students (Class XI&ndash;XII), College Students, Freshers, Professionals, and Coding Enthusiasts across India. How to Participate Step 1 Register for Ascent Quest 2026 on Unstop. Step 2 Complete the mandatory registration on the official HackerRank Coding Arena. HackerRank Contest Link:https://www.hackerrank.com/ascent-quest Step 3 Join the official WhatsApp group shared after registration. Step 4 On 5 July 2026, log in to HackerRank anytime between 11:00 AM and 8:00 PM IST. Step 5 Start the contest whenever you''re ready. Once started, your 90-minute timer begins and cannot be paused. Competition Format Individual coding competition Hosted on HackerRank Multiple algorithmic programming challenges Beginner to intermediate difficulty level Use any programming language supported by HackerRank Automatic evaluation using visible and hidden test cases Live leaderboard during the contest Final rankings based on score and submission time Why Participate? Compete with talented programmers from across India Test your coding and problem-solving skills Solve real-world algorithmic challenges Improve DSA and competitive programming skills Gain hands-on coding contest experience Earn a Digital Certificate Win exciting prizes and recognition Strengthen your resume and coding portfolio Perks Digital Certificate of Participation Certificates of Excellence for winners Exciting prizes for top performers National-level recognition Competitive programming experience Live leaderboard and rankings Opportunity to benchmark your coding skills Who Can Participate? School Students (Class XI&ndash;XII) Diploma Students Undergraduate Students Postgraduate Students Freshers Software Developers Competitive Programmers Coding Enthusiasts Rules Individual participation only. Registration on both Unstop and HackerRank is mandatory. Participants can start the contest anytime between 11:00 AM and 8:00 PM IST. Once started, the contest timer cannot be paused. Each participant gets 90 minutes to complete the contest. Only submissions made within the allotted contest duration will be evaluated. Multiple submissions are allowed; the best valid submission before the timer ends will be considered. Plagiarism, collaboration, or any unfair means will result in immediate disqualification. The organizing team reserves the right to modify the rules if required. The decision of The Ascent Circle will be final and binding. Judging Criteria Participants will be evaluated based on: Correctness of solutions Number of problems solved Total score achieved Submission time Code efficiency Performance on hidden test cases Prerequisites Basic knowledge of any programming language Laptop or Desktop Stable internet connection Active HackerRank account Updated web browser Certificate Policy Every participant who: Registers on Unstop Completes mandatory HackerRank registration Participates in the contest Submits at least one valid solution will receive a Digital Certificate of Participation. Top-performing participants will receive Certificates of Excellence. Prize Details Exciting prizes for top performers Certificates of Excellence National-level recognition Performance-based rankings Exclusive recognition from The Ascent Circle Registration Process Register on Unstop. Complete the mandatory HackerRank registration. Join the official WhatsApp group. Log in on 5 July 2026. Start the contest anytime between 11:00 AM and 8:00 PM IST. Complete all challenges within 90 minutes. Official Coding Arena HackerRank Registration & Contest Link https://www.hackerrank.com/ascent-quest Important Notes Registration on HackerRank is mandatory to participate. Participants may start the contest at any time between 11:00 AM and 8:00 PM IST. The contest duration is 90 minutes from the moment the participant starts. Ensure your HackerRank account is active before contest day. Join early if you plan to begin at the opening time. Use a stable internet connection throughout the contest. Read all contest instructions carefully before starting. Any malpractice, plagiarism, or unfair means will result in immediate disqualification. Code. Compete. Conquer. Rise Beyond Limits.', '2026-06-27T00:00:00+05:30', '2026-07-05T17:34:15+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/algoquest-2026-national-level-coding-competition-apex-institute-of-technology-chandigarh-university-1704834', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704703', 'Grand Hack IPEC', 'Grand Hack IPEC is a 24-hour national-level offline hackathon organized by HackShastra in collaboration with Inderprastha Engineering College (IPEC), Ghaziabad. Inspired by the iconic GTA San Andreas theme, the hackathon combines innovation, technology, and creativity in an immersive experience where participants build impactful solutions to real-world challenges. The Offline Grand Finale will take place on 26&ndash;27 September 2026 at Inderprastha Engineering College, Ghaziabad. Idea submissions are currently open, while the schedule for the online shortlisting and mentorship round will be announced soon. Whether you''re a developer, designer, AI enthusiast, cybersecurity expert, or an aspiring entrepreneur, Grand Hack IPEC provides the perfect platform to showcase your skills, collaborate with like-minded innovators, receive mentorship from industry professionals, and compete for exciting prizes. Tracks: Participants can build projects under any of the following themes: Artificial Intelligence & Machine Learning Cybersecurity Web3 & Blockchain Internet of Things (IoT) AR/VR & Immersive Technologies Smart Cities & Urban Innovation Open Innovation Eligibility: Open to undergraduate and postgraduate students from all colleges and universities across India. Participants can register individually or as a team. Team size: 2&ndash;4 members. Cross-college and cross-disciplinary teams are allowed. Each participant can be a part of only one team. Competition Format: Round 1: Online Idea Submission (Open) Teams are required to submit a presentation (PPT) outlining their problem statement, proposed solution, implementation approach, technology stack, and expected impact. This round evaluates the innovation, feasibility, and clarity of each idea. Round 2: Online Shortlisting & Mentorship Shortlisted teams will be invited to participate in mentorship sessions with industry experts to refine their ideas and prepare for the final round. The dates and schedule for this round will be announced after the completion of idea submissions. Round 3: Offline Grand Finale Selected teams will compete in the 24-hour overnight hackathon on 26&ndash;27 September 2026 at Inderprastha Engineering College, Ghaziabad, where they will build working prototypes and present their solutions before an expert judging panel. Judging Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Implementation Problem Relevance User Experience & Design Scalability Presentation & Demonstration Rules: All submitted work must be original. Teams must build their projects during the hackathon. Existing projects are not permitted. Participants are encouraged to use open-source tools and APIs while complying with their respective licenses. Any form of plagiarism or unethical conduct will result in immediate disqualification. Teams must be present throughout the offline finale. The decision of the organizing team and judges will be final. Why Participate? Build innovative solutions with fellow creators. Receive mentorship from experienced professionals. Network with students, founders, recruiters, and industry experts. Win exciting prizes and exclusive goodies. Gain certificates, recognition, and potential internship and hiring opportunities. Experience one of India''s most exciting GTA San Andreas-inspired hackathons. Get ready to enter the city, build without limits, and make your mark at Grand Hack IPEC. Join Our Community For the latest updates, announcements, important notices, and hackathon-related discussions, join our official WhatsApp Community: https://chat.whatsapp.com/KYayQzqqp3HJ5XGkDIeJuH', '2026-06-26T00:00:00+05:30', '2026-09-27T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/grand-hack-ipec-hackshastra-1704703', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704216', 'Student Innovation & Product Summit (SIPS) 2026', 'Official Telegram Group:- https://t.me/+bbJ75C7KqOA5NDM9 Google Form Required to Fill:- https://docs.google.com/forms/d/1EK09lyL-bsI76Fgj-SgFmyPHSwpASrGuN-IEWdUNyqA/edit The Student Innovation & Product Summit (SIPS) 2026 is a national innovation competition organized by the Centre for Software & IT Management (CSITM), IIM Bangalore. The summit provides undergraduate students with an opportunity to showcase technology-driven solutions that address real-world challenges through functional prototypes. SIPS exists for one reason: to give your best work the stage it deserves. Bring your software project, your prototype, your idea and walk away with recognition, feedback, and a push toward what''s next. Themes: Participants may submit their project under one of the following themes: AI & Intelligent Systems Digital Trust & Infrastructure Tech for Impact Eligibility: Open to undergraduate students from recognized colleges and universities across India. Team Size: 1-3 members per team. Inter-college teams are allowed. Each team may submit only one project under one theme. Competition Structure: Round 1 &ndash; Online Submission Teams must submit a 7-slide PDF presentation describing their project. Submissions will be evaluated based on innovation, technical quality, feasibility, impact, and presentation. The top teams from each theme will advance to the next round. Round 2 &ndash; Video Pitch Shortlisted teams will submit a 4&ndash;5 minute recorded video pitch, an updated project deck, and a prototype link for evaluation. Grand Finale: Finalist teams will be invited to IIM Bangalore to present their projects through a live pitch, prototype demonstration, and jury interaction. Submission Requirements: Each team must submit: 7-slide PDF Presentation Project Title Project Abstract Theme Selection Team Details (Optional) GitHub Repository Prototype Demo Video Live Demo Link Evaluation Criteria: Projects will be assessed on: Problem Relevance Innovation & Originality Technical Excellence Prototype Readiness Feasibility Product Thinking Real-World Impact Presentation & Communication We look forward to discovering innovative solutions that have the potential to create meaningful impact through technology.', '2026-06-26T00:00:00+05:30', '2026-07-30T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/student-innovation-product-summit-sips-2026-iim-bangalore-1704216', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704081', 'Build in AI for India', 'About Build in AI for India Build in AI for India is a nationwide 7-day online AI hackathon bringing together students, developers, founders, researchers, and builders to create AI-powered solutions for real-world challenges across India. Participants build products that create meaningful impact in sectors such as healthcare, education, agriculture, governance, MSMEs, financial inclusion, regional languages, accessibility, and developer tools. India doesn''t need more AI demos&mdash;India needs AI products that solve real problems. This is where builders come together to ship them. Joining the WhatsApp Community is mandatory after registration, as all event communication takes place there. WhatsApp Community: https://chat.whatsapp.com/GFuzY2ahsa258q8hSiuV66 Eligibility Criteria Open to students, developers, startup founders, working professionals, and AI enthusiasts. Individual and team participation are allowed. Participants must be at least 16 years old. Teams can have up to 4 members. Hackathon Format Fully online, 7-day event. Build any AI-powered product, tool, agent, workflow, or application that solves a meaningful problem for India. No fixed problem statement&mdash;usefulness and impact are the primary focus. Access mentor sessions, founder talks, workshops, and partner resources throughout the event. Technical and Founder Sessions will be conducted on all seven days by partner founders and technology leaders. Tracks AI Agents. Voice AI. Indic and Regional Language AI. Healthcare. Agriculture. MSME Automation. Education. Government and Public Services. Financial Inclusion. Developer Tools. Timeline Day 1: Orientation and Kickoff. Day 2: Technical and Founder Session. Day 3: MVP + 4-Page Deck Submission. Day 4: Technical and Founder Session. Day 5: Technical and Founder Session. Day 6: Technical and Founder Session. Day 7: Final Project Submission. Sessions will be a maximum of 1.5 hours daily, with daily submissions and live judging. Submission Requirements Project demo video. Live product link or GitHub repository. Problem statement and solution overview. Presentation / Pitch Deck. Details of AI models, APIs, or tools used. Judging Criteria Usefulness and Impact for India &ndash; 40%. Execution and Working MVP &ndash; 30%. Innovation &ndash; 20%. Demo and Communication &ndash; 10%. Prizes and Recognition The Top 5 teams will share $35,000+ in credits and swags from partner platforms. API and Cloud Credits. Premium AI Tool Subscriptions. Exclusive Swags (T-shirts, stickers, and more). Incubation and Mentorship Opportunities. Hiring and Internship Opportunities. Certificates and Community Recognition. Perks & Benefits Mentorship from AI founders, operators, and industry experts. Technical workshops and product sessions. Access to partner API credits, cloud credits, and developer tools. Networking opportunities with startups, investors, and hiring partners. Internship, incubation, and collaboration opportunities for top teams. Confirmed Partners Slashy &ndash; AI Automation Partner. Keploy &ndash; API Testing Partner. Outlier &ndash; Education Partner. Alchemyst AI &ndash; Dev Tool Partner. Gnani.ai &ndash; Voice AI Partner. GenZDealZ.ai &ndash; Community Partner. Together, the partners are offering $35,000+ in credits and swags for the Top 5 winners. Frequently Asked Questions Is it free? Yes, participation is 100% free. Can beginners join? Yes, sessions and mentors will guide participants throughout the event. Can I participate individually or as a team? Both are allowed, with teams of up to 4 members. Is prior AI experience required? No, only curiosity and a willingness to build. Will participants receive a certificate? Yes, all participants will receive a certificate. Our Mission To build India''s highest-signal AI builder ecosystem by empowering builders to create impactful AI products that solve real-world problems and accelerate AI innovation across the country. Build. Ship. Solve for India. Contact Website: buildinai4india.com Email: hello@buildinai4india.com', '2026-06-25T19:00:37+05:30', '2026-07-08T23:30:47+05:30', 'Online', 'online', 'Top 5 winners (no fixed ranks) each receive: - Slashy — 3 months premium subscription - Keploy — 3 months premium subscription + swags - Outlier — fast-track submission for Top 5 - Gnani.ai — 20,000 credits (₹20,000) + swags - Alchemyst AI — $150 credits Together worth $35,000+ in credits & swags.', 'https://unstop.com/hackathons/build-in-ai-for-india-build-in-ai-for-india-1704081', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704134', 'Port Mortem 2026 | Code Resurrection Hackathon', 'About the Hackathon: Port Mortem 2026 is a 72-hour online hackathon focused on AI-assisted software migration and cross-language code porting. Participants will rewrite a real open-source project from one programming language to another while preserving its functionality, correctness, and engineering quality. Rather than simply generating code, teams are expected to demonstrate behavioral equivalence through testing, benchmarking, and documentation. The challenge emphasizes engineering discipline, software quality, and production-ready implementations. Event website: https://coderesurrection.com/2026 Stay Updated: Join the official Hackathon Raptors Discord server for all announcements, rule clarifications, repository releases, submission instructions, FAQs, and live event support. Important updates will be communicated exclusively through Discord. You can find the Discord invite on our website: https://raptors.dev. Eligibility: Open to students, professionals, researchers, and software developers worldwide. Participants from any college, university, organization, or country are welcome. Solo participation is allowed. Teams may consist of 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization and cross-disciplinary teams are allowed. Event Format: Registration Phase: Register individually or as a team. Join the official Discord server for announcements, discussions, and support. Repository Selection: At hackathon kickoff, participants will choose a repository from a curated pool of eligible open-source projects or submit an alternative repository for approval (subject to organizer guidelines). Development Phase (72 Hours): Teams will: Port the selected project into the target programming language. Preserve the original behavior and functionality. Validate correctness using the original test suite whenever possible. Benchmark the implementation. Document architectural decisions and implementation trade-offs. Submission: Each team must submit: Public GitHub repository Build instructions Working implementation Benchmark report DECISIONS.md Differential testing/fuzzing artifacts (if applicable) Demo video Tracks: Participants may choose one of the following migration tracks: C &rarr; Rust Zig &rarr; Rust TypeScript &rarr; Go Python &rarr; Rust Go &rarr; Rust JavaScript &rarr; Go or Rust C &rarr; Zig Open Pair (Any Language &rarr; Any Language) Judging Criteria: Projects will be evaluated on: Functionality & Reliability (40%) Build quality, successful execution, and test suite compatibility. Behavioral Equivalence (30%) Accuracy of the migration, differential testing, benchmarking, and performance analysis. Code Quality (20%) Idiomatic implementation, maintainability, engineering practices, and documentation. Innovation (10%) Creative solutions, architectural improvements, and valuable enhancements. Bonus points may be awarded for: Differential fuzzing Minimal unsafe code Discovering bugs in the original project Exceptional engineering documentation Rules: Team size: 1&ndash;4 members. All development must be completed during the official 72-hour hackathon period. AI coding assistants and developer tools are permitted. The submitted repository must be public at submission time. The project must build using a single documented command. Source-language runtime wrappers or proxy implementations are not permitted. Teams should preserve the original test suite wherever feasible. Any modifications must be documented. Participants must comply with all open-source licensing requirements. Plagiarism or submission of pre-existing ports may result in disqualification. Timeline: Registration Opens: 29 June 2026 Hackathon Begins: 31 July 2026 Submission Deadline: 3 August 2026 Judging: 3&ndash;13 August 2026 Winner Announcement: 14 August 2026', '2026-06-25T00:00:00+05:30', '2026-07-31T18:00:00+05:30', 'Online', 'online', '₹ 800', 'https://unstop.com/hackathons/port-mortem-2026-code-resurrection-hackathon-hackathon-raptors-1704134', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704089', 'Anakin Blitz: Second version', '​Anakin Blitz is a fast-paced virtual hackathon designed for builders who want to ship, not just plan. In just six hours, participants will use the Wire API and Anakin Universal Scraper to create something functional, creative, and real. No fluff, no filler, just focused building. ​This isn''t a multi-day marathon with endless brainstorming sessions. It''s a tight, high-energy sprint where the constraint is the feature: six hours to go from idea to working product. Whether you''re prototyping a tool, automating a workflow, or building something nobody''s tried before, Blitz is about momentum and execution. ​The details: ​When: June 28, 2026 (Sunday), 12:00 PM to 6:00 PM IST ​What you''ll build with: Wire API and Anakin Universal Scraper Where: Discord (https://discord.gg/tDTvFPE2fw) ​The stakes: ​1st Place: Sony Headphones ​2nd and 3rd Place: 2,000 Anakin credits each ​Whether you''re a solo builder or teaming up, Anakin Blitz is your chance to test your speed, creativity, and problem-solving under pressure, and walk away with something to show for it. ​Register now and get ready to build.', '2026-06-25T17:30:00+05:30', '2026-06-28T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/anakin-blitz-second-version-anakin-skywalker-pvt-ltd-1704089', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001704073', 'Ascent Quest 2026: The Ultimate Coding Challenge', 'Ascent Quest 2026 &ndash; National Level Coding Competition Think Fast. Code Smarter. Rise Higher. Ready to put your coding skills to the test? Join Ascent Quest 2026, a national-level online coding competition organized by The Ascent Circle as Episode 06 of the Summer of Skills series. Designed for aspiring programmers, competitive coders, and technology enthusiasts, this event offers an exciting opportunity to solve real coding challenges, compete with participants from across India, and earn a verified certificate while battling for exciting prizes. Whether you''re just beginning your coding journey or already experienced in competitive programming, Ascent Quest 2026 provides the perfect platform to challenge yourself, sharpen your problem-solving skills, and showcase your talent. Event Details Event: Ascent Quest 2026 Series: Summer of Skills &ndash; Episode 06 Mode: Online Platform: HackerRank Date: 5 July 2026 Time: 10:00 AM &ndash; 8:00 PM IST Participation Fee: Free Who Can Participate? School Students College Students Working Professionals Coding Enthusiasts Participants from all educational backgrounds and skill levels are welcome. Competition Format Solve coding challenges on HackerRank Multiple programming problems Difficulty Level: Beginner to Intermediate Multiple programming languages supported Live leaderboard throughout the competition Rankings based on score, accuracy, and submission time Why Participate? Compete in a national-level coding competition Solve practical programming challenges Enhance your logical thinking and coding skills Gain competitive programming experience Build your resume with a verified participation certificate Benchmark your performance against coders across India Perks & Rewards Exciting prizes for top performers Digital Certificate for every participant National-level recognition Valuable coding experience Opportunity to improve problem-solving abilities Rules Individual participation only. A stable internet connection is required. Any form of plagiarism, cheating, or unfair practices will result in immediate disqualification. The decision of the organizing team shall be final and binding. One Challenge. Countless Possibilities. Think Fast. Code Smarter. Rise Higher. Are You Ready to Take the Quest?', '2026-06-25T00:00:00+05:30', '2026-07-09T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ascent-quest-2026-the-ultimate-coding-challenge-chandigarh-university-cu-ajitgarh-punjab-1704073', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702857', 'InnoGenesis 2026 - National Level Hackathon', 'InnoGenesis 2026 is a National Level Hackathon organized by Dr. RVR NRI Institute of Technology. The event is scheduled to be held on 7&ndash;8 August 2026 and features 24 hours of non-stop innovation, bringing together talented students to build, innovate, and create impactful solutions. Event Tracks: Track 1: 24-Hour Hackathon Artificial Intelligence Machine Learning Agentic AI Robotics IoT Healthcare Sustainability Smart Energy Open Innovation Problem statements will be provided on the event day. Track 2: Prototype Exhibition & Demo Sessions Hardware Innovations AI-Based Solutions Healthcare Innovations Participants will present their own ideas and prototypes. Eligibility Criteria: Education: Open to all students pursuing any Undergraduate, Postgraduate, or Diploma program. Disciplines: Students from all branches Engineering, Management, Arts, Science, Commerce, and others are eligible Team Size: 2&ndash;4 members per team. Registration Fee: ₹500 per participant. Rewards & Benefits: Cash prizes worth up to ₹5 Lakhs. Track-wise and Domain-wise prizes will be provided.  E-Certificates. Best Startup Idea Award. Mentorship opportunities. Networking opportunities. Accommodation. Goodies & Swags.  Food and refreshments. Additional Highlights: Networking activities. Music sessions. Fun games. Why Participate? Gain hands-on experience through innovation and problem-solving. Collaborate with talented students from across the country. Build impactful and practical solutions. Earn national-level recognition. Connect with mentors, innovators, and industry professionals. Rules & Guidelines: Plagiarism of any form will lead to immediate disqualification. All team registrations must be completed through the official google form. The decisions made by the organizing committee and judges will be final and binding NOTE: Kindly register through the above link only. No Need of filling all the details through unstop... For any Queries Contact Student Co-Ordinators: Shaik Shafiya - 9550235962 J.Sai Praneeth - 8143173691 K.Bala Krishna- 7981372766 K.Lakshman - 7330930528', '2026-06-23T10:00:00+05:30', '2026-07-23T11:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innogenesis-2026-national-level-hackathon-dr-rvr-nri-institute-of-technology-deemed-to-be-university-1702857', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703899', 'FutureX', 'FutureX is a national-level innovation hackathon designed to challenge participants to envision life in the year 2040 through creativity, innovation, and strategic thinking. Participants will take on the role of futurists, innovators, and product visionaries to design practical, technology-driven solutions that address future challenges and improve everyday life. Objective: Encourage futuristic thinking and innovation. Develop creative problem-solving skills for real-world challenges. Explore the role of emerging technologies in shaping the future. Enhance strategic thinking, product ideation, and presentation skills. Promote sustainable and human-centric innovation. Eligibility: Open to all undergraduate students. Individual participation only. No technical or coding background is required. Competition Format: Single-round innovation hackathon. Participants will receive a future-focused problem statement at the start of the competition. Problem statements may cover areas such as: Schools & Education in 2040 Healthcare in 2040 Smart Cities of the Future Shopping & Retail in 2040 Workplaces & Offices in 2040 Transportation & Mobility Sustainable Living Solutions AI-Powered Everyday Experiences Participants will have 24 hours to analyze the problem statement and develop an innovative solution for the year 2040. Detailed problem statements and submission guidelines will be shared on the day of the competition. Important Dates: Registration Deadline: 6th June 2026, 8:00 PM Competition Start: 6th June 2026, 9:00 PM Submission Deadline: 7th June 2026, 9:00 PM Submission Details: Submission format: PPT or PDF (6&ndash;10 slides recommended). Participants must clearly present: Problem understanding Future vision and assumptions Proposed solution Technologies involved Product concept or service model User journey or workflow Expected impact and feasibility Optional prototype, mockup, storyboard, or wireframe may be included. Final submission guidelines will be shared on the day of the competition. Rules & Guidelines: Individual participation only. Original work is mandatory; plagiarism will result in disqualification. AI tools are permitted; however, solutions must reflect the participant''s own creativity, analysis, and strategic thinking. Late submissions will not be accepted. Participants must ensure clarity, practicality, and proper justification of their future vision and proposed solution. The decision of the organizing team will be final and binding.', '2026-06-25T00:00:00+05:30', '2026-07-05T21:00:00+05:30', 'Online', 'online', 'Opportunity to work with AI Academia', 'https://unstop.com/hackathons/futurex-ai-academia-1703899', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702474', 'Women Who Master', 'Women Who Master 2026 is a national-level all-women hackathon designed to bring together aspiring innovators, problem-solvers, and future technology leaders from across India. The hackathon provides participants with an opportunity to showcase their creativity, collaborate with peers, solve challenging problems, and compete for exciting rewards, mentorship opportunities, and national recognition. Whether you''re a beginner or an experienced builder, this platform is open to women from all academic disciplines who are ready to innovate and make an impact. Eligibility: Women students across all disciplines and academic backgrounds, including 2026 graduates, are eligible to participate. Participants must register individually during the registration phase. Rules and Guidelines: Only candidates who complete the registration form will be eligible to attempt the assessment on 25th July 2026. Post the MCQ round, shortlisted candidates will be grouped into teams of 5 members for the subsequent rounds. Team formation will be done college-wise based on participants&rsquo; accuracy and speed in the MCQ Assessment. In cases where there are insufficient participants from a particular college, teams will be formed zone-wise. Participants will not be allowed to create or modify teams. All decisions pertaining to eligibility, shortlisting, team formation, and progression in the competition will be made by Aspire For Her and Unstop, and their decision shall be final and binding.* The MCQ assessment will be available on the scheduled date and time. Participants are encouraged to attempt the assessment within this window, as access to the platform is subject to system conditions and may not remain uniformly available for all users throughout the duration. Competition Structure: Round 1: Registration: This is the first step in your Aspire For Her journey! Complete your registration by 21st July 2026 to secure your participation. Only candidates with completed registrations will be eligible to take the assessment on 25th July 2026. Round 2: Online MCQ Assessment: Participants will be required to attempt 30 MCQs in 30 minutes. The assessment will cover Artificial Intelligence (AI) and Machine Learning (ML)   You don''t need prior experience in AI/ML to participate; curiosity, creativity, and a growth mindset are all you need. Round 3: Zonal Rounds: Based on performance in the MCQ assessment, shortlisted participants will qualify for the zonal rounds. Hackathon problem statements will be shared 48 hours in advance. Teams can use this time to collaborate, research, and develop their initial solutions. On the day of the event, they will have the opportunity to reassess their approach, consult with mentors, and refine their submissions based on the feedback and guidance from the mentors.  Participants will become part of the Women Who Master community, with access to ongoing learning resources including hackathon prep materials, hackathon mini challenges, mentorship, career opportunities, and community support beyond the hackathon: https://aspireforher.com/community/women-who-master/ Zonal Round Format: Participants will be grouped into teams of 5 members. Teams will compete across different zones - North (Delhi), South (Bengaluru), East (Kolkata), and West (Mumbai). Each team will receive the problem statement at least 48 hours prior to their respective zonal round. Teams will have to curate their solution and present it before the Aspire for Her Jury during the in-person Zonal Rounds. Note: For the Zonal Round, participants will be assigned to the zone closest to their location and will be responsible for arranging their own travel. Round 4: Grand Finale: The top-performing teams from the Zonal Rounds will advance to the Grand Finale at the Logitech Headquarters in Chennai, where they will work on a new problem statement, receive mentorship from industry experts, and present their solutions before a distinguished jury. The Grand Finale will be held at the Logitech office in Chennai. A new problem statement will be shared with qualifying teams 48 hours before the event. Teams will have the opportunity to refine their solutions with guidance and mentorship from industry experts. Final presentations will be evaluated by a prestigious jury comprising leaders from Logitech and Aspire For Her (AFH). A fixed allowance will be provided to all Grand Finale participants attending the finale. Rewards and Prizes: Placement and interview opportunities with Logitech The Winning team will receive a prize worth INR 1,00,000/-* The First Runners-Up team will receive a prize worth INR 75,000/-* The Second Runners-Up team will receive a prize worth INR 50,000/-* Chance to connect with Logitech''s Talent Acquisition team and explore exciting future career opportunities. Exclusive mentorship from the Logitech leaders Participation Certificates will be awarded to all participants who appeared for the MCQ Round Merit Certificates for all winners, grand finale participants and zonal participants Fixed allowance for all Grand Finale participants Opportunity to showcase AI-powered solutions on a national stage at Logitech HQ, Chennai along with recognition by Logitech leaders Please refer to the FAQs for more details, including the T&Cs applicable to the program.', '2026-06-22T14:00:00+05:30', '2026-09-10T17:30:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/crp-women-who-master-aspire-for-her-x-logitech-1702474', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703568', 'AI Alliance Forge 2026', 'About AI Alliance Forge 2026 AI Alliance Forge 2026 is an online coding challenge hosted by the Apex Institute of Technology, Chandigarh University. The event is designed to bring together bright minds to explore and innovate within the rapidly evolving field of Artificial Intelligence. Participants will engage in a dynamic online environment, showcasing their coding prowess and problem-solving skills. This challenge offers a unique platform to contribute to the AI landscape and gain valuable experience in a collaborative setting. Themes / Problem Statements Exact problem statements will be revealed to participants during the event. The challenge focuses on: Innovation in Artificial Intelligence. Eligibility and Registration Open to participants engaging in team participation. Competition Structure No specific competition structure details were provided. Rewards and Prizes No specific prize details were provided. Why Participate? Explore emerging opportunities in Artificial Intelligence. Showcase coding and problem-solving skills. Gain hands-on experience in a collaborative online environment. Contribute to shaping the future of AI. Organized By Apex Institute of Technology, Chandigarh University. Closing Note Join AI Alliance Forge 2026 and be a part of shaping the future of AI.', '2026-06-24T16:00:00+05:30', '2026-07-31T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-alliance-forge-2026-apex-institute-of-technology-chandigarh-university-1703568', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703493', 'Heritage to Horizon: A 24hrs Ideathon', 'A 24-hour ideathon inspired by groundbreaking historical inventions created by women. Participants draw inspiration from these inventions and transform their core ideas into innovative, technology-driven solutions for today&rsquo;s challenges through creativity and innovation. Event Details: Date: 3rd&ndash;4th July 2026 Mode: Online Duration: 24 Hours Participation Size: 1&ndash;4 members Eligibility: Open to all students Timeline: 3rd July, 3:00 PM: Problem statements/tracks released and ideation begins 4th July, 1:00 PM: PPT submission deadline 4th July, 1:30 PM onwards: Final presentations and judging Themes/Problem Statement: Participants will be provided with tracks inspired by groundbreaking inventions created by women Teams must transform the core idea behind these inventions into innovative, technology-driven solutions addressing modern-day challenges. Problem statements will be released soon. Guidelines: Each team must consist of 1&ndash;4 members At least one female participant is mandatory in every team All submissions must be original and free from plagiarism', '2026-06-24T00:00:00+05:30', '2026-07-04T15:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exciting vouchers and certification courses.', 'https://unstop.com/hackathons/heritage-to-horizon-wie-week-20-guru-tegh-bahadur-institute-of-technology-gtbit-new-delhi-1703493', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703362', 'IKIGAI 2026', 'IKIGAI 2026 &ndash; National Level Hackathon IKIGAI 2026 is a premier National Level Hackathon designed to bring together innovative minds, developers, designers, and problem-solvers from across the country to collaborate, innovate, and build impactful technology-driven solutions. The event aims to foster creativity, inclusivity, and the practical application of emerging technologies while encouraging participants to solve real-world challenges through innovation and teamwork. Eligibility Guidelines Open to all Undergraduates, Postgraduates, Diploma students, and Recent graduates from recognized institutions. Participants from all academic disciplines are welcome. Inter-college teams are allowed. Inter-specialization teams are allowed. Team Size: 2&ndash;4 Members Each team must mandatorily include at least one female participant. A participant can be a member of only one team. Hackathon Tracks Participants may build projects under any of the following tracks: Track 1: SportsTech, Gaming and Robotics Track 2: AgriTech and Food Security Track 3: Cybersecurity, Digital Trust and Smart Surveillance Track 4: AI Frontiers and Smart Systems Track 5: ClimateTech, Energy and Disaster Resilience Track 6: Open Innovation Hackathon Format Round 1: Online Idea Submission & Evaluation All registered teams will participate in the online evaluation round. Teams will be required to submit their solution as per the template :Link Submissions will be evaluated based on innovation, feasibility, impact, and alignment with the selected track. Screening & Shortlisting Following the online evaluation, submissions will undergo a screening process by industry experts and mentors. Teams demonstrating strong problem-solving capabilities, innovation, and execution potential will be shortlisted for the Offline Grand Finale. Round 2: Offline Grand Finale Duration: 36 Hours Dates: 21&ndash;23 August 2026 Shortlisted teams will participate in an intensive 36-hours offline hackathon where they will design, develop, and present their solutions to the panel of judges and industry experts. Prize Pool Total Prize Pool: ₹1,03,000 Exciting cash prizes, certificates, recognition, and networking opportunities await the top-performing teams. Submission Requirements Teams must submit: Source Code Repository (GitHub or equivalent) Project Documentation Project Presentation/Pitch Deck Demo Video (if applicable) Deployed Application Link (if applicable) Judging Criteria Projects will be evaluated on: Innovation & Creativity Technical Excellence Problem Relevance Scalability & Feasibility User Experience & Design Presentation & Demonstration Overall Impact Participant Guidelines Every participant must carry: Valid College ID Card Government-Issued Photo ID Personal Laptop Laptop Charger Extension Board (Recommended) Headphones/Earphones (Recommended) Undergraduate students must carry Consent letter from their Institution Participants are responsible for bringing all hardware and accessories required for development. Rules & Regulations Teams must primarily build their solution during the hackathon duration. Open-source libraries, frameworks, APIs, and AI tools may be used. Plagiarism or submission of previously developed projects will lead to immediate disqualification. Participants must maintain professional conduct throughout the event. Any form of harassment, discrimination, or misconduct will result in immediate removal from the hackathon. Decisions made by the organizing committee and judging panel shall be final and binding. Organizers reserve the right to modify schedules, rules, or judging criteria if required due to unforeseen circumstances. By participating, teams consent to photography, videography, and promotional use of event media. Registration fees are non-refundable if your team is not shortlisted after Round 1 (Online Idea Submission & Evaluation). Why Participate? Compete with talented innovators from across the country. Gain mentorship from industry professionals. Build impactful solutions for real-world challenges. Network with developers, founders, and technology enthusiasts. Showcase your skills on a national platform. Win exciting prizes and recognition. Our Mission IKIGAI 2026 is more than just a hackathon&mdash;it is a platform where innovation meets purpose. We aim to empower the next generation of creators, thinkers, and builders by providing an environment that encourages collaboration, learning, and impactful problem-solving. Website Link: https://ikigai-csit.netlify.app WhatsApp Community(join after registration process only) https://chat.whatsapp.com/JEQE5xMKb2pIP7JErhurhK?s=cl&p=a&ilr=2 Instagram Handle: https://instagram.com/ikigai_aitr Registered participants are strongly encouraged to join the official WhatsApp community to receive important announcements, event updates, queries, schedules, and support throughout the hackathon. For complete event details, registration updates, timelines, and announcements, please visit the official IKIGAI 2026 website. For any queries or support, you can email us at: acroikigai@acropolis.in Our team will be happy to assist you. Build. Innovate. Transform.', '2026-06-24T00:00:00+05:30', '2026-08-23T00:00:00+05:30', 'Online', 'online', '₹ 1,03,000', 'https://unstop.com/hackathons/ikigai-2026-acropolis-institute-of-technology-and-research-indore-1703362', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703244', 'Agent-A-Thon NCR Marketing Challenge', 'About the Challenge The Agent-A-Thon NCR Marketing Challenge is a two-day competition by Nerds Room designed to identify and reward creators, storytellers, community builders, and growth enthusiasts who can effectively spread awareness about Agent-A-Thon NCR and the mission behind Nerds Room. Over two rounds, participants will create and publish content across platforms such as LinkedIn, Reddit, and Quora, competing to generate the highest engagement, spark meaningful conversations, and bring new people into the community. This challenge is not about who has the biggest audience&mdash;it&rsquo;s about who can create the most impact through creativity, storytelling, and authentic community engagement. Round 1: Agent-A-Thon Awareness Challenge Date: 24 June Time: 12:00 AM &ndash; 11:59 PM IST Your mission is to introduce Agent-A-Thon NCR to the world. Create content that explains: What the event is. Why people should participate. What attendees can expect. Why AI builders, students, developers, and innovators should be excited about it. Participants are encouraged to: Share the registration link. Engage with other creators. Help amplify the reach of the challenge through meaningful interactions. Round 2: Nerds Room Storytelling Challenge Date: 25 June Time: 12:00 AM &ndash; 11:59 PM IST Great communities are built through stories. In this round, participants will: Showcase the vision, impact, and opportunities created by Nerds Room. Share what makes the community unique. Highlight its initiatives. Discuss upcoming programs and hackathons. Connect the larger mission of Nerds Room with Agent-A-Thon NCR and future community-led innovation. Allowed Platforms LinkedIn Reddit Quora Submission Platform Unstop Community Group Join the challenge WhatsApp group for updates, announcements, networking, and discussions. Participants must submit the links to their published posts along with screenshots of engagement and analytics through Unstop before the submission deadline for each round. What We''re Looking For Creative storytelling High-quality content Meaningful engagement Community building efforts Organic reach and impact Collaboration with fellow participants Rewards Top 3 Winners will receive: ₹500 Cash Prize each Official Certificate of Achievement Letter of Recommendation from Nerds Room Who Should Participate? Content Creators Marketers Student Leaders Founders Builders Anyone passionate about growing communities Why Participate? Demonstrate your ability to create impact at scale. Build your personal brand. Tell compelling stories. Create meaningful engagement. Help make Agent-A-Thon NCR one of the most talked-about community-driven AI events in the region.', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agent-a-thon-ncr-marketing-challenge-vishveshwarya-group-of-institutions-vgi-greater-noida-uttar-pradesh-1703244', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695117', 'The Black-Box Protocol: Stage 01 - "System Escalation"', 'Phase 1 // Stage 01: SYSTEM ESCALATION The Black-Box Protocol &mdash; Gwalior ️ THE "48-HOUR HACKATHON MIRAGE" IS DEAD. Every single day, dozens of conventional hackathons take place across the country. Thousands of developers write rushed, unstructured code over a weekend, claim prizes, pack up, and abandon their repositories forever. This is the Mirage. High-value cloud resources are burned, sponsor APIs are temporarily activated, and developer retention drops to absolute zero. An estimate 98% of hackathon projects are abandoned immediately after the closing ceremony. The Black-Box Protocol is explicitly engineered to smash this cycle. We are introducing an interconnected, campaign-driven technical universe where products don''t die&mdash;they undergo structural incubation. Just like a cinematic universe, your progress in Stage 01 carries directly into subsequent stages, culminating in the Singularity Protocol (Stage 05) and final market scaling. Welcome to Stage 01 // "System Escalation"&mdash;the genesis node focusing on the absolute convergence of autonomous AI agents and decentralized Web3 ledger technology. Are you ready to build systems that survive? For More Updates, join WhatsApp group ️ THE 2-ROUND HYBRID ARCHITECTURE & EXECUTION MODEL To ensure an uncompromised signal-to-noise ratio, we are implementing a strict, multi-stage gatekeeper pipeline. To survive the protocol and reach the Gwalior finale, your team must clear both phases.  ROUND 01 // REGISTRATION & SYSTEM ARCHITECTURE SCREENING (ONLINE) Round 1 Timeline: June 05 &ndash; July 12, 2026 Registration Window: June 15 &ndash; July 5, 2026 System Blueprint Submission (PPT/Abstract): Open until July 5, 2026 The HiDevs Skill Test Window: July 6 &ndash; July 10, 2026 Results Declaration & Access Codes Release: July 12, 2026 Round 01 Execution Model (Step-by-Step): The Portal Onboarding (Open until July 5, 2026) Register your team (consisting of 2-4 developers) on Luma. Provide active GitHub profiles and select your core technical domains (AI orchestration, smart contracts, or UI/system architecture). The Blueprint Design (Due July 5, 2026) Shortlisted teams will gain access to the submission portal. You must submit a rigorous $6$-slide system architecture blueprint (PPT/PDF) detailing the following: Problem Statement & Proposed Use Case. Technical architecture diagram mapping the precise data flow between your autonomous AI agent and the layer-1 blockchain. Proposed sponsor tool integration and API/SDK deployment logic. The HiDevs Skill Gatekeeper (July 6 &ndash; July 10, 2026) All registered team developers must complete a mandatory 60-minute technical challenge hosted directly on the HiDevs Platform to evaluate actual coding competence, backend structuring, and deployment capability. Core Syllabus Tracks: Gen AI Products, Reliability & Monitoring, Cost & Latency Optimization. Focus Areas: System Design Questions, Scenario-Based Problem Solving, Architecture Analysis, GenAI Infrastructure Concepts, and Production Deployment Challenges. Objective: To verify each participant''s ability to design, optimize, monitor, and scale real-world GenAI applications beyond simple prototypes. Performance scores will contribute directly to the Round 01 selection process. The Core Filter (July 10 &ndash; July 11, 2026) Our technical division will audit every blueprint submission and challenge score. We evaluate: Originality Logic Validity Technical Depth System Design Quality Execution Potential Note: Plagiarized projects, low-intent AI wrappers, or technically invalid architectures will be eliminated immediately. Access Codes Release (July 12, 2026) Only the top 50-60 teams will receive physical terminal clearance codes to enter the Gwalior build arena.  ROUND 02 // THE TERMINAL LOCKDOWN (12-HOUR OFFLINE FINALE) Round 2 Date: July 26, 2026 Location: Gwalior, Madhya Pradesh (with synchronized hybrid/remote channels for global teams) Format: A strict, non-stop $12$-hour continuous physical hacking sprint. Round 02 Execution Model (Step-by-Step): Hour 00: Deployment & Gating Selected teams arrive at the Gwalior physical hub. Outstation participants gain access to designated storage and preparation areas for their equipment and belongings. Hour 01: The Network Ignition Teams connect to the central coding arena. Each team receives dedicated power access and uninterrupted high-speed connectivity. Hours 01-06: The Terminal Lockdown A continuous, high-pressure hacking window. Teams must live-code, test, and deploy their MVPs. No Slide Preparation Allowed. Teams must focus entirely on building, testing, and deployment. Mandatory Stack Integration: Projects must actively execute sponsor APIs, AI workflows, cloud infrastructure, or blockchain smart contracts. Hour 06: The System Recharge Dedicated lunch, snacks, beverages, and hydration stations will remain available to sustain active builders. Hour 08: The Submission Protocol (Final Hour) All teams must submit their final working repositories. Submissions require: GitHub Repository with verified commit history. Live Demo Link. Technical Documentation. Sponsor Integration Details. Hour 09-11: The Live-Execution Jury No dry pitching. Evaluation is based strictly on live execution. Teams must demonstrate a functional MVP, autonomous AI workflows, smart contract executions, and real-time transaction logs.  THE VALUE MATRIX (WHAT IS IN THE BOX?) Incentive Pool: Up to 50K+ in developer bounty pools, cash prizes, sponsor rewards, and hardware incentives. Continuous Incubation: Access to a 6-12 month post-event support pipeline connecting viable projects directly with mentors, accelerators, investors, and ecosystem partners. Expert Mentorship: Real-time architecture reviews, technical guidance, and execution-focused triage support from industry specialists during the live build.  REGISTRATION COMPLIANCE RULES Repository Integrity: All code must be initialized and systematically committed during active round windows. Pre-existing, copy-pasted, or white-labeled projects will trigger immediate disqualification. Mandatory Convergence: Projects must functionalize both domains. An AI wrapper without Web3 trust, or a Web3 contract without autonomous AI capabilities, will not pass Round 01. Strict Gatekeeping: Registrations are limited and subject to manual review. Ensure all submitted team details and profile links are completely accurate. Stop building throwaway apps. Start building persistent systems. Welcome to the Black-Box Protocol.   Presented by TECHhelp4U&mdash;Where Creativity Meets Talent, Founder Vedansh Goyal Central India''s ultimate launchpad where code meets culture and students evolve into creators. By fueling experiential learning and real-world challenges, we empower the next generation of tech disruptors to architect the future.', '2026-06-06T00:00:00+05:30', '2026-07-25T22:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/the-black-box-protocol-stage-01-samrat-ashok-technological-institute-sati-vidisha-1695117', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703222', 'Code. Innovate. Impact', 'What You''ll Gain: Certificates for Participants & Winners Knowledge Enhancement Networking with Like-Minded Students Skill Development & Recognition Opportunity to Join the CodeForge Community Event Highlights: Multiple-choice quiz format Beginner-friendly Open to all students Time-based competition Fair evaluation process', '2026-06-23T00:00:00+05:30', '2026-08-09T23:59:00+05:30', 'Online', 'online', 'Certificate of Excellence, Featured on CodeForge''s LinkedIn & Instagram, Winner Badge, Early Access to Future CodeForge Events', 'https://unstop.com/hackathons/code-innovate-impact-iit-bombay-1703222', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703153', 'The Closer Challenge - Pitch. Convince. Win.', 'Think you can sell ice to a penguin? Welcome to The Closer Challenge&trade;, a real-world sales simulation designed to test your communication, negotiation, persuasion, and problem-solving skills. Participants will be assigned different products and customer personas. Your mission is simple: understand the customer''s needs, overcome objections, negotiate effectively, and close the sale. This isn''t about memorizing scripts. It''s about thinking on your feet, building trust, and creating value through powerful conversations. What You''ll Experience: Live Sales Simulations Customer Handling & Objection Management Negotiation & Persuasion Challenges Real-Time Sales Targets Leaderboards & Performance Rankings Challenge Format: Participants will pitch products to multiple customers. Each successful sale contributes toward their sales score. Different customers will have different requirements, objections, and budgets. Participants must use their convincing and negotiation skills to achieve sales targets. The Goal: Reach the required sales threshold and prove that you can close deals like a professional. Rewards: Internship Opportunities Full-Time Job Offers (for exceptional performers) Certificate of Achievement Direct Exposure to Industry Professionals', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/the-closer-challenge-pitch-convince-win-yai-infraventure-1703153', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702893', 'Agentic AI Hackahton', 'This is a build-focused AI hackathon designed for makers, developers, students, and professionals who want to create and launch a real AI-powered product within a weekend. What You''ll Build: Over two intensive days, participants will transform an idea into a working AI application by: Discovering and validating a real-world problem. Designing the product and technical workflow. Building AI-powered features using modern tools and frameworks. Integrating APIs, agents, and external services. Testing, refining, and presenting a functional solution. The challenge is centered around Agentic AI Systems that can: Reason and make decisions. Use tools and external resources. Automate workflows and complete tasks. Operate with minimal human intervention. By the end of the Buildathon, you''ll have a working project that can be showcased in your portfolio, demonstrated during interviews, or further developed into a real product. Who Can Participate? Individuals and teams are welcome. Recommended team size: Up to 2 members. Beginners and experienced builders can participate. Participants may use AI tools, APIs, SDKs, and open-source frameworks. Project Requirements: Every team must: Build their solution during the event duration. Maintain clear documentation of their development process. Explain the problem statement, approach, architecture, and implementation. Submit a functional prototype or live product demonstration. Submission Checklist: To complete your submission, provide: A live demo or recorded product walkthrough. Source code repository (GitHub or equivalent). Brief project overview and architecture explanation. Details about the tools, models, and technologies used. Rules & Judging Criteria: Event Rules: Pre-built end-to-end projects are not permitted. Starter templates, boilerplates, and open-source libraries are allowed. Any form of plagiarism or unauthorized copying will result in immediate disqualification. Teams must disclose the use of AI-generated code, content, or assets. Only fully functional submissions will be considered for evaluation. All entries must be submitted before the official deadline. Evaluation Areas: Projects will be assessed based on: Innovation and originality. Problem-solving impact. Technical implementation. Product usability and user experience. Quality of the AI agent workflow. Completeness of the final solution. Build fast, experiment boldly, and turn your idea into a real AI product.', '2026-06-23T00:00:00+05:30', '2026-07-18T14:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agentic-ai-hackahton-gradient-1702893', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701580', 'TNX Codathon', 'Overview: TNX Codathon 2K26 is a 24-hour national-level offline hackathon organized by TechNeekX, bringing together developers, innovators, designers, AI enthusiasts, and startup builders from across India to solve real-world challenges through technology and innovation. Participants will collaborate in teams to build impactful solutions across multiple domains while receiving mentorship, technical guidance, networking opportunities, and evaluation support from industry experts and experienced professionals. Eligibility: Open to undergraduate, postgraduate, and diploma students from recognized institutions. Students from all academic disciplines are eligible. Inter-college teams are allowed. Cross-specialization teams are allowed. Participants must carry a valid student ID during the event. Team Size: Minimum: 1 Members Maximum: 5 Members Solo participation is not permitted.Join Participation Group: click here to join TRACKS & PPT TEMPLATE : Click here to download Hackathon Tracks: Participants may choose from the following tracks: Artificial Intelligence & Machine Learning Healthcare Technology FinTech & Smart Automation Sustainability & Green Innovation Smart City Solutions Cybersecurity Web & Mobile Applications Open Innovation Competition Format: Round 1: Shortlisting & PPT Round Applications may undergo screening based on team profile, idea quality, innovation potential, and technical feasibility. Round 2 : Shortlisting & Online Hackathon Applications may undergo screening based on team profile, idea quality, innovation potential, and technical feasibility. Final Round : Offline Hackathon Selected teams will participate in a 24-hour offline hackathon where they will build and present their solutions. Activities include: Opening Ceremony Team Workspace Allocation Mentorship Sessions Mid-Evaluation Checkpoints Technical Reviews Final Submission Live Demonstrations Jury Evaluation Closing Ceremony & Results Judging Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Implementation Problem-Solution Fit Scalability User Experience Business & Social Impact Presentation & Demonstration Quality Rules: All submitted work must be developed during the hackathon period. Plagiarism will result in immediate disqualification. Teams must comply with event guidelines and code of conduct. Open-source libraries and APIs may be used where permitted. Participants are responsible for their own devices and equipment. Any form of misconduct, cheating, or unethical behavior will lead to disqualification. Judges'' decisions will be final and binding. Organizers reserve the right to modify schedules or rules if required. Participants must submit all required deliverables before the deadline. Team members must remain registered with their original team throughout the competition. What Participants Get: National-Level Exposure Industry Mentorship Networking Opportunities Certificates of Participation Exciting Prizes & Rewards Internship Opportunities Recognition Across the Innovation Ecosystem Access to the TechNeekX Community Event Duration: 24-Hour Offline Hackathon', '2026-06-23T00:00:00+05:30', '2026-08-09T17:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/tnx-codathon-techneekx-1701580', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703194', 'The Cypher Trail', 'An immersive, Among Us themed technical challenge where participants step into the role of crewmates aboard a sabotaged spaceship. Through missions involving Artificial Intelligence, Cybersecurity, Programming, Networking, and Digital Investigation, they must solve challenges, uncover hidden clues, identify the impostor, and restore the ship&rsquo;s systems.  Event Details: Date: 1st July, 2026 Time: 4PM-6PM Duration: 2hrs Mode: Online Team size: Individual Number of rounds: 5 Eligibility: Open to all  Coding Languages: Python, Java, C/C++ Laptops are mandatory. Rules: No AI, No Cheating: Use of AI tools or help from others is prohibited. Level by Level: You must solve each level to move to the next. Race Against Time: The fastest participant to finish wins.', '2026-06-23T00:00:00+05:30', '2026-06-30T20:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exciting vouchers and certification courses.', 'https://unstop.com/hackathons/the-cipher-trail-wie-week-20-institute-of-electrical-and-electronics-engineers-gtbit-1703194', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001703189', 'Creative Lens', 'A creative advertising challenge where participants transform an already existing product with an innovative technological feature and present it through either an advertisement poster or a promotional video, showcasing creativity, storytelling, and marketing skills. Event Details: Date: 2nd July 2026 Time: 12:00 PM &ndash; 4:00 PM Duration: 4 Hours Mode: Online Participation Size: Individual Participation Eligibility: Open to All Students Domains: Women&rsquo;s Health & FemTech Safety & Personal Security Smart Wearables Career & Productivity Tech Lifestyle Innovation Guidelines: The submitted video must be 30&ndash;60 seconds in duration. Accepted Formats: Video &ndash; MP4 | Poster &ndash; PDF, PNG, JPG/JPEG. AI-generated videos or AI-generated artwork are strictly prohibited and will lead to immediate disqualification. Ensure that the submission is clear, original, and adheres to the event theme and rules. Any submission found to violate the guidelines may be rejected at the discretion of the organizing team.', '2026-06-23T00:00:00+05:30', '2026-07-01T20:00:00+05:30', 'Online', 'online', 'Win exciting swags including curated goodies, exciting vouchers and certification courses.', 'https://unstop.com/hackathons/creative-lens-wie-week-20-guru-tegh-bahadur-institute-of-technology-gtbit-new-delhi-1703189', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702966', 'BrandVerse 2026: India''s Startup Branding & AI Innovation Challenge', 'About the Challenge: BrandVerse 2026 is a national-level innovation hackathon designed to bring together creative minds, problem solvers, aspiring entrepreneurs, developers, designers, marketers, and technology enthusiasts from across India. The challenge aims to encourage participants to develop innovative solutions that address real-world business, branding, technology, sustainability, education, and artificial intelligence challenges. Participants will have the opportunity to showcase their creativity, technical expertise, strategic thinking, and entrepreneurial mindset while competing with talented students from leading institutions. This competition provides a platform for students to gain practical experience, enhance their problem-solving abilities, collaborate with like-minded peers, and present impactful ideas that can create meaningful change. Themes: Participants can choose to build solutions in any of the following domains: Artificial Intelligence & Machine Learning AI-powered assistants Computer vision applications Natural language processing solutions Predictive analytics systems Automation tools Branding & Marketing Innovation Customer engagement platforms Digital branding solutions Marketing automation tools Community growth platforms Creator economy solutions Startup & Business Solutions Business process automation CRM and productivity systems SaaS products Customer acquisition solutions Sales intelligence tools Education Technology Learning management systems Student productivity applications Skill development platforms Career guidance solutions Sustainability & Social Impact Environmental solutions Waste management innovations Renewable energy technologies Community development initiatives Open Innovation Participants are free to submit innovative projects outside the listed categories if they solve a significant real-world problem. Eligibility: Open to all undergraduate and postgraduate students across India. Students from any stream, specialization, or academic discipline may participate. Individual participation is allowed. Team participation is allowed. Team size: 1 to 4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. Competition Format: Round 1: Idea Submission Participants must submit: Problem Statement Proposed Solution Unique Value Proposition Expected Impact Brief Implementation Plan Shortlisted teams will move to the next round. Round 2: Prototype Development Qualified participants must develop and submit: Working Prototype or MVP Project Presentation Deck Solution Documentation Demo Video (Optional) Round 3: Final Evaluation Finalists will present their projects before the evaluation panel. The presentation should include: Problem Identification Solution Overview Technical Architecture Business Impact Future Scope Live Demonstration (if applicable) Evaluation Criteria: Projects will be evaluated based on: Criteria Weightage Innovation & Creativity 25% Problem Solving Ability 25% Technical Implementation 20% Business & Social Impact 15% Presentation & Communication 15% Submission Guidelines: Participants must ensure that: All submitted work is original. Solutions should address a clearly defined problem. Projects must include adequate documentation. Teams should clearly explain the practical impact of their solution. Submissions must be completed before the deadline. Participants may use any technology stack, programming language, framework, or design tool. Rewards & Recognition: Winner: Certificate of Excellence Winner Recognition Runner-Up: Certificate of Achievement Runner-Up Recognition All Participants: Digital Participation Certificate Networking Opportunities Industry Exposure Skill Development Experience Important Dates: Participants are advised to complete registration before the deadline and regularly check the platform for updates regarding submissions, evaluations, and announcements. Rules & Regulations: The competition is open only to currently enrolled students. Participants may register individually or as a team. Team size cannot exceed four members. Inter-college and inter-specialization teams are permitted. All submissions must be original and created by the participants. Any form of plagiarism will result in immediate disqualification. Multiple submissions of the same project are not allowed. Organizers reserve the right to verify participant information. The decision of the evaluation panel shall be final and binding. Organizers reserve the right to modify schedules, timelines, and evaluation procedures if required. Why Participate? Showcase your skills on a national platform Build innovative solutions for real-world problems Gain recognition among peers and industry professionals Strengthen your portfolio and resume Collaborate with talented students from across India Enhance your problem-solving, technical, and entrepreneurial abilities Join BrandVerse 2026 and transform your ideas into impactful innovations!', '2026-06-23T00:00:00+05:30', '2026-07-07T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/brandverse-2026-indias-startup-branding-ai-innovation-challenge-printila-services-private-limited-1702966', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702501', 'Nexus: Where Prompts Become Products', 'Promptathon 2026 is a national-level AI Prompt Engineering Challenge where participants transform innovative ideas into AI-generated prototypes using the power of prompt engineering. Participants are required to submit both the prompt(s) used and the AI-generated prototype image(s) showcasing their solution. The challenge evaluates creativity, prompt design, problem-solving ability, and the effectiveness of AI-generated outputs. Whether you''re building a futuristic product, solving a real-world problem, or designing the next big innovation, Promptathon provides the perfect platform to demonstrate your AI creativity and technical thinking. Submission Requirements AI-generated Prototype Image(s) -- Minimum 3 images of the prototypeComplete Prompt(s) Used to Generate the PrototypeBrief Description of the Idea  Judging Criteria Prompt Quality & Creativity Innovation & Originality Prototype Design & Visual Impact Problem-Solving Approach Feasibility & Practical Application Prompt Today. Innovate Tomorrow.', '2026-06-22T00:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate of Recognition for top 3 submission', 'https://unstop.com/hackathons/nexus-where-prompts-become-products-techverse-solutions-1702501', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702687', 'Forge 6', 'Date: 18 August 2026Venue: NMG Technologies, GurugramFormat: Solo or Team of up to 3 The next wave of AI will not be built for chatbots. It will be built for factories. Forge 6 is an Industrial AI Hackathon organized by NMG Labs in association with Maruti Suzuki, bringing together students, engineers, AI builders, and innovators to solve real manufacturing challenges using Artificial Intelligence. Manufacturing, automotive, supply chain, quality control, procurement, logistics, and industrial operations are undergoing one of the biggest technology transformations in decades. Organizations are actively searching for AI systems that can reduce defects, improve quality, optimize inventory, automate compliance, predict disruptions, and increase productivity on the shopfloor. This is your opportunity to build those systems. Participants will develop working AI prototypes inspired by high-impact industrial use cases prioritized by the manufacturing sector. The best solutions will demonstrate how AI can create measurable business value across automotive and industrial operations. Challenge Tracks: Choose from multiple industrial AI problem statements, including: AI-powered Defect Detection & Quality Inspection Quality Documentation Co-Pilots Cost Estimation & Localization Intelligence Workplace Safety & Vision Analytics Inventory & Supply Chain Optimization Supplier Risk Prediction Sustainability & Carbon Intelligence Agentic AI for Manufacturing Operations Technology Areas: Computer Vision Machine Learning Generative AI Agentic AI Systems Predictive Analytics Industrial Automation RAG & Knowledge Systems Supply Chain Intelligence Why Forge 6? Build AI solutions inspired by real manufacturing challenges Gain exposure to industrial and automotive workflows Learn how AI is transforming factory operations Showcase your work to industry leaders and engineering professionals Build a portfolio project with real-world business relevance Earn recognition, prizes, and career opportunities through NMG Labs Judging Criteria: Working Prototype Industrial Impact AI & Technical Excellence Real-World Applicability Production Readiness Presentation & Storytelling Eligibility: Open to students and recent graduates from Engineering, Computer Science, Artificial Intelligence, Data Science, Mechanical, Production, Manufacturing, Mechatronics, Industrial Engineering, and related disciplines. Team Size: Individual Participation Teams of up to 3 Members Theme: Participants will receive challenge statements and datasets on sprint day and will have approximately 6&ndash;7 hours to build and demonstrate their solution. The future of manufacturing will be powered by AI. Forge 6 is where builders take the first step toward creating it.', '2026-06-22T00:00:00+05:30', '2026-08-15T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-6-nmg-technologies-1702687', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702556', 'Forge 3', 'Forge 3 is India''s first AI-powered creative production sprint designed for creators, designers, filmmakers, motion artists, social media creators, advertisers, and digital storytellers. While traditional hackathons focus on building software, Forge 3 challenges participants to build creative experiences. In just six hours, you''ll operate a complete creative studio from your laptop, using cutting-edge AI tools to produce a portfolio-grade creative asset. Participants can compete individually or in teams of up to three members and choose from seven challenge tracks, including AI Brand Films, UI/UX Prototyping, Social Media Campaigns, Ad Creative Production, VFX Innovation, AI Brand Avatars, and Integrated Multi-Channel Campaigns. The exact client brief will be revealed on sprint day. Your mission is to transform that brief into a finished creative deliverable using modern AI tools such as Higgsfield, Google Flow (Veo + Nano Banana), Figma, Runway, Midjourney, ElevenLabs, Suno, Adobe Firefly, Meta Edits, and more. What You''ll Build: Cinematic AI-generated brand films Clickable product prototypes Social media campaigns High-converting ad creatives Advanced VFX shots AI spokesperson avatars Integrated cross-platform creative campaigns Judging Criteria: Creativity & Originality (25%) Craft & Technical Execution (20%) Storytelling & Communication (15%) Effective Use of AI Tools (15%) Brand Fit & Brief Relevance (15%) Presentation & Process (10%) Why Participate? Create a real portfolio-worthy project in a single day Learn industry-leading creative AI workflows Network with creators, mentors, and industry professionals Compete for cash prizes, certificates, and exclusive opportunities Earn consideration for creative roles and internships at NMG Eligibility: Open to students and recent graduates from design, animation, VFX, advertising, visual communication, media, creative technology, and related disciplines. Exceptional creators from other backgrounds are also encouraged to apply. Team Size: Solo Participation Theme: The official creative brief and assets will be disclosed at the start of the sprint. Whether you''re a designer, filmmaker, editor, motion artist, social creator, or AI-powered creative builder, Forge 3 is your opportunity to prove that creativity, speed, and AI mastery can produce extraordinary work.', '2026-06-22T00:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-3-nmg-technologies-1702556', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702568', 'U-19 AI Olympics', 'An intensive, project-driven development tournament where elite incoming students compete to build, deploy, and launch production-ready products from scratch. The competition is designed and judged by Manas Kumar Verma, ranked among the Top 15 Programmers in India and a Meta Hacker Cup Winner.The Challenge Blueprint: Over the course of the competition, participants must rapidly architect, code, and deploy 6+ live, real-world projects to climb the leaderboard. The submission portfolio includes: Live News Tracker &ndash; Real-time data streaming and monitoring. Newspaper-Style Web App &ndash; Dynamic content layouts and publishing architecture. Character-Themed Animated UI &ndash; Advanced front-end motion graphics and styling. Document Explorer &ndash; Complex data filtering and search systems. E-Commerce Landing Page &ndash; High-conversion user experience and responsive design. Interactive Browser Piano &ndash; Audio API integration and real-time event handling. Platform: Unstop Timeline & Intensity: Duration: 2 Days of high-intensity, non-stop building and deployment sprints. Eligibility & Rules: Target Audience: Open to students who have successfully passed the 12th grade, including gap-year students (&ldquo;droppers&rdquo;), who are entering engineering colleges. Prerequisites: Zero prior coding experience is required&mdash;your drive to learn, build, and adapt under pressure is what matters. The Golden Rule: This is a pure building competition. Active participation, daily milestone submissions, and completely functional, live-deployed URLs are strictly required to remain in the running.', '2026-06-10T18:11:26+05:30', '2026-08-30T10:44:29+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/u-19-ai-olympics-algo-university-1702568', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695290', 'Hack Better Than Me (HBTM)', 'Guidelines Event Name: hack better than me (hbtm) &mdash; IABTM x IIIT Pune Theme: Agentic AI for Human Potential Format: Two-Round Competition &mdash; Online Qualifier followed by In-Person 24-Hour Hackathon Final Round Date: 1&ndash;2 August 2026 Venue: IIIT Pune Campus, Pune, Maharashtra Eligibility Open to all undergraduate and postgraduate students currently enrolled in any recognised college or university across India. Participants must register through the Unstop platform. No minimum GPA or prior AI/ML experience required. A strong interest in agentic AI and problem-solving is sufficient. Teams must have at least one member with basic proficiency in programming and system design. All participants must carry a valid college ID card for verification during the final round. Participants from non-technical backgrounds (design, management, humanities) are welcome as long as the team collectively covers both technical and user-centric aspects. Team Size Minimum 2 members and maximum 4 members per team. Teams must be exactly 2 or 4 members. Solo participation is not allowed. 3-member teams are also not permitted. One member must be designated as the Team Leader at the time of registration. Inter-College Teams Students from different colleges may participate. Inter-Specialization Teams Allowed and strongly encouraged. Teams may consist of participants from different academic specializations &mdash; engineering, design, management, sciences, arts, or any other discipline. Registration Requirements To complete your registration, every team must fulfil all three of the following steps: Step 1 &mdash; Register on Unstop Fill in the registration form on Unstop with your full details. The Problem Statement email will be sent to the Team Leader. Step 2 &mdash; Create an IABTM Account Every team member must create an account on the IABTM platform at: iambetterthanme.com Note down your IABTM username. All team members must share their IABTM usernames in the registration form. Step 3 &mdash; Upload an Intro Video on LinkedIn Each team must upload a short introduction video on LinkedIn, tag all three pages below, and share the LinkedIn post URL in the registration form. Pages to tag: IABTM &mdash; https://www.linkedin.com/company/iabtm-i-am-better-than-me/m/company/iabtm-i-am-better-than-me IIIT Pune &mdash;  https://www.linkedin.com/school/iiitpune/ Your video must cover: A introduction of yourself and your team. Clearly mention who the Team Leader is. Projects or achievements you have accomplished so far. Why you want to participate in hack better than me (HBTM). Share the LinkedIn post URL in the registration form after uploading. Round Details Round 1 &mdash; Online Qualifier Registrations close on 11th July 2026. After registrations close, the Problem Statement will be sent via email to the Team Leader. Teams will have 2&ndash;3 days to work on the problem and submit their solution. Submission format: A PowerPoint presentation (mandatory) and an optional 2&ndash;3 minute video walkthrough. Full submission instructions will be shared in the same email as the Problem Statement. Shortlisting for Round 2 will be based on innovation, feasibility, clarity of vision, and alignment with the theme. Round 2 &mdash; In-Person 24-Hour Hackathon Shortlisted teams must appear physically at IIIT Pune on 1&ndash;2 August 2026. Teams will work on building a working prototype during a continuous 24-hour development sprint. Food and all necessary arrangements will be provided by the organisers. Final evaluation will be based on project demonstrations and presentations to the judging panel. Problem Statements Number of Problem Statements: 1 The Problem Statement will be shared with all registered teams via email after registrations close on 16th July 2026. The email will be sent to the Team Leader. Teams will have 2&ndash;3 days to submit their solution after receiving the Problem Statement. Duration of the Competition Round 1: 2&ndash;3 days online submission window after the PS email is sent. Round 2: 24 hours of continuous development at IIIT Pune, conducted over two days (1&ndash;2 August 2026). Submission Requirements Round 1 PowerPoint presentation covering: problem understanding, proposed architecture, technology stack, user journey, personalisation logic, feasibility, and expected outcomes. IABTM usernames of all team members must be included in the submission. Optional: A 2&ndash;3 minute video walkthrough of the proposed solution. Round 2 (Offline at IIIT PUNE) Working prototype or live demo. 3&ndash;5 minute demo presentation to the judging panel. Explanation of system architecture and agent design decisions. Sample user journey showcasing personalisation logic. Code repository (GitHub or similar). Evaluation Criteria Round 1 &mdash; Online Qualifier Clarity of Problem Understanding &ndash; 20% Innovation in Proposed Solution &ndash; 25% Technical Feasibility &ndash; 20% Presentation and Communication &ndash; 20% Alignment with Theme &ndash; 15% Round 2 &mdash; On-Campus Final at IIIT PUNE Innovation and Creativity &ndash; 25% Technical Execution and Completeness &ndash; 25% User Experience and Design &ndash; 20% Scalability and Growth Potential &ndash; 15% Alignment with Challenge Objective and Theme &ndash; 15% Registration Registrations will be conducted through Unstop. The registration form will collect: team details, IABTM usernames of all members, designation of Team Leader, email addresses of all members, and the LinkedIn post URL of the intro video. Prizes The prize pool includes cash prizes for the top 3 finalists: 1st Place: Cash Prize 2nd Place: Cash Prize 3rd Place: Cash Prize Goodies for all participants and finalists: Stickers Keychains Tote Bags Additional Opportunities Outstanding projects may be considered for future platform integration. Internship and collaboration opportunities may be offered to exceptional teams. Rules Participants must register in teams of 2 or 4 members only. Solo entries and 3-member teams are not permitted. One team member must be designated as the Team Leader at the time of registration. All teams must submit their project before the deadline communicated in the Problem Statement email. Teams must present their solution during the final judging session at IIIT Pune. Participants must adhere to the event''s Code of Conduct throughout the hackathon. All finalists must review and sign the Hackathon Participant Agreement before the event begins. Projects submitted during the hackathon must be original work created by the participating team. Participants agree that project repositories and intellectual property developed during the hackathon may be shared with the organisers as specified in the Participant Agreement. Organisers reserve the right to use submitted work for evaluation, further development, demonstration, or integration purposes. Any violation of event rules, misconduct, plagiarism, unfair practices, or failure to comply with organiser instructions may result in disqualification. The decision of the judges and organisers shall be final and binding in all matters related to the competition. Organisers reserve the right to modify event schedules, rules, judging criteria, or participation requirements if necessary.', '2026-06-22T17:00:00+05:30', '2026-07-15T23:55:50+05:30', 'Online', 'online', 'Cash prize (Amount Disclose soon), Certificate, Goodies (stickers, keychains, tote bags)', 'https://unstop.com/hackathons/hack-better-than-me-hbtm-indian-institute-of-information-technology-iiit-pune-1695290', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702397', 'X-Play Aaruush ''26', 'Introduction: X-Play is a national-level game development challenge that brings together creativity, innovation, and technical expertise to transform original ideas into engaging gaming experiences. Participants will progress through stages of ideation and prototype development, showcasing their ability to design, develop, and deliver compelling interactive worlds. Objectives: Encourage the development of innovative and impactful gaming experiences. Provide participants with practical exposure to the game development lifecycle. Promote creativity in game design, storytelling, mechanics, and user engagement. Foster problem-solving, technical proficiency, and interdisciplinary collaboration. Create a platform for aspiring developers to showcase their skills before industry professionals and peers.', '2026-06-22T00:00:00+05:30', '2026-07-15T23:59:00+05:30', 'Online', 'online', '₹ 35,000', 'https://unstop.com/hackathons/x-play-aaruush-26-srm-institute-of-science-and-technology-kattankulathur-chennai-1702397', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702266', 'Open Source Hackathon', 'The Open Source Hackathon 2026 is a nationwide coding challenge designed to encourage developers to contribute to real-world open-source projects, collaborate with fellow innovators, and enhance their practical development skills. Powered by Unstop and supported by students and communities from IITs and NITs, this hackathon provides participants with an opportunity to work on live repositories, solve meaningful issues, and compete for exciting rewards. Eligibility: Open to all students and professionals across India. Participants must have basic knowledge of Git, GitHub, and software development workflows. Individual participation only. Participants must have an active GitHub account. Multiple registrations from the same participant are not permitted. Hackathon Format Round 1: Screening Round All registered participants will undergo an initial screening process. Participants may be evaluated based on their GitHub profile, technical background, and responses submitted during registration. Selected participants will proceed to the main hackathon round. Round 2: Open Source Contribution Round Shortlisted participants will receive repository access details through their registered email addresses. Participants will be assigned repositories and issues/tasks. They must work on the assigned tasks and submit their contributions through GitHub Pull Requests. Contributions must follow standard GitHub practices and repository guidelines. Successfully completed changes should be merged into the repository after review. Evaluation Criteria: Participants will be evaluated based on: Quality of code and implementation Innovation and problem-solving approach Impact of contribution Documentation quality Code readability and maintainability Successful merging of Pull Requests Adherence to project guidelines Rewards & Recognition Prize Pool: ₹20,000 1st Rank: ₹10,000 2nd Rank: ₹6,000 3rd Rank: ₹4,000 In addition: Participation Certificates will be provided to eligible participants. Certificates of Excellence will be awarded to top performers. Outstanding contributors may receive recognition for their open-source contributions. Rules: All submissions must be original work. Participants must only work on the repositories and tasks assigned to them. Use of plagiarized code will result in immediate disqualification. Participants must maintain professional conduct throughout the event. Any attempt to manipulate repository history, submissions, or evaluation criteria may lead to disqualification. Decisions made by the organizing team and judges will be final and binding. Late submissions will not be considered unless officially communicated. Participants are responsible for maintaining the confidentiality of any repository access provided. Submission Process: Complete registration. Qualify through the screening round. Receive repository details via email. Fork/clone the assigned repository. Implement the required changes. Create and submit Pull Requests. Wait for review and merge confirmation. Final evaluation and winner announcement. Complete hackathon is on Unstop. Why Participate? Gain practical open-source experience. Strengthen your GitHub profile. Learn industry-standard collaboration workflows. Compete for a ₹20,000 prize pool. Receive certificates and recognition. Connect with a community of developers from across India. Build. Collaborate. Contribute. Create Impact.', '2026-06-21T00:00:00+05:30', '2026-07-18T11:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/open-source-hackathon-iit-bombay-1702266', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701779', 'Hacknite: 12 Hour Hackathon', 'Eligibility Guidelines Hacknite is open to all undergraduate, postgraduate, diploma students, and recent graduates from any recognized institution. Participants from all disciplines are welcome. Individual registrations are allowed. Team size: 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. A participant can be a member of only one team. Tracks: Participants can build projects under any one of the following tracks: Artificial Intelligence & Machine Learning Open Innovation Cyber Security Internet of Things (IoT) Blockchain & Web3 Gaming & XR Communication & Announcements All important announcements, updates, result notifications, schedule changes, and event-related communication will be shared through the official WhatsApp group. Official WhatsApp Group:https://chat.whatsapp.com/KcPvJQpSPBT1NJaTVgiNmJ Participants are strongly encouraged to join the group to stay informed about the latest updates. Problem Statements Participants may choose from the official problem statements released before the event or build an open innovation project aligned with one of the hackathon tracks. Teams are encouraged to solve real-world problems with practical and scalable solutions. Selection Process Hacknite &ndash; Code Royale 2026 follows a two-phase registration and selection process. These phases are independent registration opportunities and not elimination rounds. Teams may participate only once during the event. Phase 1 (Expected) Registration Window: 21 June 2026 &ndash; 05 July 2026 Eligibility: Open to all eligible students. Team Size Minimum: 1 Members Maximum: 4 Members Expected Result Declaration: 06 July 2026 &ndash; 10 July 2026 Phase 2 (Expected) Registration Window: 11 July 2026 &ndash; 22 July 2026 Purpose Phase 2 is intended for new teams who were unable to register during Phase 1. It serves as an additional registration opportunity and is not a continuation or elimination round of Phase 1. Important Rule Teams that have already registered or participated in Phase 1 will not be eligible to register in Phase 2. Any duplicate registrations may be disqualified. Expected Result Declaration: 23 July 2026 &ndash; 25 July 2026 Final Shortlisting (Expected) Based on the evaluation process across both phases, approximately 250&ndash;300 participants are expected to be shortlisted for the Offline Grand Finale. Submission: Teams must submit by Google Form: Source Code Repository (GitHub or equivalent) Project Demo Brief Documentation Project Deployed Link Judging Criteria: Projects will be evaluated on: Innovation & Creativity Technical Implementation Problem Relevance Scalability & Feasibility Presentation & Demo Overall Impact Mentorship Industry mentors will be available throughout the hackathon to guide participants on technical challenges, product development, and pitching. Rules Every participant must carry a valid college ID and government-issued ID for verification. Participants must report to the venue before the reporting time. Teams must develop their solution primarily during the hackathon duration. Pre-existing libraries, frameworks, and open-source tools may be used; however, the core project must be built during the event. Plagiarism or submission of previously developed projects will lead to immediate disqualification. AI tools are permitted unless explicitly restricted in a specific problem statement. Teams are responsible for bringing their own laptops, chargers, and other required equipment. Internet access and basic infrastructure will be provided by the organizers. Participants are expected to maintain professional conduct throughout the event. Any form of harassment, discrimination, or misconduct will result in immediate removal from the hackathon. Decisions made by the organizing committee and judging panel shall be final and binding. Organizers reserve the right to modify the schedule, rules, or judging process if required due to unforeseen circumstances. By participating, teams consent to photography, videography, and promotional use of media captured during the event. We look forward to welcoming you to Hacknite: Code Royale&mdash;Build. Innovate. Survive.', '2026-06-20T00:00:00+05:30', '2026-08-10T20:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hacknite-12-hour-hackathon-hackers-cult-1701779', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702203', 'AI Product Hackathon', 'Overview Dates: 18th & 19th July, 2026 Registrations: Now Open Kickoff Session: 11th July (Saturday) This is a hands-on, build-first hackathon created for individuals who want to launch a real AI product, not just present ideas or mockups. What You&rsquo;ll Do During these two days, participants will: Conceptualize, build, and launch a complete agentic AI solution Work on practical, real-world challenges Go through the entire product journey: Identifying the problem Designing system architecture Integrating tools and APIs Delivering a functional end product The core focus is on building AI agents ready for real-world use that can: Think and make decisions. Interact with tools. Execute tasks independently. By the end, you&rsquo;ll walk away with a working AI product that can be: Added to your portfolio. Demonstrated in interviews. Expanded into real-world use cases. Participation Guidelines You can join individually or in teams (up to 2 members recommended). All development must happen within the hackathon timeframe. You are free to use AI tools, APIs, and frameworks. Participants must clearly document their process (problem &rarr; solution &rarr; architecture). A functional prototype or live demo is required. Submission Requirements A demo video or live working product. Access to the codebase (GitHub or equivalent). A brief explanation of your solution. Rules & Evaluation ️ Rules Fully pre-built solutions are not allowed (starter templates are acceptable). Any form of copying or plagiarism will result in disqualification. Teams must clearly specify their actual contribution vs AI-generated output. Submissions must be fully working products, not just designs or presentations. All entries must be submitted before the deadline.', '2026-06-21T10:00:00+05:30', '2026-07-19T14:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-product-hackathon-product-space-1702203', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701822', 'DropHack', 'Welcome to the ultimate tech battleground. DropHack is not your average hackathon; it is a high-stakes, high-velocity coding sprint designed strictly for elite student developers. There are no pre-built templates and no rehearsed pitches. Participants will be tested on their raw adaptability, logical thinking, and rapid execution because the exact problem statements are kept heavily guarded until "Zero-Hour." When the timer starts, the challenges drop, and teams have exactly 10 hours to architect, build, and ship a working prototype. The 5 Core Themes While the exact problem statements are a surprise, all challenges will fall under one of these five high-demand tech sectors: Artificial Intelligence (AI) Web3 & Blockchain Cybersecurity Fintech Healthcare Tech Eligibility & Team Formation Guidelines Target Audience (Tech Only): To maintain the highest quality of competition, participation is strictly limited to students pursuing technical degrees (B.Tech, BE, BCA, MCA, M.Tech, BSc IT, or equivalent tech backgrounds). Team Size: 2 to 4 members per team. Inter-College Teams: ALLOWED. You can form teams with developers from different tech institutions. Inter-Specialization (Within Tech): ALLOWED. We highly encourage balancing your team with different technical skill sets (e.g., combining a Frontend UI dev, a Backend architect, and an AI specialist). Solo Participation: Not allowed. A 10-hour sprint requires a coordinated team. The Process & Format (How It Works) Phase 1: Registration & Profile Screening Register your team on Unstop. Ensure all team members have updated their profiles with their technical degrees, primary tech stacks, and active GitHub/LinkedIn links. Phase 2: The Pre-Hackathon Online Assessment (Elimination Round) To ensure an elite playing field, all registered teams must pass a mandatory online technical assessment. Format: Online Quiz / Coding & Algorithmic Fundamentals. Duration: 45 Minutes. Goal: This round filters for strong coding fundamentals and logic to shortlist only the top 15% of teams for the main event. Phase 3: DropHack - The Main Offline Event The shortlisted elite teams will be invited to the official physical venue for the grand finale. Duration: A ruthless 10-Hour Offline Development Sprint. The Drop: Problem statements are revealed live on stage at exactly Zero-Hour. Teams must immediately pivot, divide tasks, and code a Minimum Viable Product (MVP) before the 10-hour clock runs out. Rules of the Competition No Pre-compiled Code: All projects must be built entirely during the 10-hour sprint. Bringing pre-written core logic will lead to instant disqualification. Open Source & APIs: Because time is incredibly tight, the use of open-source libraries, frameworks, and sponsor APIs is heavily encouraged to speed up development. Hardware: Participants must bring their own laptops, chargers, and any necessary adapters. Submission: Final submissions must include a working prototype (MVP), a code repository link (GitHub), and a quick technical walkthrough for the judges. Code of Conduct: Teams must maintain a professional and respectful environment at the offline venue. Any form of harassment or damage to venue property will result in strict action. Are you fast enough to survive the Drop? Register your team now.', '2026-06-21T00:00:00+05:30', '2026-08-29T19:00:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/drophack-siec-community-1701822', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001702167', 'Build The Next Big UI', 'Build The Next Big UI  &ndash; Competition Guidelines Overview Frontend Battle 2026 is a single-round design and development challenge where participants are required to showcase their creativity, problem-solving skills, and frontend development expertise. Teams must submit a PDF presentation highlighting their project idea, user experience, interface design, and implementation approach. Participants may choose any domain or real-world problem, including but not limited to AI, Healthcare, Education, Finance, Sustainability, Productivity, Smart Cities, E-Commerce, and more. Submission Requirements Submission Format One PDF presentation (2&ndash;6 pages) Individual or Team Participation Frontend-focused solutions only Backend implementation is optional Required Sections Problem StatementClearly define the problem your solution aims to address. Explain its significance, target audience, and the challenges faced by users. Proposed SolutionDescribe your solution in detail, including key features, user flow, and how it effectively solves the identified problem. Tech Stack UsedMention the technologies, frameworks, libraries, design tools, and platforms used during development. Examples: React.js Next.js Vue.js Angular Tailwind CSS Bootstrap Figma Framer Motion AI Design Tools 4. Prototype  Include visual representations of your solution such as: Github repo link Vercel link 5. Expected Impact Explain the value your solution creates, including: Target Users Benefits Social or Business Impact Real-world Applications 6. Future Scope Highlight potential future enhancements, scalability opportunities, integrations, and advanced features planned for upcoming versions. Judging Criteria Submissions will be evaluated on the following parameters: UI/UX Design Quality: Visual appeal, design consistency, accessibility, and overall user experience. Innovation & Creativity: Originality of the idea and uniqueness of the proposed solution. Problem-Solving Ability: Relevance of the identified problem and effectiveness of the solution. Prototype Quality: Clarity, completeness, functionality, and presentation of the design. Impact & Feasibility: Potential real-world value, scalability, and practicality of implementation. Submission Guidelines Submit a single PDF file (2&ndash;6 pages). Figma designs, wireframes, mockups, and developed frontend screenshots are all accepted. Participants may use any frontend framework, design tool, or technology stack. AI-assisted tools for design and development are permitted. The submitted work must be original and created by the participating individual or team. Plagiarism or copied designs may lead to disqualification. Deliverable Mandatory Deliverable One PDF Presentation (2&ndash;6 Pages) The competition primarily focuses on: Design Thinking User Experience Frontend Development Creativity & Innovation Problem-Solving Approach A fully functional backend is not required. Case Study Themes Participants may choose any one of the following themes or create their own innovative problem statement. Healthcare & Wellness: Design a platform that helps users monitor health, book appointments, access medical records, or receive AI-powered wellness recommendations. Education & Learning: Build an interactive learning platform that enhances engagement through personalized learning paths, progress tracking, and skill development. Sustainability & Environment: Create solutions focused on waste management, carbon footprint tracking, environmental awareness, or sustainable lifestyle practices. Business & Productivity: Develop a platform that improves task management, team collaboration, workflow automation, and productivity. AI & Future Technologies: Design an AI-powered application that enhances productivity, decision-making, content creation, research, or everyday experiences. Smart Cities & Civic Innovation: Create solutions that improve public services, citizen engagement, issue reporting, and access to government services. Finance & FinTech: Build a user-friendly platform for budgeting, expense tracking, investment insights, and financial literacy. E-Commerce & Customer Experience: Design modern shopping experiences with personalized recommendations, seamless navigation, and intuitive interactions. Gaming & Entertainment: Develop platforms for gaming communities, content discovery, event participation, creator engagement, or digital entertainment. Open Innovation: Participants may choose any real-world problem beyond the listed themes and develop a frontend solution that demonstrates creativity, innovation, and impact.', '2026-06-21T12:00:00+05:30', '2026-07-10T00:00:00+05:30', 'Online', 'online', 'Certificate of Achievement for winners for Top - 5', 'https://unstop.com/hackathons/build-the-next-big-ui-techverse-solutions-1702167', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693713', 'Business Leadership Simulator 2026', 'About the Competition: What if you were given control of a real business and asked to grow it? Business Leadership Simulator is not a business plan competition. It is not a case study competition. It is not a hackathon. This is a real-world business simulation designed to test your entrepreneurial thinking, leadership ability, decision-making skills, execution capability, and business acumen under realistic conditions. Participants will be assigned a live business scenario and will be expected to make strategic decisions, solve operational challenges, manage growth opportunities, and navigate real-world business situations. Your performance will be evaluated not on presentations or theoretical answers, but on your ability to think like an entrepreneur and lead like a business owner. What Makes This Different? Most competitions test how well you can create a business plan. This competition tests how well you can actually run a business. Participants will be required to: Make strategic business decisions Solve real business challenges Manage limited resources Develop growth strategies Handle customer and operational situations Demonstrate leadership and execution ability Adapt to changing market conditions Every decision you make will influence your overall performance in the simulation. Skills Evaluated: Entrepreneurship Leadership Decision Making Business Strategy Problem Solving Communication Team Management Crisis Handling Growth Thinking Execution Capability Competition Format: Round 1: Business Introduction & Market Understanding Participants will receive details of the business they will be managing and will be expected to understand its challenges, opportunities, and market dynamics. Round 2: Business Simulation Participants will make operational, strategic, and growth decisions while responding to real-world business scenarios. Round 3: Leadership & Execution Assessment Participants will be evaluated on how effectively they manage resources, solve problems, and grow the business. Rewards: Internship Opportunities for Top Performers The highest-performing participants will receive internship offers and opportunities to work on real business projects. Industry Recognition Gain practical experience that goes far beyond traditional academic competitions. Leadership Exposure Demonstrate your entrepreneurial and managerial abilities in a realistic business environment. Eligibility: Open to: Undergraduate Students Postgraduate Students Aspiring Entrepreneurs Future Business Leaders Anyone interested in entrepreneurship, management, and leadership Platform: The competition will be conducted entirely on YAI Infraventure''s proprietary platform. Participants will receive further instructions after successful registration. Think Like a Founder. Lead Like a CEO. Execute Like an Entrepreneur.', '2026-06-19T00:00:00+05:30', '2026-06-30T00:01:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/business-leadership-simulator-2026-yai-infraventure-1693713', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701194', 'ThreadCounty Web Development Hackathon 2026', 'About ThreadCounty: ThreadCounty is an AI-powered textile technology platform that helps textile manufacturers, students, researchers, and quality control professionals analyze fabric structures using Artificial Intelligence and Computer Vision. The platform aims to simplify textile inspection by allowing users to upload fabric images and receive automated thread density analysis, weave information, AI insights, and downloadable reports through a modern web application. Your challenge is to build the next-generation ThreadCounty platform with an exceptional user experience, production-ready architecture, and scalable backend. Problem Statement: Design and develop a complete full-stack web application for ThreadCounty. The application should look like a professional SaaS product and must include a modern UI, secure authentication, responsive design, efficient backend architecture, and database integration. Participants are free to use their creativity while maintaining the required functionality. The final product should be deployable and production-ready. Objective: Develop a professional website that enables users to: Learn about ThreadCounty. Create an account. Login securely. Manage their profile. Upload fabric images. View AI-generated analysis reports. Download reports. View previous uploads. Contact the organization. Purchase subscription plans. Access FAQs and documentation. Additionally, administrators should be able to manage users, uploaded images, and platform analytics through an Admin Dashboard. Website Pages (Mandatory): Landing Page Hero Section. Professional Navbar. Call-to-Action Buttons. Product Overview. Features Section. Benefits. Workflow Section. Testimonials. Statistics. FAQ. Contact Section. Footer. Authentication Sign Up. Login. Forgot Password. Email Verification. Logout. Remember Me. User Dashboard Welcome Section. User Information. Total Uploads. Recent Reports. Storage Usage. Activity Timeline. Quick Actions. Notifications. Image Upload Module Allow users to upload: JPG. PNG. JPEG. Features: Drag & Drop Upload. Image Preview. Upload Progress. Validation. File Size Restrictions. Delete Uploaded Images. AI Analysis Result Page Display: Uploaded Image. Thread Density. Warp Count. Weft Count. Fabric Type. Confidence Score. AI Suggestions. Download Report Button. Share Report Option. Mock AI results are acceptable if no AI model is integrated. History Page View Previous Analyses. Search Reports. Filter Reports. Delete Reports. Download Previous Reports. Pricing Page Free Plan. Student Plan. Professional Plan. Enterprise Plan. Display: Features. Pricing Cards. Subscribe Button. About Page Company Story. Mission. Vision. Technology Used. Team Section. Timeline. Contact Page Contact Form. Email. Social Media Links. Google Maps (Optional). FAQ Page Include common questions regarding: Platform. AI Analysis. Pricing. Upload Limits. Account. User Profile Update Profile. Upload Profile Picture. Change Password. Delete Account. View Activity. Admin Dashboard View Total Users. Manage Users. View Uploaded Images. Delete Reports. View Analytics. Manage Subscription Plans. Platform Statistics. Backend Requirements: Develop a scalable backend with proper architecture. Required APIs: Authentication API. User API. Upload API. Report API. Dashboard API. Admin API. Contact API. Use proper: Error Handling. Input Validation. Authentication Middleware. Authorization. Logging. Database: Use Supabase. Suggested Tables: Users. Profiles. Uploads. Reports. Subscriptions. Contact Messages. Notifications. Use proper relationships and security policies. UI/UX Requirements: Fully Responsive. Mobile Friendly. Modern UI. Attractive Animations. Smooth Transitions. Dark Mode. Light Mode. Accessible. Fast Loading. Bonus Features: AI Chatbot. Voice Search. Image Compression. OCR Integration. Multi-language Support. Progressive Web App (PWA). Real-time Notifications. Email Notifications. Analytics Dashboard. Fabric Comparison Tool. Blog Section. Community Forum. Admin Role Management. Infinite Scroll. Lazy Loading. Offline Support. Recommended Tech Stack: Frontend: React.js. Next.js. TypeScript. Tailwind CSS. Framer Motion. ShadCN UI. Backend: Python Database: Supabase. Authentication: Supabase Auth. Deployment: Vercel. Netlify. Render. Railway. Version Control: Git. GitHub. Deliverables: GitHub Repository. Live Hosted Website. README Documentation. Database Schema. API Documentation. Rules: Original work only. No plagiarism. Open-source libraries are allowed. AI tools are allowed. All code must be developed during the hackathon period. Website must be fully responsive. The project should be hosted on a public platform. GitHub repository must remain public until evaluation. Late submissions will not be accepted. Judges'' decision will be final.', '2026-06-18T00:00:00+05:30', '2026-06-30T21:47:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/threadcounty-web-development-hackathon-2026-dkte-societys-textile-engineering-institute-dktestei-ichalkaranji-1701194', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701427', 'Unlock''D', 'The New Build-A-Thon Concept: Unlock&rsquo;D is a fast-paced, 24-hour virtual Build-A-Thon designed around the principles of agile development and milestone-based execution.​The Progression: Instead of forcing you to conceptualize an idea from scratch, the core application structure and underlying blueprint will be provided directly to your team.​The Execution: Over a focused 24-hour timeline, your team will follow a progressive, milestone-driven sprint. You will be tasked with building and deploying specific features of the application one by one. Successfully unlocking and completing each feature sequentially will navigate your team to full application development by the end of the event.​Key Benefits & Perks: Zero Experience Required: This is a completely beginner-friendly sandbox. To ensure you can build confidently.​Resume & Portfolio Acceleration: Unlike standard hackathons, where ideas go unfinished, this milestone framework mirrors real-world production engineering, leaving you with a highly polished, GitHub-worthy full-stack project perfect for placement cycles.​Tangible Perks: Every single participant will receive an official Certificate of Participation to boost their credentials, along with the chance for top teams to claim rewards from our premier prize pool!​ Event Details: Mode: Online ​Dates: 3rd - 4th July 2026 ​Duration: 24 Hours ​Team Size: 1-3 Members ​Prize Pool: Announced Soon Ping us here for queries: Pushkar Chaudhary (9313073267) Jaagriti Sethia (7439454640) ​Alekhya Mazumdar (8777090142)', '2026-06-22T00:00:00+05:30', '2026-07-04T10:30:00+05:30', 'Online', 'online', '₹ 3,000', 'https://unstop.com/hackathons/unlockd-manipal-university-mu-jaipur-1701427', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694014', 'StoxraHack 2026 — India''s Student FinTech & AI Trading Hackathon', 'Build. Innovate. Compete. Win. Stoxra National Online Hackathon 2026 is one of India''s largest student innovation challenges, bringing together developers, designers, entrepreneurs, AI enthusiasts, and future innovators from across the country. Participants will solve real-world problems in Artificial Intelligence, FinTech, Trading Technology, Financial Literacy, Data Analytics, Automation, and Emerging Technologies while competing for prizes worth ₹3.5 Lakhs+. Whether you''re a beginner exploring innovation or an experienced builder ready to showcase your skills, this hackathon provides a platform to learn, collaborate, network, and create impactful solutions. fees -200 New Update: Join the STOXRA Hackathon 2026 for FREE! We''ve listened to your feedback! Many participants wanted a way to reduce or completely waive the ₹200 registration fee. To make the hackathon more accessible, we''ve introduced the STOXRA Earn Registration Credits Program. Now you can earn registration credits by: Referring Hackathon participants Sharing the official STOXRA Hackathon posts Inviting new STOXRA users Complete the required tasks and reduce your registration fee&mdash;or even join the hackathon for FREE! Want to Join the Hackathon for FREE? Join our Official WhatsApp Community and WhatsApp Channel to get the complete step-by-step guide on: How to earn registration credits How to complete each task How to verify your submissions How to reduce your registration fee How to unlock FREE Hackathon registration WhatsApp Community:https://chat.whatsapp.com/JDX5EOO8UcN4hmPvhLc1Dz WhatsApp Channel:https://whatsapp.com/channel/0029Vb8bgCX9hXFEib74FM1u Note: All referrals, social media posts, and invited users will be verified by the STOXRA team before registration credits are added to your account. Start completing your tasks today and join STOXRA Hackathon 2026 at the lowest possible cost&mdash;or even FREE! Prize Pool: ₹3,50,000+ Worth of Prizes Domains: Artificial Intelligence (AI) FinTech Innovation Trading Technology Financial Literacy Machine Learning Data Analytics Web Development Mobile Applications Automation & Productivity Tools Startup & Business Solutions Team Size: Minimum: 2 Members Maximum: 5 Members Event Mode: 100% Online Level Competition Structure: Level 1 &ndash; Idea Submission Last Date for PPT Submission:  Teams submit their innovative idea and problem statement. Level 2 &ndash; Prototype & Pitch Deck  : Shortlisted teams develop an initial prototype and pitch deck. Level 3 &ndash; Live Build Sprint (Semi-Finals) ( Selected teams receive mentorship and further develop their solutions. Level 4 &ndash; Grand Finale  Top teams present their projects before an expert jury panel. Eligibility: Open to all College Students across India Engineering, Management, Commerce, Design, and Technology students are welcome Students from any recognized institution can participate Evaluation Criteria: Innovation & Creativity Technical Implementation Problem Solving Scalability User Experience Business Potential Presentation & Pitch Quality Benefits: Certificates for All Participants Internship Opportunities at Stoxra Industry Expert Mentorship National-Level Recognition Networking with Students Across India Real-World Problem Statements Portfolio Building Opportunity Fast-Track Opportunities for Top Performers Duration: 48-Hour Online Innovation Challenge Why Participate? Build innovative solutions, gain industry exposure, connect with talented students nationwide, and compete for exciting rewards while solving meaningful real-world problems.', '2026-06-02T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', '₹ 2,00,000', 'https://unstop.com/hackathons/stoxrahack-2026-indias-student-fintech-ai-trading-hackathon-stoxra-hackathon-2026-iimt-university-iimtu-great-1694014', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001701080', 'Infinity Hack 1.0', 'Code Beyond Limits &bull; Innovate Without Boundaries Code Infinite IT Training Service, Coimbatore proudly presents INFINITY HACK 1.0, an innovation-driven hackathon that brings together aspiring developers, innovators, and problem solvers to transform ideas into impactful solutions. Participation Process: Idea Submission Round 18 June 2026 &ndash; 22 June 2026 Teams are invited to submit their innovative ideas via WhatsApp. WhatsApp Number: +91 99764 99765 Only the Team Leader should contact and submit the idea. While submitting, the Team Leader must provide: Team Name Project Title Domain Team Leader Name Names of all Team Members College Name Contact Number Shortlisting Round 23 June 2026 Shortlisted teams will be notified after evaluation of the submitted ideas. Registration Confirmation Selected teams are required to confirm their participation by paying a registration fee of ₹100. Hackathon Day 26 June 2026 Time: 9:00 AM &ndash; 5:00 PM Location: Coimbatore Domains: Artificial Intelligence & Machine Learning Web Development Cybersecurity Data Science Cloud Computing IoT & Robotics What Participants Will Receive: Exciting Surprise Gifts E-Certificates for All Participants Internship and Career Opportunities Networking with Fellow Innovators Exposure to Real-World Problem Solving Bring your ideas to life and become part of a community that believes in innovation without limits. Think Infinite. Create Impact.', '2026-06-18T00:00:00+05:30', '2026-06-22T00:01:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/infinity-hack-10-sangam-soft-solutions-1701080', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700798', 'AI Product Challenge 2026', 'Build an AI Product. Solve a Real Problem. Compete with Builders Across India. The AI Product Challenge 2026 is a national-level innovation challenge for students, developers, creators, designers, and aspiring founders who want to build real AI-powered products and showcase their creativity. Participants will identify a real-world problem, design an innovative solution, and build an AI-powered product, tool, workflow, application, or platform. This is not about theory. This is about building. Challenge Theme: Build the Future with AI Create solutions in: Education Healthcare Productivity Finance Sustainability Agriculture Student Life Creator Economy Social Impact Any other domain where AI can create meaningful impact Challenge Rounds: Round 1: Idea Submission Submit: Problem Statement Proposed Solution AI Implementation Approach Round 2: Product Development Shortlisted participants build: AI Tools AI Agents SaaS Products Automation Workflows Mobile Applications Web Applications Productivity Solutions Round 3: Final Showcase Present your solution and demonstrate: Innovation Impact Execution Product Thinking Judging Criteria: Innovation & Creativity Problem Solving AI Integration Product Execution User Value Presentation Rewards & Opportunities: Scholarships & Special Recognition Internship Opportunities Founder Mentorship Builder Community Access Certificates Networking Opportunities Exclusive Opportunity: The Top 50 Participants will be shortlisted for an exclusive builder initiative where they will gain access to advanced opportunities, founder interactions, project support, community programs, and future innovation initiatives within the Dyndox ecosystem. Who Can Participate? School Students Undergraduate Students Postgraduate Students Developers Designers Creators Aspiring Founders AI Enthusiasts Individual Participation Allowed. Build. Compete. Launch.', '2026-06-18T00:00:00+05:30', '2026-07-02T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-product-challenge-2026-dyndox-1700798', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700796', 'AI Builders Hackathon 2026', 'Build Products. Launch Startups. Create the Future. The AI Builders Hackathon 2026 is a national-level innovation challenge for students, developers, creators, aspiring founders, and future builders who want to leverage AI to solve real-world problems and create meaningful products. Whether you''re building an AI tool, startup idea, automation workflow, SaaS product, mobile app, or innovative solution, this hackathon is designed to help you think, build, and execute. What You''ll Get: AI & Product Building Workshops Founder-Led Mentorship Sessions Startup & Innovation Frameworks Access to AI Resources & Toolkits Networking with Builders & Innovators Community Support & Collaboration Certificates of Participation Scholarships & Special Recognition The Builder Acceleration Cohort This hackathon is more than a competition. The Top 50 participants will be selected for an exclusive Builder Acceleration Cohort, where they will receive: 1 Week of Intensive Mentorship Product Building Guidance Startup Validation Sessions AI Implementation Workshops Founder Office Hours Community Access Demo Day Opportunities Career & Internship Opportunities Who Can Participate? School Students Undergraduate Students Postgraduate Students Developers Designers Creators Aspiring Founders AI Enthusiasts No prior startup experience is required. Judging Criteria: Innovation & Creativity Problem Solving AI Integration Feasibility Impact Potential Execution Ability Why Participate? The future belongs to people who can build. This hackathon is your opportunity to turn ideas into reality, connect with ambitious peers, learn from founders, and gain access to opportunities that extend far beyond the competition itself. Build. Launch. Grow.', '2026-06-18T00:00:00+05:30', '2026-07-02T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ai-builders-hackathon-2026-dyndox-1700796', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001690425', 'AVANZARE V19.0 – 24-Hour National Level Hackathon', 'Ready to turn your ideas into reality? Join the 24-Hour National Level Hackathon at AVANZARE 2K26 and challenge yourself to innovate, code, collaborate, and build impactful solutions within 24 hours. Compete with talented teams, solve real-world problems, and showcase your creativity on a national platform. Event Date & Duration: Event Dates: 17.07.2026 &ndash; 18.07.2026 Hackathon Duration: 24 Hours (Continuous) The hackathon will commence on 17 July 2026 and conclude on 18 July 2026. All project development activities must be completed within the 24-hour hackathon period. Eligibility: Open to Undergraduate (UG) and Postgraduate (PG) students from recognized colleges and universities across India. Students from all engineering, technology, science, and allied disciplines are eligible to participate. Participants must carry a valid College ID card for verification. Team participation is mandatory. Problem Statements:  Hardware  1. IoT-Based NPK Soil Nutrient Monitoring System Problem Statement:Develop an IoT system to monitor soil Nitrogen (N), Phosphorus (P), and Potassium (K) levels in real time and provide fertilizer recommendations to farmers. Tech Stack: IoT, Sensors, Cloud, Mobile/Web App Outcome: Improved crop yield and optimized fertilizer usage.   2. Smart Weather Station for Agriculture Problem Statement:Build a smart weather station that monitors environmental parameters and provides localized weather insights for agricultural decision-making. Tech Stack: IoT, Sensors, Analytics Outcome: Better crop planning and reduced weather-related losses.   3. Geographic Location-Based Crop Disease Prediction Problem Statement:Develop an AI model that predicts crop diseases using location and climatic data and recommends preventive measures. Tech Stack: Machine Learning, GIS, Data Analytics Outcome: Early disease detection and reduced crop losses.   4. Soil Moisture-Based Automated Irrigation System Problem Statement:Design an automated irrigation system that controls water supply based on soil moisture levels. Tech Stack: IoT, Sensors, Embedded Systems Outcome: Water conservation and efficient irrigation.   5. Precision Farming Solution for Polyhouse Cultivation Problem Statement:Create a smart monitoring and control system for polyhouse environments to optimize crop growth. Tech Stack: IoT, AI, Automation Outcome: Increased productivity and resource efficiency.    Software   1. Burn-Ex: AI-Based Calorie Estimation System Problem Statement:Develop an AI model to estimate calories burned during physical activities using a self-generated dataset without relying on external APIs. Tech Stack: Computer Vision, Machine Learning Outcome: Accurate and privacy-preserving fitness analytics.   2. Enhancement of Existing IEEE Projects Problem Statement:Enhance an existing IEEE project by integrating advanced technologies to improve performance and real-world usability. Tech Stack: AI, IoT, Edge Computing Outcome: Scalable and deployable solution.   3. WhatsApp Lead Engagement System Problem Statement:Build a system that automatically sends WhatsApp messages to leads and prioritizes prospects based on interactions. Tech Stack: NLP, CRM, Automation Outcome: Improved customer engagement and conversion.   4. AI-Based Resume Screening System Problem Statement:Develop an AI solution that filters and ranks resumes according to job requirements and skills. Tech Stack: NLP, Machine Learning Outcome: Faster and more accurate hiring.   Team Formation: Each team must consist of 2 to 4 members. Inter-college teams are allowed. Inter-department/inter-specialization teams are allowed. A participant can be a member of only one team. Hackathon Format: The hackathon will be conducted in a single round. Teams are required to analyze the problem, design the solution, develop the prototype, and prepare the final presentation within the allotted time. At the end of the hackathon, each team must present and demonstrate their solution before the judging panel. Duration: Hackathon Duration: 24 Hours (Continuous) All project development activities must be completed within the 24-hour hackathon period. General Instructions: Team members must complete individual registration. After registration, payment must also be completed. Teams can be formed on the day of the event. A common community group will be created and shared via the registration confirmation mail for updates and announcements. Teams are free to select the problem statement from give list. The jury&rsquo;s decision will be final and binding. Dinner and Breakfast and refreshments will be provided for both days. Lunch will be not provided. Participants will not be permitted to leave the campus under any condition. Any team leaving the campus within the 24 hours will be eliminated immediately. Participants are advised to carry an extension box and other necessities as required. AC venues will be allocated for all participants. Participants must bring their own water bottles, water refill facilities will be provided. What Participants Gain: National-Level Competition Experience Opportunity to Build Real-World Solutions Networking with Developers and Innovators Participation and Winner Certificates Exciting Cash Prizes and Recognition Organized By: IEEE Student Branch, Kongu Engineering College Tagline: Code for 24 Hours. Create Solutions for Tomorrow.', '2026-06-06T14:59:00+05:30', '2026-07-16T12:59:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/avanzare-v190-24-hour-national-level-hackathon-kongu-engineering-college-1690425', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700757', 'ROBOVANTA ''26 Hackathon – Code & Build for ₹80,000 Prize Pool', 'ROBOVANTA ''26 HACKATHON &mdash; Code. Build. Innovate. Transform₹80,000 Prize Pool  Register here : https://robovanta.vercel.app Got an idea that solves a real problem? Bring it to life in 24 hours at ROBOVANTA ''26 &mdash; India''s most electric inter-college tech fest, hosted at AKV Vidyalaya, Dindigul. This year, Software and Hardware innovators compete together under one roof &mdash; one hackathon, two tracks, one shot at ₹80,000 in prizes. Why Join:₹80,000 prize pool across 7+ award categories &mdash; Winner, Runner-Up, Second Runner-Up, Best Innovation, Best UI/UX, Best Hardware Design, and Best Social Impact Solution. Be part of a 3-day fest with 1000+ participants and 20+ industry speakers. Live problem statements only (no pre-built projects) for a fair, skill-only fight, plus direct visibility in front of expert judges and recruiters. Choose Your Track Software Track &mdash; Build a working software prototype in AI/ML, Web Dev, Mobile Apps, Cybersecurity, Cloud Computing, IoT (software side), HealthTech, AgriTech, Smart Cities, EdTech, FinTech, or Social Impact. Use Python, Java, C/C++, JavaScript, Flutter, React, Node.js, PHP, .NET, SQL/NoSQL, open-source frameworks, and APIs. Hardware Track &mdash; Design and demo a working hardware prototype in Robotics, Automation, IoT, Embedded Systems, AI Hardware, Smart Agriculture, HealthTech, Renewable Energy, Smart Cities, Industrial Automation, or Assistive Tech. Bring your own Arduino/ESP32/Raspberry Pi, sensors, motors, batteries, and tools. FormatProblem statements released at the start of the event. 24-hour continuous build sprint &mdash; design, develop, test. Final demo: 5-minute presentation + 3-minute Q&A before judges. EligibilityTeams of 1&ndash;5 members, open to all college students. Interdisciplinary teams encouraged. One submission per team. No pre-built or previously completed projects &mdash; originality is strictly judged. Judged OnInnovation & Creativity, Technical Implementation, Working Prototype/Functionality, Problem-Solving Impact, Presentation & Demo, and Future Scalability (out of 100 marks). ImportantParticipants must bring their own laptops/development boards/components &mdash; organizers will not provide equipment. No on-spot registration. Teams must report 30 minutes before the event begins. Jul 3&ndash;5, 2026 | AKV Vidyalaya, Dindigul  Register here: robovanta.vercel.app/events(Registrations are open exclusively on our official website &mdash; not through Unstop.)', '2026-06-17T00:00:00+05:30', '2026-07-03T15:12:01+05:30', 'Online', 'online', '₹ 80,000', 'https://unstop.com/hackathons/robovanta-26-hackathon-code-build-for-rs80000-prize-pool-pixor-robotics-club-1700757', 'external', ARRAY['Design', 'Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700357', 'Google Gemini Music Night: Live AI Band Face-off', 'Guidelines, Rules & Rewards: Event Overview: Google Gemini Music Night: AI Band Face-off is a creative innovation challenge where participants will use Google Gemini and Lyria to create a unique virtual band, design a band poster, and generate an original music track inspired by their campus, experiences, culture, stories, and student life Participants may compete individually or in teams of up to 3 members Challenge Flow: Form a team of 1&ndash;3 members Create your band''s identity, including its name, theme, and aesthetic Use Google Gemini to generate and design your band''s official poster Use Lyria to create an original music track that represents your campus, experiences, stories, traditions, culture, or student life Submit the required deliverables before the submission deadline Entries will be showcased and voted upon by participants and the community Submission Requirements: Each team must submit: AI-generated Band Poster Lyria Music Track (shareable link) Team Details Google Gemini chat links/prompts used during creation Completed Feedback Form Rules: Team size must be between 1 and 3 members All submissions must be original and created specifically for this challenge Google Gemini must be used for poster creation Lyria must be used for music generation Copyrighted, plagiarized, or previously published content is strictly prohibited Participants may submit only one final entry per team Any inappropriate, offensive, or misleading content will result in disqualification Organizers reserve the right to verify submissions and request supporting evidence if required The decision of the organizers and judges shall be final Voting & Evaluation: Community voting will be conducted after submissions are received The team receiving the highest number of valid votes will be recognized as the Top Creator of the event Entries may also be reviewed for originality, creativity, storytelling, and effective use of AI tools Rewards & Recognition: National Winner: Google Pixel Buds 2A Top Creator Certificate: Awarded to the participant/team receiving the highest number of valid votes Participation Certificates: Awarded to eligible participants who: Submit all required deliverables Complete the official feedback form Provide the required Google Gemini chat links/prompts used during the challenge Certificates will only be issued after successful verification of submissions and completion of the feedback process', '2026-06-17T00:00:00+05:30', '2026-06-20T21:00:00+05:30', 'Online', 'online', 'Nomination for Google Pixel Buds 2a and Top Prompt Creator Certificate', 'https://unstop.com/events/google-gemini-music-night-live-ai-band-face-off-google-student-ambassador-1700357', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700643', 'SRCAS Hackathon 3.0 - What''s the next big idea?', 'SRCAS Hackathon 3.0: SRCAS Hackathon 3.0 is a national-level innovation challenge organized by the Programming Club of Sri Ramakrishna College of Arts & Science (SRCAS), Coimbatore, in association with iGenius, an authorized partner of Microsoft The hackathon focuses on developing innovative solutions aligned with the United Nations Sustainable Development Goals (SDGs) Open Statements (Choose a problem statement by your own) It encourages students to create technology-driven solutions for real-world problems Submit your ideas and register your team  Eligibility: Open to all UG, PG and Engineering students across India Participants must register as a team Teams should consist of 2 to 4 members Members may be from the same or different disciplines, but all members need to be from same college A valid college ID card is mandatory for all participants during the event Registration: Registration Fee: Free Registration Opens: 12 June 2026 Registration Closes: 25 July 2026 Teams must complete the online registration form and submit their project idea before the deadline', '2026-06-17T00:00:00+05:30', '2026-08-15T10:00:00+05:30', 'Online', 'online', '₹ 1,80,000', 'https://unstop.com/hackathons/srcas-hackathon-30-whats-the-next-big-idea-sri-ramakrishna-college-of-arts-science-srcas-1700643', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700622', 'Full Stack Hackathon', 'Hackathon Overview Step into the PaperBuddy Web Hackathon! We are calling on creators, programmers, and critical thinkers to engineer groundbreaking web platforms that will redefine educational technology. Share your most creative concepts and contribute to developing future EdTech solutions designed to optimize and simplify school management. Participation Guidelines Who Can Enter: This event is accessible to every student. We highly welcome and permit collaborative groups formed across different colleges and fields of study. Group Capacity: You may compete individually or assemble a squad of up to four people (1 to 4 participants). Technology Permitted: Completely unrestricted! You have the full liberty to utilize any frameworks, coding languages, cloud platforms, or databases you are comfortable with. Challenges: After registration, participants will be emailed a specific list of challenges. Every group is required to select and tackle just one of these provided issues. Event Structure & Stages The competition is divided into two primary stages: Stage 1 (Concept Pitch): Groups are required to hand in a comprehensive plan that describes their main concept and the technological strategy they intend to use for their selected challenge. Stage 2 (Prototype Creation): Teams that advance past the first stage will move on to construct their web application and hand in a functional, final model. Official Rules Original Code: All programming for the second stage must be authored specifically during the competition window. Turning in previously completed applications will result in immediate removal from the event. Submission Requirements: To complete the final round, groups need to share a public GitHub link featuring their code, coupled with either a live demonstration link or a brief video walkthrough of their creation. Permitted Tools: You are allowed to leverage AI coding aids, open-source resources, and external APIs, as long as they are woven into a unique, custom-built application. Academic Integrity: Copying someone else''s work, whether in the initial concept pitch or the final software, is entirely forbidden. Judging Finality: All verdicts made by the evaluators concerning scoring, advancements, and the ultimate champions are absolute and cannot be contested.', '2026-06-17T00:00:00+05:30', '2026-07-04T17:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/full-stack-hackathon-deenbandhu-chhotu-ram-university-of-science-and-technology-dcrust-murthal-haryana-1700622', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700632', 'Anakin Blitz', 'About Anakin Blitz: Anakin Blitz is a fast-paced virtual hackathon designed for builders who want to ship, not just plan In just six hours, participants will use the Wire API and Anakin Universal Scraper to create something functional, creative, and real No fluff, no filler, just focused building Overview: This isn''t a multi-day marathon with endless brainstorming sessions It''s a tight, high-energy sprint where the constraint is the feature: six hours to go from idea to working product Whether you''re prototyping a tool, automating a workflow, or building something nobody''s tried before, Blitz is about momentum and execution Event Details: When: June 20, 2026, 12:00 PM to 6:00 PM IST Where: Discord (https://discord.gg/5eyFsVPj) What you''ll build with: Wire API and Anakin Universal Scraper Prizes: 1st Place: Keychron Mechanical Keyboard 2nd and 3rd Place: 2,000 Anakin credits each Why Participate: Whether you''re a solo builder or teaming up, Anakin Blitz is your chance to test your speed, creativity, and problem-solving under pressure Walk away with something to show for it Call to Action: Register now and get ready to build', '2026-06-17T00:00:00+05:30', '2026-06-21T18:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/anakin-blitz-anakin-skywalker-pvt-ltd-1700632', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700212', 'WebChamp', 'WebChamp 2026 is an online web development competition designed to encourage creativity, innovation, and technical excellence in website design and development. Participants are required to design and develop a fully functional website based on the competition theme and submit their work for evaluation by the judging panel. Eligibility Open to university students, school students, and independent learners. Participants may compete individually or as a team. Team size: 1&ndash;4 members. Inter-college teams are allowed. Inter-specialization teams are allowed. Participants may submit only one project/team entry. Competition Format Round 1 &ndash; Registration Participants must register through the official registration platform. Teams must provide accurate member details. Round 2 &ndash; Development & Submission Participants will design and develop a website based on the competition theme. Projects can be developed using any web technologies, frameworks, or platforms. Participants must submit: A ZIP file of the project, or A hosted/live website link. A GitHub repository link is highly recommended. All submissions must be made before the submission deadline. Round 3 &ndash; Evaluation Projects will be evaluated by a panel of judges. Judges may access the live website or review the submitted source code. Final results will be announced on the official WebChamp channels. Judging Criteria Projects will be evaluated based on: Creativity and Innovation User Interface (UI) Design User Experience (UX) Functionality and Features Responsiveness and Accessibility Code Quality and Best Practices Performance and Optimization Overall Impact and Presentation Submission Requirements Website must be fully functional. All links and features should work properly. Hosted links must remain accessible during the judging period. Participants must own or have permission to use all assets included in the project. AI tools may be used as development aids, but participants must understand and be able to explain their implementation. Rules All submitted work must be original. Plagiarism or direct copying of existing projects is strictly prohibited. Participants must comply with all deadlines. Offensive, illegal, or inappropriate content will result in immediate disqualification. The organizing committee reserves the right to disqualify submissions that violate competition rules. Judges'' decisions are final and cannot be appealed. By participating, contestants grant the organizers permission to showcase submitted projects for promotional and educational purposes. Participants are responsible for maintaining access to their hosted projects throughout the judging period. Communication All official announcements, updates, and competition-related information will be shared through the WebChamp WhatsApp Community and official communication channels. Certificates & Awards Winners will receive certificates and recognition. Participation certificates will be awarded to eligible participants who successfully complete the competition requirements.', '2026-06-16T00:00:00+05:30', '2026-06-25T10:39:26+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/webchamp-nsbm-green-university-homagama-sri-lanka-1700212', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001700041', 'Hackathon: AI for Public Good – Sustainable & Resilient Supply Chains', 'AI for Public Good: Sustainable & Resilient Supply Chains Hackathon The Hackathon is being organized under the Indo-Swiss Research Grant in collaboration with researchers from ETH Zurich, the University of Lausanne, IIIT Allahabad and Manipal University Jaipur alongside WikiClub Tech. Participants will work on real-world challenges in sustainable and resilient supply chains using AI-driven and innovative approaches. Eligibility: Open to undergraduate, postgraduate, and PhD students from all recognized institutions. Students from any discipline are eligible to participate. Inter-college teams are allowed. Inter-specialization/inter-department teams are allowed. Team Formation: Participation is in teams of 1&ndash;3 members. Team members may belong to different colleges, universities, or academic disciplines. One participant can be a member of only one team. Problem Statement: A detailed problem statement will be provided by Lowe''s India, focusing on sustainable and resilient supply chains. Participants are expected to propose innovative solutions addressing the challenge using AI and related technologies. Rules: All submissions must be original work created by the participating team. The use of AI tools (e.g., ChatGPT, Claude, Gemini, etc.) is permitted and encouraged. Teams must clearly explain how AI contributed to refining their solution. Any form of plagiarism will result in immediate disqualification. Teams must adhere to all submission deadlines and guidelines. Organizers reserve the right to modify timelines, evaluation procedures, or event details if required. The decision of the jury and organizing committee will be final and binding. Prizes & Opportunities: Certificates for winning teams. Mentorship and networking opportunities with international researchers and industry experts. Potential research, internship, and collaboration opportunities for outstanding participants. IMPORTANT LINKS Register on Unstop (Hackathon):https://unstop.com/o/UNtyVfK?lb=0rMVMUWm Register on Unstop (Workshop) :https://unstop.com/o/cHq3dRS?lb=0rMVMUWm Join the official WhatsApp community:https://chat.whatsapp.com/ETHdVU9X9Vo8O6LDK4bBY2', '2026-06-16T00:00:00+05:30', '2026-06-30T23:59:00+05:30', 'Online', 'online', 'Official Signed Merit Certificate from Collaborating institutes and industry partners alongside research internship oppurtunities', 'https://unstop.com/hackathons/hackathon-ai-for-public-good-sustainable-resilient-supply-chains-manipal-university-mu-jaipur-1700041', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699892', 'AI Hackathon.', 'AI & Web Dev Hack-a-Thon &ndash; Hosted by Manas Kumar VermaAPPLY HERE: https://ng.tinyc.co/-aicampAn intensive, project-driven development tournament where elite incoming students compete to build, deploy, and launch production-ready products from scratch. The competition is designed and judged by Manas Kumar Verma, ranked among the Top 15 Programmers in India and a Meta Hacker Cup Winner.The Challenge Blueprint: Over the course of the competition, participants must rapidly architect, code, and deploy 6+ live, real-world projects to climb the leaderboard. The submission portfolio includes: Live News Tracker &ndash; Real-time data streaming and monitoring. Newspaper-Style Web App &ndash; Dynamic content layouts and publishing architecture. Character-Themed Animated UI &ndash; Advanced front-end motion graphics and styling. Document Explorer &ndash; Complex data filtering and search systems. E-Commerce Landing Page &ndash; High-conversion user experience and responsive design. Interactive Browser Piano &ndash; Audio API integration and real-time event handling. Platform: Unstop Timeline & Intensity: Duration: 10 Days of high-intensity, non-stop building and deployment sprints. Eligibility & Rules: Target Audience: Open to students who have successfully passed the 12th grade, including gap-year students (&ldquo;droppers&rdquo;), who are entering engineering colleges. Prerequisites: Zero prior coding experience is required&mdash;your drive to learn, build, and adapt under pressure is what matters. The Golden Rule: This is a pure building competition. Active participation, daily milestone submissions, and completely functional, live-deployed URLs are strictly required to remain in the running.', '2026-06-10T18:11:26+05:30', '2026-08-18T13:06:14+05:30', 'Online', 'online', 'GOOGLE CAMPUS VISIT', 'https://unstop.com/hackathons/ai-hackathon-algo-university-1699892', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699798', 'Ignisys', 'Ignisys Hackathon 2026 A 24-Hour Hackathon at IGNITIA''26 IGNISYS Hackathon 2026 is a 24-hour innovation challenge designed to bring together students, developers, designers, and innovators to build impactful solutions for real-world problems. Participants will collaborate, ideate, develop, and present their projects within the hackathon duration. Eligibility: Open to all Undergraduate and Postgraduate students. Inter-college teams are allowed. Inter-specialization teams are allowed. Team size: 2&ndash;4 members. Format: Round 1: Registration & Team Confirmation Round 2: 24-Hour Development Phase Round 3: Final Project Presentation & Evaluation Themes: Artificial Intelligence & Machine Learning Cybersecurity Healthcare Education Sustainability Open Innovation Productivity & Automation Judging Criteria: Innovation & Creativity Technical Implementation Problem-Solving Approach User Experience Scalability & Impact Presentation & Demonstration Rules: All projects must be developed during the hackathon. Teams must submit an original solution. Use of AI tools, APIs, frameworks, and open-source libraries is permitted. Plagiarism will result in immediate disqualification. Participants must bring their own laptops and necessary accessories. The decision of judges will be final and binding. Perks: Participation Certificates Winner & Runner-Up Recognition Exciting Prize Pool Mentorship & Networking Opportunities  24 Hours. Infinite Possibilities. Don''t Predict the Future. Program It.', '2026-06-16T00:00:00+05:30', '2026-07-28T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/ignisys-uem-kolkata-1699798', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699739', 'Innovex 2026', 'Innovex 2026 is a platform for creators, problem-solvers, and aspiring technologists to transform ideas into impactful solutions. Designed to encourage innovation and collaboration, Innovex brings together participants from diverse backgrounds to tackle challenges that matter. Whether you''re passionate about AI, web technologies, cybersecurity, sustainability, or social impact, Innovex provides the opportunity to build, learn, and showcase your talent on a national stage. Challenge Tracks Participants are free to choose any domain, including: Artificial Intelligence & Machine Learning Health & Well-being Education and Learning Solutions Smart Infrastructure & IoT Financial Technologies Green & Sustainable Innovation Cybersecurity and Privacy Agriculture & Rural Development Accessibility and Social Good Open Innovation Who Can Participate? Undergraduate and postgraduate students Fresh graduates and early professionals Individual participants or teams of up to 4 members Innovators from all academic disciplines Competition Journey Phase 1 &ndash; Concept Submission Teams will present their idea along with: Problem Identification Proposed Approach Technologies to be Used Expected Benefits Execution Plan Phase 2 &ndash; Product Development Selected teams will develop their solution and submit: Working Prototype Source Code Repository Documentation Project Demonstration Final Showcase Top teams will pitch their projects before in a detailed video presentation. Judging Parameters Originality and Innovation Technical Excellence Practical Impact User Experience Scalability and Future Potential Participant Benefits Digital Certificates Networking Opportunities Mentorship Sessions Project Showcase Platform Internship and Career Opportunities Exciting Rewards for Top Performers Why Innovex? Innovex is more than a competition&mdash;it''s a community that encourages experimentation, creativity, and meaningful innovation. Think Beyond Limits. Build Solutions. Shape the Future. INNOVEX 2026 &mdash; Where Ideas Evolve Into Impact.', '2026-06-15T00:00:00+05:30', '2026-07-04T01:50:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innovex-2026-jims-engineering-management-technical-campus-jemtec-greater-noida-1699739', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699721', 'Open Source Competition', 'The Elite Coders Open Source Challenge (ECSoC) is a beginner-friendly open source competition designed to help students and developers start their open source journey. Whether you''ve never made a pull request before or you''re already contributing to projects, ECSoC provides a platform to learn, collaborate, and grow. Why Participate? Learn Git & GitHub Make Your First Open Source Contribution Work on Real Projects Connect with Developers Across India Build Your Portfolio Earn Certificates & Recognition Win Swags and Exciting Rewards Who Can Participate? Students Beginners in Open Source Developers Designers Technical Writers Community Builders No prior open source experience required. How It Works Step 1: Register Sign up for ECSoC. Step 2: Join the Community Get access to projects, mentors, and resources. Step 3: Learn & Contribute Choose beginner-friendly issues and start contributing. Step 4: Submit Your Work Create pull requests and complete assigned tasks. Step 5: Get Evaluated Contributions will be reviewed based on quality, impact, and consistency. Contribution Areas Development Frontend Backend Full Stack Mobile Development AI / ML Machine Learning Data Science AI Applications Design UI/UX Design Graphics Branding Content Documentation Technical Writing Tutorials Community Outreach Marketing Community Growth Rewards Top Contributors Digital Certificates Swags & Goodies Community Recognition Internship & Collaboration Opportunities Beginner Support We don''t expect participants to know everything. ECSoC provides: Git & GitHub Guides Open Source Workshops Community Support Mentor Assistance Beginner-Friendly Issues Evaluation Criteria Quality of Contributions Consistency Project Impact Collaboration Documentation Our Mission To help thousands of students make their first open source contribution and become part of the global developer ecosystem. Learn. Contribute. Grow.', '2026-06-15T00:00:00+05:30', '2026-06-30T22:31:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/open-source-competition-elite-coders-1699721', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699516', 'Code Crackdown', 'About the Event Think you have an eye for detail? Put your testing and debugging skills to the test in the ToolsPilot Bug Hunting Challenge! Participants will explore the ToolsPilot platform and identify bugs, glitches, UI/UX issues, broken workflows, security concerns, or any unexpected behavior. Website: https://www.toolspilot.tech/ Registration Period Registration Opens: 15 June 2026 Registration Closes: 27 June 2026 Event Duration Event Starts: 15 June 2026 Event Ends: 28 June 2026 Eligibility Open to all students and professionals. Participants from any college, university, specialization, or organization can participate. Individual participation only. No prior bug-hunting or cybersecurity experience is required. Competition Format Round 1: Bug Hunting Participants will explore the ToolsPilot website and identify bugs (one or more). Bugs may include: Functional bugs UI/UX issues Broken links Workflow errors Performance issues Security vulnerabilities Browser compatibility issues Participants must submit bug reports with: Bug title Steps to reproduce Expected behavior Actual behavior Screenshots or screen recordings (if applicable) Judging Criteria Submissions will be evaluated based on: Severity of the bug Reproducibility Quality of bug report Impact on user experience Originality of findings Duplicate bug reports will be considered only for the participant who submitted them first. Rewards First Prize: Winner Certificate All participants may receive a participation certificate at the discretion of the organizers. Rules Participants must use only legal and ethical testing methods. Any activity that harms the website, servers, or user data is strictly prohibited. Do not attempt Denial-of-Service (DoS/DDoS) attacks. Do not access, modify, or delete data belonging to other users. Automated scanning tools may be used responsibly; however, activities causing excessive traffic are prohibited. Organizers reserve the right to disqualify participants for unethical behavior. The decision of the organizers will be final and binding. By participating, contestants agree that submitted bug reports may be used by ToolsPilot for platform improvement. Submission Process Participants must submit: Bug description Steps to reproduce Evidence (screenshots/videos) The submission link and reporting instructions will be shared with registered participants. Good luck and happy bug hunting!', '2026-06-15T00:00:00+05:30', '2026-06-28T12:00:00+05:30', 'Online', 'online', 'WINNER CERTIFICATE', 'https://unstop.com/hackathons/code-crackdown-amity-university-au-noida-1699516', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699311', 'No Python. No Excuses. Build AI Agents with Mastra', 'HiDevs &times; Mastra Hackathon No PPT. Just Agents. The first AI agent hackathon built exclusively for TypeScript developers. Python was never the gate. It was just the key everyone assumed you needed. For years, the AI agent ecosystem has been dominated by Python-first frameworks. If you wanted to build production-grade agents, you were expected to learn Python before writing your first workflow. Meanwhile, millions of TypeScript developers watched the agent revolution from the sidelines. That changes now. HiDevs &times; Mastra is a flagship AI agent-building hackathon designed for developers who want to build real, production-ready AI systems using TypeScript from end to end. Over multiple rounds, participants will design, architect, and ship autonomous agent systems that solve real-world problems across hiring, finance, legal intelligence, education, incident response, and open innovation. This is not a hackathon for slide decks, mockups, or AI wrappers. Every submission must be a working agent. Event Timeline: The hackathon unfolds across four key milestones, taking participants from architecture design to building and showcasing production-grade AI agents. 13 June &ndash; 19 June 2026 | Registrations Open Register through Luma, Unstop, and the HiDevs Platform. Participants gain access to resources, referral programs, and hackathon updates. 20 June 2026 | Round 1 Begins (Online) Participants receive the problem statements and begin designing their solution architecture using HiDevs Architecture Copilot. The focus of Round 1 is creating a robust agent architecture built around Mastra, Qdrant, and Enkrypt AI. Round 1 Submission Requirements : Participants must submit the following : Product Requirements Document (PRD): outlining the problem, target users, solution approach, key features, user journey, and expected outcomes. Full-Stack Architecture : Document covering agent workflows, Mastra orchestration, Qdrant memory and retrieval, Enkrypt AI evaluation layer, frontend, backend, APIs, databases, integrations, and deployment architecture. Submissions will be evaluated on architecture quality, technical feasibility, innovation, and effective integration of the mandatory technology stack. 2 July 2026 | Round 1 Results The top 300 submissions advance to Round 2. Shortlisted participants will receive feedback on their architecture and begin building their solution based on the architecture submitted in Round 1. 4 July &ndash; 11 July 2026 | Build Sprint Qualified teams will work remotely to transform their approved architecture into a fully functional AI agent using Mastra, Qdrant, and Enkrypt AI. During this phase, participants will build, test, refine, and prepare their solutions for the Grand Finale. 12 July 2026 | Grand Finale (Offline) The top 300 builders will participate in a 12-hour offline hackathon at OJone, Bengaluru, from 10:00 AM to 10:00 PM. Participants will complete final development, receive mentorship, network with fellow builders, and present their working AI agents to judges from Mastra, Qdrant, and Enkrypt AI. Projects will be evaluated on technical implementation, innovation, problem impact, agent capabilities, and effective integration of the mandatory technology stack. Winners will be announced at the conclusion of the event. Prizes, Swags & Recognition: Compete for a ₹50,000 Cash Prize Pool, exclusive sponsor swags, books, and community rewards. ₹50,000 Cash Prize for the Top 5 teams in the Final Round Exclusive Swags from Mastra, Qdrant, and Enkrypt AI Mastra Book for all participants qualifying for Round 2 Top 10 Social Media Awards &ndash; ₹2,000 reward and recognition from HiDevs & Mastra Referral Program &ndash; ₹3,000 reward pool for the Top 20 referrers Total confirmed rewards: ₹50,000 Cash Prize + Qdrant Swags + Enkrypt AI Swags + Mastra Books + Community Recognition. Mandatory Technology Stack: Every submission must integrate all three technologies as core components of the solution. These are not optional integrations or bonus points&mdash;they form the foundation of the entire hackathon experience. Mastra &mdash; Agent Orchestration Layer Mastra powers the intelligence and execution layer of your agent. It is responsible for orchestrating workflows, managing tool calls, routing memory, handling branching logic, enabling human-in-the-loop interactions, and coordinating multi-step agent behavior. Participants are expected to leverage Mastra to build agents that can reason, plan, execute, and adapt across complex workflows rather than relying on isolated prompts. Qdrant &mdash; Memory & Retrieval Layer Qdrant serves as the long-term memory system for your agent. It enables semantic search, vector storage, contextual retrieval, retrieval-augmented generation (RAG), and persistent memory across sessions. Whether you''re building a hiring copilot, a finance advisor, or an incident response system, your agent should be able to remember, retrieve, and reason over historical information to deliver context-aware experiences. Enkrypt AI &mdash; Safety & Evaluation Layer Enkrypt AI ensures that every agent remains reliable, trustworthy, and production-ready. Participants must use Enkrypt AI to evaluate outputs for hallucinations, bias, toxicity, safety violations, and other potential risks before information reaches the end user. The future of AI is not just intelligent&mdash;it must also be safe, transparent, and accountable. Hard Requirement All three technologies&mdash;Mastra, Qdrant, and Enkrypt AI&mdash;must be integrated into every submission. Any project missing even one of the required technologies will be automatically disqualified before judging begins. What You''ll Build: Participants can choose to solve one of several high-impact, real-world challenges designed around autonomous AI agents and production-grade workflows. AI Hiring Copilot: Build an end-to-end recruitment agent capable of analyzing job descriptions, ranking candidates, generating interviews, evaluating responses, and producing recruiter-ready hiring recommendations. Personal Finance & Debt Advisory Agent: Create an intelligent financial advisor that understands spending behavior, analyzes debt obligations, models future financial scenarios, and delivers personalized financial guidance. Legal Document Intelligence Agent: Develop a legal analysis system capable of understanding contracts, identifying risky clauses, answering legal questions, benchmarking against standard practices, and generating safer alternatives. Student Doubt-Solving & Learning Agent: Build a personalized AI tutor that adapts explanations to individual learning levels, tracks weak concepts over time, and provides intelligent academic support across multiple sessions. Incident Response & Post-Mortem Agent: Design an engineering copilot that can analyze logs, detect anomalies, retrieve historical incidents, recommend remediation steps, and automatically generate post-mortem reports. Open Innovation Challenge &mdash; Build Your Own Agent: Have an idea that doesn''t fit a predefined category? Build an original AI agent that solves a meaningful real-world problem using the mandatory technology stack. Across every challenge, participants will design autonomous workflows, retrieval systems, long-term memory architectures, safety evaluation pipelines, and intelligent agent experiences that resemble real production software rather than simple chatbot demos. What Makes This Different: TypeScript-first AI agent development Real production architectures instead of prompt demos Long-term memory powered by Qdrant Agent orchestration with Mastra Safety and evaluation using Enkrypt AI Industry-standard judging focused on engineering depth Direct access to engineers and mentors from the ecosystem Judging Criteria: Projects will be evaluated on: Mastra Integration Depth (25%) Qdrant Integration Quality (20%) Enkrypt AI Coverage (20%) Agent Output Quality (20%) Problem Impact & Novelty (15%) The Challenge: Build an AI-native system that can think, retrieve, remember, evaluate, and act. Not a chatbot. Not a demo. An agent. Because the future of software will be built by interconnected ecosystems of autonomous agents&mdash;and this is where those builders start. Hosted By: HiDevs is a Builder Intelligence Platform for the Agentic Era We help developers transform ideas into production-grade AI agents through personalized guidance, intelligent evaluation, continuous feedback, and contextual memory. By combining specialized AI agents with developer intelligence, HiDevs understands each builder''s goals, tracks their progress, and provides the insights needed to accelerate their journey. Through 100+ community experiences, builder initiatives, and ecosystem collaborations, HiDevs has engaged 15,000+ developers and is building the infrastructure that powers the next generation of AI builders. AIHouse is the community layer powering this ecosystem. Built for founders, researchers, engineers, students, and AI enthusiasts, AI House creates a space where people consistently learn, share, collaborate, and grow together. Through initiatives like 100 Days of AI House, community gatherings, founder conversations, knowledge-sharing sessions, and industry collaborations, AI House has built a thriving network of 15,000+ community members who are actively shaping the future of AI. More than a community, AI House is where meaningful relationships, opportunities, and ideas are created every day. Together, HiDevs and AI House are building one of the fastest-growing AI ecosystems where ideas turn into products, builders become founders, and collaborations turn into impact.', '2026-06-14T00:00:00+05:30', '2026-07-12T23:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/no-python-no-excuses-build-ai-agents-with-mastra-hidevs-1699311', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699309', 'Hack[AI]thon 2.0', 'Hack[AI]Thon 2.0 2026 - Official Event Details About the Hackathon: Hack[AI]Thon 2.0 2026 is a national-level Artificial Intelligence hackathon organized by Sphere Hive in collaboration with VRIF VTU Belagavi. The event brings together students, innovators, and aspiring AI practitioners from across India to compete in a unique Data-Centric AI Challenge. Unlike traditional AI competitions that focus on modifying model architectures, participants will improve AI performance by enhancing dataset quality through intelligent data analysis, strategic labeling, and identification of high-impact samples. Teams will utilize the 3LC.ai platform to analyze embeddings, discover edge cases, optimize training data, and improve overall model performance. The hackathon follows a two-stage competition format, beginning with an online selection round and culminating in a 24-hour offline grand finale hosted at VRIF VTU Belagavi. Eligibility: Open to undergraduate and postgraduate students from recognized institutions across India. Students from all academic disciplines and specializations are eligible to participate. Participants must possess a valid college identity card. Prior experience in Artificial Intelligence or Machine Learning is beneficial but not mandatory. Team Composition: Participation is strictly team-based. Each team must consist of 2 to 4 members. Inter-college teams are permitted. Inter-disciplinary teams are encouraged. Event Format & Venue: Competition Format: Two Rounds Round 1 - Online Selection Round Teams will participate in a virtual screening challenge designed to evaluate problem-solving ability, data analysis skills, and strategic thinking in Data-Centric AI. Round 2 - 24-Hour Offline Grand Finale Selected teams from Round 1 will advance to the final round hosted at VRIF VTU Belagavi, Karnataka. Final Round Dates: 8&ndash;9 August 2026 During the finale, teams will work on a real-world AI challenge focused on image classification and dataset improvement using the tools and workflow provided by the organizers. Competition Structure: Round 1 - Online Selection Round Conducted virtually for all registered teams. Teams will solve a Data-Centric AI challenge within the allotted time. Performance will be evaluated based on the prescribed assessment criteria. Top-performing teams will qualify for the offline finale. Round 2 - 24-Hour Offline Grand Finale Opening ceremony and challenge briefing. Official problem statement release. Continuous 24-hour hacking session. Mentor interactions and technical checkpoints. Final submission, demonstration, and presentation before the judging panel. Prize distribution and closing ceremony. Problem Statement: Participants will receive the challenge statement at the beginning of each round. Teams will be expected to: Analyze datasets and identify quality issues. Detect edge cases and impactful samples. Perform strategic data labeling and curation. Improve model performance through Data-Centric AI techniques. Demonstrate measurable improvements in accuracy and reliability. Evaluation Criteria: Projects will be assessed on: Innovation and creativity Dataset enhancement strategy Improvement in model performance Technical implementation Problem-solving approach Presentation and demonstration quality Rules & Guidelines: All work submitted in the final round must be completed during the official hackathon duration. Teams must provide accurate registration information. Plagiarism, misconduct, or unfair practices will result in immediate disqualification. Participants are expected to maintain professional and respectful conduct throughout the event. Open-source libraries and publicly available resources may be used unless otherwise specified. Participants must bring their own laptops, chargers, and necessary accessories. Internet connectivity and workspace facilities will be provided at the venue. All submissions must be completed before the official deadline announced by the organizers. The organizing committee reserves the right to amend rules, schedules, or procedures if required. All decisions made by the judges and organizers shall be final and binding. Participant Benefits: Certificates for all registered participants. Direct mentorship from industry professionals and AI experts. Networking opportunities with innovators, researchers, and builders. Sponsored goodies and partner benefits. Exposure to modern Data-Centric AI workflows and tools. Opportunity to compete for a ₹35,000 Prize Pool. Additional Information: Cafeteria facilities are available in and around the venue. Limited accommodation support may be available for eligible participants. Detailed instructions regarding the competition, venue access, and reporting procedures will be shared with shortlisted teams before the final round. Beyond Code. Into Intelligence. Hack[AI]Thon 2.0 2026 is more than a competition - it''s a platform to explore the future of Artificial Intelligence through data-driven innovation, collaboration, and problem-solving.', '2026-06-04T00:00:00+05:30', '2026-08-09T00:00:43+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/hackaithon-20-sphere-hive-kvg-college-of-engineering-sullia-1699309', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695806', 'TraceBash CTF (Capture The Flag)', 'TraceBash CTF 2026 is a 24-hour online Jeopardy-style Capture The Flag (CTF) competition designed for students, cybersecurity enthusiasts, and professionals from around the world. Whether you''re taking your first steps into cybersecurity or you''re an experienced competitor, TraceBash CTF offers an exciting opportunity to test your skills, learn new techniques, and compete against players globally. Organized by Team TraceBash, one of India''s top-ranked CTF teams, this event features a diverse set of realistic cybersecurity challenges inspired by modern attack and defense scenarios. Event Overview: Format: Team-based or Solo Participation Mode: Online Duration: 24 Hours Start Time: 26 June 2026, 3:00 PM IST End Time: 27 June 2026, 3:00 PM IST Flag Format: TBCTF{example_flag} Prize Pool: ₹5,000 Challenge Release: Two waves of challenges, with the second wave released 12 hours after the competition begins CTF Website: https://ctf.tracebash.xyz/ Discord Link: https://discord.gg/5mgXM9HcM7 Challenge Categories: Participants will encounter challenges across multiple cybersecurity domains, including: Web Security Binary Exploitation (Pwn) Reverse Engineering Cryptography Digital Forensics Open Source Intelligence (OSINT) Miscellaneous Challenges Challenges are designed to test technical knowledge, logical reasoning, creativity, and problem-solving abilities under time constraints. Platform & Community: Participants are strongly encouraged to join the Discord server, where announcements, event updates, support, and public challenge hints will be posted throughout the competition. Rules & Regulations: Participation is open worldwide. Participants may compete individually or as a team. All flag submissions must be made through the official CTF platform. Sharing flags, solutions, or challenge-specific assistance with other participants is prohibited. Attacking event infrastructure, attempting denial-of-service attacks, or abusing unintended platform vulnerabilities is strictly forbidden. Any behavior deemed unfair or against the spirit of the competition may result in penalties or disqualification. Organizers reserve the right to modify rules if required to maintain fairness and event integrity. Scoring & Ranking: Challenges use dynamic scoring. Higher difficulty challenges award more points. Challenge values decrease as more participants solve them. Teams and participants will be ranked based on their cumulative score. In the event of a tie, submission timing may be used as a deciding factor. Support: If you encounter any issues during the competition, support will be available through Discord tickets and event moderators. Technical issues, challenge outages, and platform-related concerns will be addressed as quickly as possible. Why Participate? Compete against players from around the world. Learn practical cybersecurity skills through hands-on challenges. Gain experience across multiple security domains. Win a share of the ₹5,000 prize pool. Join a growing cybersecurity community and connect with fellow enthusiasts. Sharpen your skills, challenge yourself, and prepare to capture the flags. See you on the scoreboard.', '2026-06-06T00:00:00+05:30', '2026-06-27T15:00:00+05:30', 'Online', 'online', '₹ 5,000', 'https://unstop.com/hackathons/tracebash-ctf-capture-the-flag-team-tracebash-1695806', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699053', 'Codesprint2026', 'About the Competition: CodeSprint 2026 is an exciting offline Data Structures and Algorithms (DSA) coding competition designed to test participants'' logical thinking, problem-solving abilities, and programming skills. The competition provides students with an opportunity to showcase their coding talent and compete with fellow programmers in a challenging environment. Participants will solve a set of carefully curated DSA problems ranging from easy to hard difficulty levels within the given time limit. Eligibility: Open to all students of the college. Participants must register before the registration deadline. Individual participation only. No team participation is allowed. Competition Format: Mode: Offline Duration: 90 Minutes Total Questions: 5 Difficulty Levels: Easy: 2 Questions Medium: 2 Questions Hard: 1 Question Programming Languages Allowed: C++ Java Python Rules & Guidelines: Participants must carry their College ID Card. Internet access is strictly prohibited unless permitted by organizers. Any form of plagiarism, copying, or unfair means will lead to immediate disqualification. Participants must submit their solutions before the deadline. The decision of judges and organizers will be final and binding. Late submissions will not be accepted. Participants are expected to maintain discipline throughout the event. Evaluation Criteria: Correctness of Solution &ndash; 70% Time & Space Complexity &ndash; 20% Code Readability & Optimization &ndash; 10% Prizes & Recognition: Winner Certificate Runner-Up Certificate Participation Certificate for all participants Why Participate? Improve Problem-Solving Skills Test Your DSA Knowledge Gain Competitive Coding Experience Build Your Coding Portfolio Network with Fellow Programmers Event Theme: Think Fast &bull; Code Smart &bull; Win Big CodeSprint 2026 &ndash; Where Logic Meets Innovation.', '2026-06-13T00:00:00+05:30', '2026-06-27T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/codesprint2026-technocrats-institute-of-technology-and-main-1699053', 'external', ARRAY['Coding']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699008', 'Hackathon', 'BGMI PLAYERS, ASSEMBLE!   Ready to drop, loot, survive, and dominate?   Funniche Week BGMI Championship by IIT Guwahati is now open for registrations!   ₹20,000 Prize Pool  FREE Registration Open for Everyone Squad Format (4+1) Tournament: 29 June &ndash; 5 July 2026   Prize Distribution: Champions &ndash; ₹10,000 Runner-Up &ndash; ₹6,000 Second Runner-Up &ndash; ₹4,000   Maps: Erangel Miramar Sanhok Vikendi   ️ Battle against squads from across the country and prove that your team has what it takes to claim the Chicken Dinner!   Don''t have a full squad? No worries! Solo registrations are also allowed, and teams can be formed by the organizers.       Tag your squad and get ready for the ultimate BGMI showdown!     Chicken dinner!!!!!', '2026-06-13T00:00:00+05:30', '2026-06-28T00:00:20+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/indiaruns-2026-national-innovation-challenge-veloris-1699008', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001699047', 'Agent{a}thon by Nerds Room', 'About the Event: Agent{a}thon NCR 2026 is a community-driven AI and innovation hackathon designed to bring together ambitious students, developers, builders, and aspiring entrepreneurs from across Delhi NCR and beyond. Hosted by Nerds Room, this hackathon provides a platform for participants to explore the rapidly evolving world of AI agents, automation, and intelligent systems while collaborating with like-minded innovators. Participants will work individually or in teams to build impactful solutions, experiment with emerging technologies, and transform ideas into functional prototypes. Whether you''re a beginner exploring AI for the first time, a developer building your next project, or an aspiring founder validating a startup idea, Agent{a}thon NCR offers a unique opportunity to learn, build, network, and showcase your talent within a thriving technology ecosystem. Theme: Build intelligent solutions powered by AI agents, automation, and emerging technologies that solve real-world challenges across industries and communities. Participants are encouraged to innovate in areas including but not limited to: AI Agents & Autonomous Systems Developer Tools & Productivity Education & Learning Healthcare & Wellness Climate & Sustainability FinTech & Financial Inclusion Community & Social Impact Business Automation Smart Cities & Civic Tech Open Innovation Why Participate? Build Real Projects Transform your ideas into working prototypes and gain hands-on experience with modern AI and software development tools. Learn from Industry Experts Interact with mentors, developers, startup founders, and technology professionals who can guide you throughout the hackathon journey. Expand Your Network Connect with talented students, builders, entrepreneurs, and professionals from diverse backgrounds. Showcase Your Skills Present your solution to judges, mentors, and the broader community. Gain Practical Experience Develop problem-solving, teamwork, communication, and product-building skills through an immersive innovation experience. Access Career Opportunities Demonstrate your abilities, collaborate with industry leaders, and explore future opportunities within the technology ecosystem. Who Can Participate? Agent{a}thon NCR is open to: Engineering Students Computer Science Students Developers AI & Machine Learning Enthusiasts Product Builders Technology Enthusiasts Startup Aspirants Early-Stage Entrepreneurs Designers and Innovators Participants from all academic years and experience levels are welcome. Hackathon Structure: Round 1: Registration & Idea Submission Participants register and submit their profiles, skills, and project ideas. Round 2: Project Proposal Evaluation Shortlisted participants submit a project presentation outlining the problem statement, proposed solution, implementation approach, and expected impact. Round 3: Final Build & Demo Day Selected teams build and present their solutions before a panel of judges, mentors, and community leaders. What You''ll Gain: Hands-on project-building experience Mentorship from industry professionals Exposure to AI and emerging technologies Networking opportunities with builders and founders Recognition for outstanding projects Certificates of participation Community access and future opportunities Event Details Date: 27 June 2026 Duration: 8 Hours Location: Gurugram, Delhi NCR Mode: Offline Team Size: Individual and Team Participation Allowed About Nerds Room: Nerds Room is one of India''s fastest-growing community-driven platforms empowering developers, students, and aspiring entrepreneurs through hackathons, workshops, innovation challenges, networking events, and technical learning initiatives. With a growing network of 25,000+ community members and 100+ community-led initiatives, Nerds Room is committed to fostering innovation, collaboration, and lifelong learning among the next generation of builders. Think. Create. Repeat.', '2026-06-13T00:00:00+05:30', '2026-06-27T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/agentathon-by-nerds-room-agentathon-by-nerds-room-vishveshwarya-group-of-institutions-vgi-greater-noida-uttar-1699047', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698998', 'InnovateX', 'InnovateX is a hybrid, project-based hardware product development programme for Indian students, organised by Project GRID in collaboration with the Central Manufacturing Facility (CMF), IIT Delhi. The defining focus of InnovateX is product development, not one-off demos. Every accepted entry must be a hardware product that solves a specific problem for a defined user, with a clear path from a working prototype to a unit that could reach more users. At the pitch stage and again at the final BOM review, participants must address scalability directly: what the product looks like at 100 or 1,000 units, where the bill-of-materials cost sits at volume, and which parts are fragile, hand-tuned, or expensive today and would need to be redesigned for production. Polished answers are not expected, but participants must have thought through these questions and be able to defend them. Originality is valued, but novelty alone is not the gate; the gate is whether the participant thinks like a product builder. Selected participants design and build an original hardware product over roughly three months. GRID funds the bill of materials and reimburses approved purchases against receipts, with each line item reviewed against the product''s scalability story. There is no fixed cap on the BOM. Programme structure (movement between phases depends on GRID approval): Phase 1 - Pitch: Outline the idea, core problem, user, rough materials list, build method, scaling plan, and past work. Phase 2 - Design: Develop the 3D model, schematic, and PCB design; record timelapses; submit a complete materials list for review. Phase 3 - BOM Review and Procurement: GRID reviews every item against the scale story; participants order and are reimbursed for verified purchases. Phase 4 - Build: Assemble, debug, and finalise the build, with required timelapses and optional CMF facility access and mentor review on request. Phase 5 - Exhibition: Final products are exhibited at IIT Delhi before senior figures from government, IIT Delhi leadership, and industry. Eligibility and requirements: Open only to Indian students. InnovateX is a solo programme; team entries are not accepted.  Only 30 participants are shortlisted from across India. Projects must be hardware-focused; software and CS components are welcome only where they support the hardware build. Each project must be framed as a product with a defined problem, user, and form factor, and must address how it could scale beyond the single unit. The bill of materials must be justified line by line and kept lean; each line is reviewed and approved by GRID before procurement. Mentorship philosophy: Mentors review work when students ask. They identify mistakes, suggest directions, and point to references, but they do not design the project or walk students through the build step by step. The aim is to produce students who can read a datasheet, recover from a failed print, think like a product builder, and finish a hardware build under their own steam.', '2026-06-13T00:00:00+05:30', '2026-06-30T20:19:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/innovatex-project-grid-1698998', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698930', 'Forge 2 - 1st Edition', 'About the Event: Forge 02 Edition 01 is NMG Labs'' flagship offline Multi-Agent AI Development Sprint, designed for ambitious developers who want to build production-grade AI systems using autonomous agents, modern LLM workflows, and real-world software engineering practices. Unlike traditional hackathons, Forge Sprint 02 challenges participants to build intelligent multi-agent systems where AI agents collaborate through Slack, orchestrate tasks, write code, validate outputs, and ship production-ready solutions within a limited time. This edition is powered by Hermes Agent &times; OpenClaw and brings together some of the country''s most promising builders for an intensive day of learning, building, and competing. Sponsored & Supported By: Forge 02 Edition 01 is proudly sponsored by EastRouter. The event is backed by a growing ecosystem of technology companies, AI startups, and industry partners committed to advancing the next generation of AI builders. Why Participate?: Build a real-world Multi-Agent AI system. Learn production-ready AI workflows used by modern engineering teams. Gain hands-on experience with Hermes Agent, OpenClaw, Slack orchestration, GitHub, and modern AI tooling. Work on a live business challenge under real-world constraints. Showcase your skills before experienced engineers and industry mentors. Network with talented builders from top colleges across India. Gain exposure to leading technology companies and ecosystem partners. Unlock internship and career opportunities at NMG Labs and partner organizations. Event Details: Date: 27 June 2026 Venue: NMG Labs 404, 4th Floor, Global Foyer Mall Golf Course Road, Near Rapid Metro Sector 42-43 Gurugram Mode: Offline Participation Type: Individual Eligibility: B.Tech students (3rd & 4th Year) PG students Recent graduates (within 12 months) Passion for AI, software engineering, and innovation Basic programming knowledge is recommended Participation in previous Forge editions is not required. Sprint Theme: Participants will build a Multi-Agent AI System using: Hermes Agent (Orchestrator) OpenClaw (Coding Agent) Slack GitHub Modern LLMs and AI tooling The challenge statement will be revealed on Sprint Day. Rewards & Opportunities: Champion (1st Prize) &ndash; Cash Prize (To Be Announced) Runner-Up (2nd Prize) &ndash; Cash Prize (To Be Announced) 3rd Place &ndash; Cash Prize (To Be Announced) Additional Benefits: Certificate of Participation NMG Labs Skool Membership Internship opportunities based on performance Priority selection for Forge 03 Opportunity to work on live AI products Learn cutting-edge Multi-Agent AI Development. Hands-on exposure to production AI engineering workflows. Build alongside some of India''s most promising student developers. Industry networking opportunities. Access to the Forge Builder Community. Priority consideration for future NMG Labs events. What to Bring: Personal Laptop Charger Valid College/Government ID Headphones (Recommended) Lunch will be provided by NMG Labs. Selection Process: Registration &rarr; Application Review &rarr; Shortlisting &rarr; Offline Sprint Important Note: This is a highly selective, builder-focused event. Shortlisted participants will receive: Builder Handbook Setup Guide Pre-Sprint Learning Resources Mandatory Prerequisites Event Logistics Participants are expected to arrive with all required software installed and ready to build.', '2026-06-13T00:00:00+05:30', '2026-06-24T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/forge-2-1st-edition-nmg-technologies-1698930', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698904', 'Build.IT ''26', '​Welcome to Build.IT &ndash; the ultimate 48-hour hackathon sprint where code, caffeine, and chaos collide. Coders, designers, storytellers, and makers unite to build bold, original projects &mdash; fast. ​Form a squad of 1 to 4 hackers and get your prompt at kickoff. Then it''s go-time: code, design, and deploy your idea before the clock runs out. Submissions must include your GitHub repo, a short demo video, and a write-up explaining what you built.  Use of AI for help is allowed &ndash; you can use tools like ChatGPT or Copilot for brainstorming, debugging, or clarifying concepts. However, using AI to generate core parts of your project (like major portions of code, designs, or written content) is not allowed. The goal is to showcase your team&rsquo;s creativity and skills, not AI-generated work. Registrations and Updates: Discord: Join for Discord Note: Every teammate needs to register individually on the above link and add the same team name Event Guide(further detail): Updates ​All announcements live on Discord&mdash; so don&rsquo;t miss a beat. ​Whether you&rsquo;re in it for the glory, the grind, or the prizes, Build.IT is where ideas turn real. Do a bit. Try a bit. Win a byte. Judging criteria: Creativity Innovation Prototype Originality  General Rules: The hackathon begins on 15th July 2026 at 12:00 am IST. The prompt will be released at the start of the event. Teams will have 48 hours to build a project based on the prompt. Each team must submit: Project title Brief description Demo or video walkthrough Repository link Submissions must be made on the official platform by 17th July at 12:00 am IST. Only original work will be accepted; plagiarism will lead to instant disqualification. All participants must register in advance using the official registration link. Discord will be used for all event communications. Judges'' decisions are final. Please refrain from messaging the event heads about the decision. Results: Results will be announced on Saturday, 18th July 2026', '2026-06-14T14:01:10+05:30', '2026-07-17T00:00:20+05:30', 'Online', 'online', 'A trophy and certificates of appreciation, 1 XYZ domain per person, 2 Art of problem solving coupons', 'https://unstop.com/hackathons/buildit-26-bal-bharati-public-school-pitampura-1698904', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697006', 'Mission Y4 Prakasam Police Hackathon 2026', 'Prakasam Police Hackathon 2026 &ndash; Mission Y4 National-Level Online Hackathon Opportunity Description: Prakasam Police Hackathon 2026 &ndash; Mission Y4 is a National-Level Online Hackathon organized by Prakasam District Police in association with Techverza (Sraventix Technologies LLP). The hackathon brings together students, innovators, developers, startups, researchers, and technology professionals to create innovative solutions for real-world public safety and policing challenges using Artificial Intelligence, Data Analytics, Cybersecurity, Automation, and Emerging Technologies. The objective is to encourage technology-driven solutions that can improve public safety, strengthen law enforcement capabilities, enhance citizen services, and contribute towards building a smarter and safer society. Hackathon Theme: "Secure Tomorrow with Next-Generation AI" Join us in developing innovative solutions that strengthen public safety, improve digital security, and create meaningful social impact. Innovate. Secure. Serve. Eligibility: The hackathon is open to: B.Tech Students M.Tech Students MCA Students B.Sc Students Diploma Students IT Professionals Startups Innovators Technology Enthusiasts Team Formation & Registration: Team participation is mandatory. Each team must consist of exactly 3 members. Registration is completely free. One member can register on behalf of the team. Registration must be completed through the official website before the deadline. Registration Deadline: 25 June 2026 11:59 PM IST No registrations will be accepted after the deadline. Rewards & Prizes: 1st Prize: ₹5,000 2nd Prize: ₹2,000 3rd Prize: ₹1,000 Surprise Prize: To be revealed during the Grand Finale Important Timeline: Registration Deadline: 25 June 2026 Project Submission Deadline: 28 June 2026 (11:59 PM IST) Shortlisted Teams Announcement: 30 June 2026 Grand Finale & Top 10 Presentations: 12 July 2026 Grand Finale Presentation: The Top 10 shortlisted teams will be invited to present their projects before the: Superintendent of Police (SP) Prakasam District Police Venue: SP Office, Ongole, Prakasam District, Andhra Pradesh Date: 12 July 2026 The final evaluation and winner selection will be based on innovation, technical implementation, impact, scalability, and presentation quality. Official Problem Statements: Participants may select any one of the following challenge statements and develop an innovative technology solution. Challenge 01 &ndash; AI-Based Social Media Fake Profile & Identity DetectionDifficulty: Medium Focus Areas: Fake Account Detection Identity Verification Deepfake Profile Detection Social Media Fraud Prevention Digital Trust Scoring Challenge 02 &ndash; Smart Vehicle Number Plate Verification SystemDifficulty: Easy Focus Areas: Automatic Number Plate Recognition (ANPR) Stolen Vehicle Detection Fake Registration Identification Traffic Enforcement Automation Challenge 03 &ndash; AI-Powered Crime Detection in Crowded Public AreasDifficulty: Hard Focus Areas: Crowd Anomaly Detection Behavioral Analytics Real-Time Alerts Video Intelligence Challenge 04 &ndash; Criminal Investigation & Suspect TrackingDifficulty: Hard Focus Areas: Suspect Tracking Criminal Intelligence Dashboards Investigation Support Systems Pattern Analysis Challenge 05 &ndash; Cybercrime Detection & Digital FraudDifficulty: Medium Focus Areas: Fraud Detection Scam Identification Cyber Threat Intelligence Transaction Monitoring Phishing Detection Challenge 06 &ndash; Women, Child & Senior Citizen SafetyDifficulty: Medium Focus Areas: SOS Systems Safety Monitoring Emergency Assistance Location-Based Protection Risk Prediction Challenge 07 &ndash; Smart Surveillance & Space MonitoringDifficulty: Hard Focus Areas: Smart City Surveillance AI CCTV Analytics Incident Detection Restricted Area Monitoring Challenge 08 &ndash; Crowd Management & Riot PreventionDifficulty: Expert Focus Areas: Crowd Density Analysis Riot Prediction Event Monitoring Public Gathering Management Challenge 09 &ndash; Traffic Management & Road SafetyDifficulty: Easy Focus Areas: Smart Traffic Control Accident Prediction Traffic Violation Detection Route Optimization Challenge 10 &ndash; Emergency Response & Police DispatchDifficulty: Medium Focus Areas: Dispatch Optimization Emergency Routing Resource Allocation Incident Prioritization Challenge 11 &ndash; Digital Evidence & Investigation AutomationDifficulty: Hard Focus Areas: Evidence Categorization Digital Forensics Support Case Management Automation Investigation Workflow Intelligence Challenge 12 &ndash; Organized Crime & Narcotics IntelligenceDifficulty: Expert Focus Areas: Criminal Network Analysis Intelligence Mapping Pattern Detection Risk Assessment Systems Challenge 13 &ndash; Public Safety & Threat DetectionDifficulty: Medium Focus Areas: Threat Detection Suspicious Activity Monitoring Public Risk Assessment Alert Generation Safety Analytics Project Submission Guidelines: Submission Deadline: 28 June 2026 11:59 PM IST Late submissions will not be accepted. Mandatory Requirement: All team members must join the Official Hackathon Community. Only teams whose members have joined the community will receive access to the Project Submission Form. Required Submission Materials: Project Presentation (PPT) Include: Problem Statement Proposed Solution Technology Stack System Architecture Implementation Details Key Features Impact Future Scope Project Demo Video (2&ndash;3 Minutes) Demonstrate: Project Overview Working Prototype Key Features Innovation Solution Impact Public GitHub Repository Requirements: Complete Source Code Documentation Included Repository Must Be Public Working GitHub Link Private repositories will not be evaluated. Submission Process: Join the Official Hackathon Community Receive Submission Form Access Upload PPT Submit Demo Video Submit Public GitHub Repository Link Complete Submission Before Deadline Evaluation Criteria: Projects will be evaluated based on: Innovation & Creativity Technical Excellence Relevance to Problem Statement Practical Impact Scalability Project Demonstration Code Quality & Documentation Presentation Quality Important Rules: Team size must be exactly 3 members. Every member must join the official community. GitHub repositories must be public. Plagiarism or copied projects will lead to immediate disqualification. Organizers and judges reserve the right to make final decisions. Late submissions will not be accepted. Organized By: Prakasam District Police Technology Partner: Techverza (Sraventix Technologies LLP) Prakasam Police Hackathon 2026 &ndash; Mission Y4 Building Technology for a Safer Tomorrow Free Registration National-Level Online Hackathon Open to Students, Startups & Professionals Top 10 Teams Present at Sp Office, Ongole', '2026-06-09T00:00:00+05:30', '2026-06-22T22:55:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/mission-y4-prakasam-police-hackathon-2026-sraventix-technologies-llp-1697006', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698744', 'Null Origin - 24 Hour CTF Challenge', 'About the Event: Null Origin is a Capture The Flag (CTF) competition designed to challenge and enhance participants'' cybersecurity skills through real-world scenarios and hands-on problem-solving. Participants will face challenges across multiple domains, testing their technical expertise, analytical thinking, and creativity. Whether you''re a beginner exploring cybersecurity or an experienced hacker looking for a challenge, Null Origin provides a competitive platform to learn, compete, and grow. Challenge Categories: Web Security Cryptography Reverse Engineering Digital Forensics OSINT Binary Exploitation Miscellaneous Challenges Event Details: Mode: Online Duration: 24 Hours Team Size: 1-4 Members ( Including Team Leader ) Date: Will be revealed soon. Eligibility: Open to students, professionals, and cybersecurity enthusiasts from all backgrounds. Rules: Participants must follow ethical hacking practices. Attacking the competition infrastructure is strictly prohibited. Flag sharing between teams is not allowed. Any form of unfair advantage may lead to disqualification. Organizers'' decisions will be final and binding. Rewards:  It will be announced soon. We''ve got something really special for you! For queries and support: Official E-mail : nullorigin@cyberhx.com Ready to Trace the Unknown? Join Null Origin and prove your skills where every flag tells a story and every challenge reveals a new attack surface.', '2026-06-12T00:00:00+05:30', '2026-09-18T22:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/null-origin-24-hour-ctf-challenge-cyber-hx-1698744', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698423', 'Agentic Arena : Build the Future with AI Agents', 'Agentic Arena 2026 is a national-level AI innovation challenge designed to bring together students, developers, and technology enthusiasts to explore the power of autonomous AI systems. Participants will design and build intelligent AI agents capable of solving real-world problems across domains such as education, healthcare, productivity, research, customer support, sustainability, and business automation. The challenge encourages innovators to move beyond traditional chatbots and create systems that can reason, plan, utilize tools, and execute tasks autonomously. Whether you are leveraging Large Language Models (LLMs), workflow automation platforms, APIs, multi-agent architectures, or custom AI solutions, this competition provides an opportunity to showcase your creativity, technical expertise, and problem-solving abilities. What Is An Agentic AI? Agentic AI refers to intelligent systems that can independently analyze tasks, make decisions, use tools, and perform actions to achieve specific goals. Unlike conventional AI models that only respond to prompts, agentic systems can plan, reason, and execute multi-step workflows with minimal human intervention. Themes Participants may choose any one of the following themes: Education & Learning: Develop AI agents that enhance learning experiences, provide personalized guidance, assist students, and improve educational accessibility. Healthcare & Wellness: Create intelligent agents that support healthcare awareness, symptom assistance, wellness tracking, and healthcare accessibility. Business & Productivity: Build AI agents that automate workflows, streamline operations, improve decision-making, and enhance workplace productivity. Research & Knowledge Management: Develop agents capable of gathering information, analyzing data, generating reports, and assisting in research activities. Open Innovation: Participants are free to identify and solve any real-world problem using autonomous AI agents beyond the listed themes. Who Can Participate? Undergraduate Students Postgraduate Students AI & ML Enthusiasts Developers & Innovators Individual Participants or Teams Round 1: Agent Blueprint Submission In the first round, participants are required to conceptualize and design an AI Agent that addresses a real-world problem within one of the specified themes. Submission Requirements Problem Statement Proposed Solution Agent Architecture / Workflow Diagram (Optional) Tools, Frameworks, and Technologies to be Used Expected Inputs and Outputs PPT/PDF Submission (Maximum 6 Slides) Evaluation Criteria Innovation & Creativity Problem-Solving Approach Technical Feasibility Clarity of Design Potential Real-World Impact Shortlisted teams will advance to Round 2. Round 2: Agent Implementation & Demo Shortlisted participants must build and demonstrate a working prototype of their proposed AI Agent. Participants may use any suitable technology stack, frameworks, APIs, automation platforms, or AI models to implement their solution. Submission Requirements Working AI Agent Prototype Source Code Repository (GitHub) Demonstration Video (2&ndash;3 Minutes) Project Documentation / README Architecture Diagram Optional Submissions Live Deployment Link n8n Workflow Export Langflow / Flowise Workflow Files API Documentation Evaluation Criteria Functionality & Performance Agent Autonomy & Intelligence Innovation & Technical Complexity User Experience & Usability Documentation & Demonstration Quality Allowed Technologies Participants are free to use any technology stack. Some examples include: OpenAI Gemini Claude n8n LangChain LangGraph Flowise Langflow CrewAI AutoGen Python JavaScript APIs & Automation Platforms Custom AI Solutions Why Participate? Showcase your AI and automation skills. Gain hands-on experience in agentic system design. Build an industry-relevant portfolio project. Compete with talented innovators from across the country. Receive certificates and exciting rewards. Demonstrate your ability to create real-world AI solutions. Note: Live presentations or pitching sessions are not required. All evaluations will be conducted through the submitted documentation, source code repository, architecture design, and demonstration video. Join the Arena The future belongs to intelligent systems that can think, reason, and act. Agentic Arena 2026 invites you to push the boundaries of innovation and build AI agents capable of transforming the way people work, learn, and solve problems. Are you ready to build the next generation of AI agents? Community & Updates All important announcements, updates, deadlines, and participant communications will be shared through the official community group. Join the community here: https://chat.whatsapp.com/KMZh9zQe0gNF4Jdsiozp7h Participants are strongly encouraged to join the community after registration to stay updated throughout the competition.', '2026-06-13T00:00:00+05:30', '2026-06-28T00:00:00+05:30', 'Online', 'online', '₹ 2,000', 'https://unstop.com/hackathons/agentic-arena-build-the-future-with-ai-agents-techverse-solutions-1698423', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001693803', 'OSDHack 2026', 'OSDHack 2026 Build AI that runs closer to the user, faster, lighter, more private, and open source. OSDHack 2026 is an online open-source hackathon by Open Source Developers Community (OSDC), built around the theme On Device AI. Your challenge: build something where the core AI feature runs locally on a phone, laptop, desktop, browser, edge device, or embedded system. Think offline-first AI, privacy-friendly tools, browser-based AI, lightweight local models, edge AI, embedded AI, and creative open-source projects that do not depend fully on cloud AI APIs for the main AI functionality. Join the official Discord server for announcements, resources, mini-event updates, and support:https://discord.gg/qNcWcJXyd Our Sponsors Theme: On Device AI Your project should focus on AI that runs locally. You can build around: Local AI models Browser-based AI Mobile on-device AI Desktop AI tools Edge or embedded AI Offline-first AI apps Privacy-focused AI utilities Lightweight local inference Cloud services are allowed for support features like hosting, authentication, storage, databases, or deployment. The main AI feature, however, should run on-device, locally, in-browser, on edge, or on embedded hardware. In short: cloud support is fine, but the AI magic should happen locally. Timeline Hackathon Starts: 10 July 2026, 6:00 PM ISTHackathon Ends: 15 July 2026, 6:00 PM ISTFinal Submission Deadline: 15 July 2026, 6:00 PM IST What to Submit Submit your project on Unstop before the deadline. Your submission should clearly show: What you built Why it matters How it works How it uses On Device AI How others can run or try it Your repository should include: Source code Clear README OSI-compliant open-source license Setup or usage instructions Demo video link Screenshots You may use GitHub, GitLab, Codeberg, Bitbucket, or any other public Git hosting platform. Mini-Events OSDHack 2026 will also have optional mini-events: CTF Speed Typing CodeBattleships Mini-events are separate from the main hackathon and are open to all. Rules, schedules, and participation details will be shared on Discord:https://discord.gg/qNcWcJXyd Basic Rules To keep things fair and fun: Build around On Device AI Build during the official hackathon period Only commits before 15 July 2026, 6:00 PM IST will be judged Keep your project open source Use an OSI-compliant license Keep your repository public at submission time Respect third-party licenses and give attribution where needed Do not submit copied, plagiarized, harmful, or unsafe projects Detailed rules, FAQs, judging flow, and resources will be shared through official communication channels. Stay Connected Join the official Discord server for: Announcements Support Resources Deadline reminders Mini-event updates Community interaction Discord link: https://discord.gg/qNcWcJXyd Final Note Build something useful. Keep it open. Try something new. Have fun exploring On Device AI.', '2026-06-08T00:00:00+05:30', '2026-07-15T18:00:00+05:30', 'Online', 'online', '₹ 7,000', 'https://unstop.com/hackathons/osdhack-2026-open-source-developers-communityosdc-1693803', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001698293', 'Statify 2.0 - GenAI Bootcamp', 'STATIFY 2.0 is a bootcamp and hackathon organized by FEBS, focused on Generative AI, Agentic AI, and Innovation. The program combines expert-led learning sessions with a competitive Gen AI Hackathon, providing participants an opportunity to learn, build, collaborate, and showcase their skills. "Participation in the bootcamp is entirely free of charge." Event Highlights Industry expert guest sessions Learning resources and guided content Networking opportunities with peers Generative AI Hackathon Skill showcase and competitive learning experience Event Structure 3-Week Learning Phase 1-Week Generative AI Hackathon Learning Phase Requirements Participation in the hackathon is contingent upon attending all weekly learning sessions. Each week includes: Industry Expert Talks Curated Learning Resources Mandatory Quizzes and Assessments Hackathon Specifications Theme: Generative AI Team Size: Up to 4 members Eligibility: Open to participants across India Discord Account: Mandatory for all participants.                                                             ( join the discord community:-https://discord.gg/ymzPmVdg) Important Note Attending the bootcamp sessions is mandatory to participate in the hackathon. Event Date 20th June 2026 &ndash; Bootcamp commencement', '2026-06-11T00:00:00+05:30', '2026-06-18T23:59:00+05:30', 'Online', 'online', '₹ 4,000', 'https://unstop.com/hackathons/statify-20-the-data-science-bootcamp-indian-institute-of-technology-bhubaneswar-1698293', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696915', 'Build With Bharat', 'Build With Bharat 2026 | National Level Hackathon Build With Bharat 2026 is a National Level Hackathon organized by CodeVerse Community, bringing together innovators, developers, designers, and problem-solvers from across India to build impactful solutions for real-world challenges. This hackathon is designed to encourage innovation, collaboration, and technical excellence while providing participants with an opportunity to showcase their skills, network with industry professionals, and compete for exciting rewards. Description: A presentation template will be provided by the organizing team before the event. For now, participants may upload a PPT based on any project idea or concept for registration purposes. Final submission guidelines and the official presentation format will be shared with all shortlisted participants through the official communication channels before the hackathon. Note: The final PPT format and submission requirements will be communicated later by the CodeVerse Community team. Participants are advised to join the official community group for all updates. communication group link- https://chat.whatsapp.com/CQQzfd5AbG2D3Y9EuNdbCj?s=cl&p=i&ilr=4 Event Details: Event Name: Build With Bharat 2026 Organizing Community: CodeVerse Community Date: 01 August 2026 Duration: 8 Hours Mode: Offline Food for All the Participants Venue: Microsoft office Gurugram, Haryana Participation Level: National Team Size: 1&ndash;5 Members Eligibility: Open to all undergraduate and postgraduate students across India. Participants from any branch, specialization, or academic background can apply. Inter-college teams are allowed. Inter-specialization teams are allowed. Participants must register before the registration deadline. Hackathon Format: Phase 1: Registration Participants must register through the official registration portal. Phase 2: Team Formation Participants may participate individually or form teams of up to 4 members. Phase 3: Hackathon Day Teams will work on innovative solutions during the 8-hour hackathon. Phase 4: Project Submission Teams must submit their final project before the submission deadline announced during the event. Phase 5: Evaluation & Results Projects will be evaluated by industry experts and mentors based on predefined judging criteria. Judging Criteria: Innovation & Creativity Problem-Solving Approach Technical Implementation User Experience & Design Scalability & Impact Presentation & Demonstration Rules & Guidelines: Teams can consist of a maximum of 5 members. Inter-college teams are permitted. Inter-specialization teams are permitted. All work must be completed during the hackathon duration. Participants must maintain ethical conduct throughout the event. Any form of plagiarism or copyright infringement may lead to disqualification. The organizing team reserves the right to modify rules if necessary. Judges'' decisions will be final and binding. Participants are responsible for bringing their own laptops and required accessories. Internet access and other event-related facilities will be communicated before the event. Communication: For announcements, updates, venue details, problem statements, and other important information, participants are requested to join the official community group:', '2026-06-09T00:00:00+05:30', '2026-08-01T17:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/build-with-bharat-codeverse-1696915', 'external', ARRAY['Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695049', 'HackNexus''26', 'About HackNexus''26: HackNexus''26 is a national-level online hackathon designed to bring together innovative minds from colleges across the country to solve real-world challenges through technology. Whether you''re a developer, designer, innovator, or entrepreneur, HackNexus''26 provides the perfect platform to showcase your skills, collaborate with teammates, and build impactful solutions. With most students on their semester break, HackNexus''26 is structured as a fully online event, allowing participants to learn, build, and compete from anywhere. The hackathon focuses on innovation, problem-solving, technical excellence, and real-world impact. Important Dates: Registration Opens: Live NowLink : https://forms.gle/JWYh9JBu1kBfRBzbA Registration Deadline: 15 July 2026 Round 1 Submission Opens: 10 July 2026 Round 1 Submission Deadline: 20 July 2026 Round 2 and 3 will be announced after these rounds. Registration Fee : Rs. 49/memberRegistration link :  https://forms.gle/JWYh9JBu1kBfRBzbA Check Problem Statements: https://hacknexus.droidecks.sbs/ Eligibility: Open to all college and university students. Participants can register as a team (as per event guidelines). Interdisciplinary teams are encouraged. Hackathon Structure: HackNexus''26 will consist of three competitive rounds. Round 1: PPT & Abstract Submission (Elimination Round) Participants must choose a problem statement from the list of problem statements provided by the organizers and submit: Submission Requirements: Project Abstract Presentation (PPT) PPT Guidelines: There is no predefined template from the organizers. Teams are free to design their presentation creatively. The PPT should contain a maximum of 8&ndash;9 slides covering: Problem Statement Proposed Solution Technical Implementation Approach System/Architecture Diagram Expected Impact Business Model / Scalability Team Information (optional) Conclusion Evaluation Criteria: Problem Understanding Innovation & Creativity Technical Feasibility Impact Potential Presentation Quality Selected teams will advance to the next phase. Round 2: Build Phase Teams shortlisted from Round 1 will develop and implement their proposed solution. Required Deliverables: Source Code Repository (GitHub/GitLab/Bitbucket) Working Project Deployment/Hosting Link Demo Video (Preferred duration: 4&ndash;5 minutes) Project Documentation Impact Statement highlighting the significance of the solution Evaluation Criteria: Technical Implementation Functionality Innovation User Experience Scalability Real-World Impact Documentation Quality Round 3: Final Jury Presentation & Q&A The top-performing teams with exceptional solutions will be invited to the final evaluation round. Format: One-to-one interaction with judges via Google Meet or Zoom Live project demonstration Technical discussion Question & Answer session Evaluation Criteria: Depth of Technical Knowledge Solution Effectiveness Problem-Solving Approach Innovation & Uniqueness Presentation & Communication Skills Impact and Future Scope Why Participate? Compete with talented innovators from across the country. Work on real-world problem statements. Enhance your portfolio with a complete project. Receive recognition from industry and academic experts. Gain valuable experience in ideation, development, and pitching. Ready to Build the Future? Join HackNexus''26, transform your ideas into impactful solutions, and compete with some of the brightest student innovators across the nation. Register now and start your innovation journey!', '2026-06-04T00:00:00+05:30', '2026-07-15T00:00:00+05:30', 'Online', 'online', '₹ 1,00,000', 'https://unstop.com/hackathons/hacknexus26-droidecks-1695049', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001695186', '#include 1.0', 'About the Event: AWS Student Builder Group (AWS SBG) Hackathon 2026 is a technology innovation challenge designed to encourage students to build impactful solutions using Cloud Computing, Artificial Intelligence, Machine Learning, Data Analytics, and emerging technologies. Participants will collaborate, innovate, and develop real-world solutions to address industry and societal challenges. Eligibility: Open to undergraduate and postgraduate students from all colleges and universities. Students from any department or specialization are eligible to participate. Inter-specialization teams are allowed. Theme: Good Health and Well Being (SDG-3) Quality Education (SDG-4) Sustainable Cities and Communities (SDG-11) Zero Hunger and Sustainable Agriculture(SDG-2) Open Innovation Competition Format: Round 1: Idea Submission Teams submit a problem statement and proposed solution. Round 2: Prototype Development Shortlisted teams develop a working prototype. Teams may use AWS services and other approved technologies. Round 3: Final Presentation & Demo Teams present their solution before the judging panel. Evaluation Criteria: Innovation and Creativity Technical Implementation Feasibility and Scalability User Experience Business/Social Impact Presentation and Demonstration Rules & Guidelines: All submissions must be original work. Plagiarism will result in immediate disqualification. Teams must register before the specified deadline. Participants must adhere to the code of conduct throughout the event. Use of open-source resources is permitted with proper attribution. Organizers reserve the right to modify schedules and rules if required. Decisions made by judges will be final and binding. Teams must submit all deliverables before the deadline. Any unethical, offensive, or inappropriate content will lead to disqualification. Multiple submissions by the same team are not permitted unless explicitly allowed. Deliverables: Project Source Code Presentation Deck (PPT/PDF) Project Documentation Demo Video (if required) Deployment Link (if applicable) Rewards & Benefits: E- Certificates for all participants. Exciting prizes for winners. ( 30 K + Cash Prizes and Swags) Networking opportunities with industry experts. Mentorship from AWS Community Leaders and professionals. Recognition through AWS Student Builder Group community channels. Contact: For queries regarding registration, participation, or event guidelines, participants may contact the organizing committee through the official AWS Student Builder Group communication channels.', '2026-06-05T00:00:00+05:30', '2026-07-25T18:01:00+05:30', 'Online', 'online', '₹ 30,000', 'https://unstop.com/hackathons/include-10-aws-students-builder-groups-smvec-1695186', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697898', 'Hackfluence 2026', 'Hackfluence 2026 is a national-level online innovation challenge for Engineering and B-School students, jointly organized by CodeBenders and Dropp. The hackathon brings together innovators, creators, developers, marketers, and entrepreneurs to solve real-world challenges in AI, creator economy, digital marketing, social commerce, creator monetization, and brand&ndash;creator collaborations. Whether you''re passionate about building AI-powered tools, solving creator challenges, improving influencer marketing, or reimagining the future of digital engagement, Hackfluence 2026 is your opportunity to turn ideas into impactful solutions. Themes: Artificial Intelligence (AI) for Creator tools  Creator Economy Digital Marketing Social Commerce Brand&ndash;Creator Collaboration Creator Growth & Monetization Influencer Discovery & Campaign Management Solutions for Challenges Faced by Creators and Brands Hackathon Tracks: 1. Engineering Track: Round 1: Idea / PPT Submission (17th - 18th June) Teams submit their problem statement, solution, business model, and impact presentation. Round 2: Mentorship & Refinement (19th June)Selected teams receive mentorship and feedback to refine their ideas and execution plans. Round 3: Grand Finale &ndash; Prototype Presentation (21st June)Teams present their working prototype, validation, business potential, and overall solution. 2. B-School Track: Round 1: Idea / PPT Submission (17th - 18th June)Teams submit their problem statement, solution, business model, and impact presentation. Round 2: Grand Finale - Business Solution Presentation (21st June)Teams will present their problem statement, solution, business model, go-to-market strategy, and overall impact. Awards & Recognition: Total Prize Pool: ₹30,000 1st Prize: ₹10,000 Cash Prize 2nd Prize: ₹7,000 Cash Prize 3rd Prize: ₹5,000 Cash Prize 4th Prize: ₹3,000 Cash Prize 5th Prize: ₹1,000 Cash Prize 6th & 7th Position: Exclusive Goodies & Swags Internship Opportunity: The best-performing team will receive an internship opportunity. Certificates for all finalists and recognition across the CodeBenders &times; Dropp community. Why Participate? Solve real-world industry problems Get mentorship from industry experts Build innovative AI-powered solutions Network with creators, founders, and students nationwide Win exciting prizes, certificates, and recognition Just Dropp It.CodeBenders &times; Dropphackathons.ondropp.app Join the official WhatsApp group for queries and updates: https://chat.whatsapp.com/I1dVTS6gnV45kuPyxlnIKP', '2026-06-10T00:00:00+05:30', '2026-06-21T23:59:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/hackfluence-2026-igdtuw-delhi-1697898', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697951', 'TechSpark Hackathon 2026', 'About the Opportunity: Embark on a thrilling journey at the TechSpark Hackathon 2026, proudly presented by Prakash Vidya Mandir Inter College, Kanpur, Uttar Pradesh. This is your chance to dive into the dynamic world of technology through an engaging online coding challenge designed to ignite your problem-solving skills. As an individual participant, you will have the opportunity to showcase your coding prowess and innovative thinking in a virtual environment. This hackathon is a platform to explore your technical capabilities and contribute to the exciting field of technology. Eligibility and Registration: This opportunity is open to individual participants. Competition Structure: The structure for this online coding challenge is as follows: There are no competition stages defined for this event. Join the TechSpark Hackathon 2026 and showcase your coding talent!', '2026-06-11T00:00:00+05:30', '2026-06-25T00:00:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/techspark-hackathon-2026-prakash-vidya-mandir-inter-college-kanpur-uttar-pradesh-1697951', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697660', 'Stellan AI Buildathon 2026', 'About the Hackathon: The Stellan AI Buildathon 2026 is a national-level online hackathon designed for students, developers, innovators, and aspiring entrepreneurs who want to build the next generation of AI-powered products. Participants will have the opportunity to solve real-world challenges using Artificial Intelligence, Automation, No-Code Tools, AI Agents, and Emerging Technologies while competing for scholarships, mentorship, internships, and exclusive opportunities. Whether you''re a beginner exploring AI or an experienced builder creating innovative solutions, this hackathon provides the perfect platform to learn, build, and showcase your skills. Theme: Build the Future with AI Create solutions that leverage AI to solve problems in: Education Healthcare Business & Productivity Finance Sustainability Smart Cities Agriculture Creator Economy Student Life Social Impact Eligibility: Undergraduate Students Postgraduate Students Recent Graduates Individual Participants Teams of up to 4 Members Participants from all academic disciplines are welcome. Hackathon Format: Round 1: Idea Submission Submit: Problem Statement Proposed Solution AI Implementation Approach Round 2: Prototype Development Shortlisted teams will develop: MVP AI Solution Automation Workflow AI Agent Web Application Mobile Application Round 3: Final Presentation Present your solution to a panel of mentors, founders, and industry experts. Judging Criteria: Innovation & Creativity Problem-Solving Ability AI Integration Technical Implementation Business Potential User Experience Presentation Quality Rewards & Benefits: Winner 100% Scholarship for the Stellan AI Builder Diploma Program Guaranteed Interview for Internship Opportunities Founder Mentorship Certificate of Excellence First Runner-Up 80% Scholarship for the Stellan AI Builder Diploma Program Career Mentorship Internship Opportunities Second Runner-Up 60% Scholarship for the Stellan AI Builder Diploma Program Industry Mentorship Top 20 Teams Exclusive Builder Community Access Networking Opportunities Special Recognition Certificates All Participants Participation Certificate Access to Exclusive AI Learning Resources Community Membership Why Participate?: Build Real-World AI Projects Showcase Your Skills Gain Industry Exposure Win Scholarships Worth Lakhs Connect with Founders and Mentors Access Internship Opportunities Join a Community of Builders and Innovators', '2026-06-10T00:00:00+05:30', '2026-06-25T14:30:00+05:30', 'Online', 'online', 'Certificate & Perks', 'https://unstop.com/hackathons/stellan-ai-buildathon-2026-dyndox-1697660', 'external', ARRAY['AI', 'Design']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696924', 'Tech Launchpad 1.0', 'To attend the intro session, join: https://chat.whatsapp.com/KPc3BNtU7cd9ShH1175m5g?mode=gi_t About the Opportunity: With the successful conclusion of MSME Launchpad 2.0, Prodmark Business Consultants Private Limited now presents Tech Launchpad 1.0, an exciting online coding challenge designed for teams to showcase their technical prowess. This event provides a dynamic platform for participants to collaborate and develop innovative solutions in a virtual environment. Problem: Our one of the offerings through MBA Partner (www.mbapartner.in) requires a dynamic website and an application that includes all the possible content that an MBA student requires including, but not limited to, Live Projects, Placements Prep, Case Competitions, Repositories, and Past year testimonials. While we have all these in the best of our capabilities with amazing set of Old IIM Mentors producing magnificent results for 2000+ students in the past, our website doesn''t show it in the best possible manner. Solution: We need a website and a mobile application with amazing UI/UX and an AI Chatbot that helps students navigate through the offerings and get a best experience even before enrollment. Our current website is hosted on Wix and hence, our preference would be to have an alternative one built on the same and integrate it with our existing one. If website built on external platforms can be integrated into Wix, that works as well Eligibility and Registration: This opportunity is open to Team Participation of maximum 3. Seize this chance to join the Tech Launchpad 1.0 online coding challenge and make your mark! Certificates of Appreciation would be given to each one of you.', '2026-06-08T00:00:00+05:30', '2026-07-06T15:59:00+05:30', 'Online', 'online', '₹ 10,000', 'https://unstop.com/hackathons/tech-launchpad-10-prodmark-business-consultants-private-limited-1696924', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001697413', 'Queue Cure ''26', '76% of India''s 1.5 million clinics still run on paper token slips and shouting. Patients wait 2&ndash;3 hours with zero visibility into when they''ll be called. Doctors have no dashboard. Receptionists manage everything from memory. You''re going to fix that. Queue Cure ''26 is a beginner-friendly Full Stack hackathon hosted on Wooble &mdash; India''s portfolio-first hiring platform where builders get hired on what they build, not what their resume says. What to build: Screen 1 &mdash; Receptionist view: Add patient, call next token, set average consultation time Screen 2 &mdash; Patient waiting room view: Current token being seen, tokens ahead, estimated wait Live sync &mdash; both screens update the moment "Call Next" is clicked  Submission Requirements Submit all 4 of the following to your Wooble portfolio: Working prototype link or demo video GitHub repository with README Socket event diagram Thought process sheet  Evaluation Criteria Criteria Weight Live queue updates correctly across both screens without refresh 40% Wait time computed from real data &mdash; not hardcoded 25% Receptionist screen is fast and mistake-proof 20% Thought process addresses concurrency and edge cases 15% Participant Benefits Participation Certificate Winner Certificate + LinkedIn Badge Portfolio feature on Wooble Interview Opportunity with hiring partners Talent Pool Shortlisting for future roles', '2026-06-10T00:00:00+05:30', '2026-06-25T00:58:00+05:30', 'Online', 'online', '₹ 3,000 + Job Offer/PPI', 'https://unstop.com/hackathons/queue-cure-26-wooble-software-private-limited-1697413', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001694233', 'Ship to Get Hired - Gappy AI Hackathon', 'Ship to Get Hired &mdash; Gappy AI Hackathon Build a real AI product. Get hired. Win ₹1 Lakh.Lemma SDK: https://github.com/lemma-work/lemma-platformLive hackathon discussion: https://discord.gg/6dVR7zTvyLemma Docs: https://lemma.work/docsHow to start using lemma: https://lemma-quickstart.vercel.app/ Join our Discord community to stay updated, access how-to guides, find teammates, and get support during the build window. At a Glance Registration: Rolling &mdash; June 8&ndash;29 Build window: June 24&ndash; 2nd July Who can build: Developers, PMs, operators & students Career: Hiring fast-track to partner companies Proof: Project certificates Not just for developers. With Lemma SDK you can build entirely through prompting &mdash; no deep coding background needed. What matters most is clear thinking: a sharply defined problem, real product sense, and the judgment to ship something people would actually use. Developers, PMs, operators, and students are all welcome. What You''ll Build: Build a working agentic app using Lemma SDK as your infrastructure layer. Lemma SDK is upcoming (launching on 24th June) open-source infrastructure for coding agents to build agentic apps that run real work. It provisions ai agents, datastores, document stores, frontend, backend, workflows, functions, and integrations to build ai apps end to end. Pick any real-world problem: a specific user, a clear pain point, and a workflow worth solving. Or build from one of our curated problem statements (to be shared over email after registration) The core loop should work end-to-end and be demoable. Bring your own IDE, AI coding tool, API key, builder platform, and hosting/deployment setup. The Hiring Fast-Track Your submission goes to work for you: Submissions are evaluated for problem clarity, product thinking, and execution quality. Top builders are matched to AI Product Engineer and AI Product Manager roles (full-time and internship role) at partner companies. Your profile &mdash; resume, project summary, and a written rationale &mdash; goes directly to the hiring team. No cold applications. Partner companies may invite you directly for a first-round interview. No CV screening, no recruiter filters. Hiring partners: YesMadam &middot; Binocs &middot; Foxo &middot; Zapdata &middot; CorallyThe Project Track (for top 10 teams, optional): Top 10 teams get the chance to keep building &mdash; with the Lemma team behind them: Two more weeks to refine your submission into a full-fledged product, with direct guidance on architecture, SDK usage, and product decisions. A verified project certificate of contribution &mdash; a real credential, not participation filler. The strongest projects published on the Lemma website as community templates. Timeline: June 8&ndash;29 &mdash; Rolling registrations (the hackathon begins June 24) June 24 &mdash; Lemma SDK launches publicly + build window begins July 2nd &mdash; Submissions close (project + short writeup + working demo) After judging &mdash; Results announced. Winners recognised, and shortlisted builders'' profiles matched and introduced to partner companies. Partner companies may invite you directly for a first-round interview. How We Judge Problem clarity & real-world fit &mdash; 35% Product judgment &mdash; 25% Execution quality &mdash; 25% Lemma SDK utilisation &mdash; 15% What is Lemma? Most software records what happened. Lemma is infrastructure for software that actually does the work &mdash; structured data, AI agents, automated workflows, and custom interfaces in one environment. The SDK is open-source and locally runnable, and it launches publicly on June 24 &mdash; the same day the hackathon begins, so everyone starts fresh.', '2026-06-03T00:00:00+05:30', '2026-07-02T14:00:00+05:30', 'Online', 'online', '₹ 50,000', 'https://unstop.com/hackathons/gappy-ai-hackathon-gappy-ai-1694233', 'external', ARRAY['AI']) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696682', 'Hackday.Exe 2.0', 'HACKDAY.EXE 2.0 is a 10-hour non-stop virtual hackathon where developers, designers, and problem solvers come together to build AI-powered applications and ship real projects within a single day.join now https://discord.gg/zn4DeAq8d Platform The hackathon will be conducted entirely online via Discord. All announcements, team formation, opening ceremony, mentorship sessions, and event updates will take place on Discord. Participants must join the Discord server before the event begins. Format 10-hour virtual hackathon Individual participation only Opening ceremony on Discord Final submissions through Unstop Prize Categories 1. Best Use of AI APIs Build innovative solutions using Gemini API, Google Cloud AI, or other cutting-edge AI APIs and developer tools. 2. Best Deployed App Develop and deploy a live, production-ready application on cloud infrastructure. Rewards Winners (1st and 2nd place) in each category will receive exclusive gadgets, goodies, official stickers, and sponsor merchandise. Participation certificates will be provided to all participants. Eligibility Open to students, freshers, and developers. No prior experience required. Participants from any college, university, or professional background can apply. Rules & Guidelines Projects must be built entirely during the hackathon window. Gemini API, Google Cloud, or another AI API must be used as a core component of the project. Each participant can submit only one project. Plagiarism or pre-built projects will result in immediate disqualification. All participants must be registered on Unstop. Hackathon Process Step 1 Register on Unstop. Step 2 Join the official Discord server. Step 3 Attend the opening ceremony on 13 June 2026 at 12:00 PM UTC. Step 4 Build your project using Gemini API, Google Cloud, or any AI API. Step 5 Submit your project via Unstop before 10:00 PM UTC. Recommended Tools & APIs Gemini API (Google AI Studio) Google Cloud Platform (GCP) Claude API Other AI and cloud-based APIs', '2026-06-08T00:00:00+05:30', '2026-06-13T23:55:00+05:30', 'Online', 'online', 'Exclusive gadgets + goodies + winner certificate', 'https://unstop.com/hackathons/hackdayexe-20-vel-tech-rangarajan-dr-sagunthala-r-d-institute-of-science-and-technology-1696682', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;
INSERT INTO hackathons (id, name, description, start_date, end_date, location, mode, prize_pool, website_url, type, tags) VALUES ('00000000-0000-0000-0000-000001696902', 'WebForge - A Smart Campus Webathon', 'About the Competition WebForge is a project-based web development competition organized by IEEE Computational Intelligence Society (CIS), MUJ. The event is designed to challenge participants to develop innovative web-based solutions that address real-world problems through technology, creativity, and effective design. Participants will showcase their skills in web development, UI/UX design, problem-solving, teamwork, and project presentation while competing against talented developers from diverse backgrounds. The competition encourages innovation, technical excellence, and user-centric thinking, providing a platform for participants to transform ideas into impactful digital solutions. Eligibility Open to all students. Participants may register individually or as a team. Inter-college teams are allowed. Inter-branch teams are allowed. Participants must complete registration through Unstop before the deadline. Team Rules Each team can have 1 to 3 members. Teams can use any tech stack such as HTML, CSS, JavaScript, React, Node.js, MongoDB, Firebase, Django, Flask, etc. Use of AI tools is allowed, but the team must understand and explain their own project properly. Plagiarism or direct copying of an existing website/template will lead to disqualification. The final submission must be functional enough to demonstrate the main features. Judges&rsquo; decision will be final and binding. The entire event will be conducted in online mode. All rounds, submissions, evaluations, and presentations (if applicable) will take place virtually. Problem Statement: The problem statement will be provided only at the commencement of the event.', '2026-06-08T00:00:00+05:30', '2026-06-14T14:00:00+05:30', 'Online', 'online', '₹ 2,500', 'https://unstop.com/hackathons/webforge-a-smart-campus-webathon-manipal-university-mu-jaipur-1696902', 'external', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, start_date = EXCLUDED.start_date, end_date = EXCLUDED.end_date, location = EXCLUDED.location, mode = EXCLUDED.mode, prize_pool = EXCLUDED.prize_pool, website_url = EXCLUDED.website_url, tags = EXCLUDED.tags;